window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["backflow"] = window.COURSE_LANG["backflow"] || {};
window.COURSE_LANG["backflow"]["es"] = [
  {id:1, q:"¿Qué es una conexión cruzada?", opts:["Cualquier conexión real o potencial entre el sistema de agua potable y una fuente de polución o contaminación","Una junta de tubería que tiene fugas bajo presión","Una válvula que reduce la presión del agua en un servicio","Un espacio de aire entre una salida y el borde de un accesorio"], re:"El Manual de Control de Conexiones Cruzadas de la EPA y la AWWA M14 definen una conexión cruzada como cualquier conexión real o potencial entre un sistema de agua potable y cualquier fuente de polución o contaminación."},
  {id:2, q:"Una manguera de jardín dejada sumergida en una cubeta de agua jabonosa es un ejemplo de:", opts:["Un espacio de aire aprobado por el código","Una conexión cruzada indirecta","Un conjunto de aislamiento del predio","Solo una conexión directa"], re:"Manual CCC de la EPA: una manguera sumergida en una fuente no potable es una conexión cruzada indirecta clásica (de entrada sumergida) que puede permitir el sifonaje inverso."},
  {id:3, q:"Una conexión cruzada directa (de tubería sólida) es aquella en la que:", opts:["Siempre hay un espacio de aire presente","El agua solo cae a través del aire hacia un recipiente","La línea de agua potable está conectada física y permanentemente por tubería al sistema no potable","Nunca puede ocurrir reflujo"], re:"AWWA M14 / Manual CCC de la EPA: una conexión cruzada directa es una conexión permanente por tubería entre los sistemas potable y no potable, y puede experimentar tanto contrapresión como sifonaje inverso."},
  {id:4, q:"Una conexión cruzada indirecta (como una entrada sumergida) generalmente está sujeta a:", opts:["Ni sifonaje inverso ni contrapresión","Solo contrapresión","Solo electrólisis","Solo sifonaje inverso"], re:"USC FCCCHR / Manual CCC de la EPA: las conexiones cruzadas indirectas (de entrada sumergida) abiertas a la atmósfera pueden experimentar solo sifonaje inverso, mientras que las conexiones directas pueden ver ambos modos."},
  {id:5, q:"¿Cuál situación es un peligro de conexión cruzada?", opts:["Una línea de alimentación de químicos conectada sólidamente al suministro potable","Un caño de grifo que termina muy por encima del borde del fregadero","Un espacio de aire por encima del borde de un fregadero de trapeador","Un manómetro conectado en T a una línea de agua limpia"], re:"Manual CCC de la EPA: una línea de alimentación de químicos o de proceso conectada a la tubería potable es una conexión cruzada porque la sustancia no potable puede invertirse hacia el agua potable."},
  {id:6, q:"¿Por qué las conexiones cruzadas son una preocupación de salud pública?", opts:["Aumentan la factura del agua","Pueden permitir que sustancias no potables entren al suministro de agua potable","Solo reducen la presión del agua","Causan ruido en las tuberías"], re:"Manual CCC de la EPA: en condiciones de reflujo, una conexión cruzada puede atraer o empujar contaminantes y polución hacia el suministro potable, amenazando la salud pública."},
  {id:7, q:"Un sistema de riego de césped conectado al agua potable de un edificio se considera una conexión cruzada porque:", opts:["El agua de riego siempre es más limpia que el agua del grifo","Los aspersores no pueden mantener la presión","La tierra, el fertilizante y los pesticidas pueden ser absorbidos de vuelta hacia el agua potable","Usa menos agua que los accesorios"], re:"Manual CCC de la EPA: los sistemas de riego son conexiones cruzadas comunes; el reflujo puede arrastrar agua contaminada con bacterias del suelo, fertilizante o pesticidas hacia el suministro potable."},
  {id:8, q:"El término 'agua potable' significa agua que es:", opts:["Almacenada en un tanque no presurizado","Usada solo para riego","Reciclada de una torre de enfriamiento","Segura para el consumo humano y que cumple con las normas de agua potable"], re:"AWWA M14: el agua potable es agua segura para el consumo humano que cumple con las normas aplicables de calidad del agua potable."},
  {id:9, q:"El 'agua no potable' se describe mejor como agua que es:", opts:["No segura o no aprobada para el consumo humano","Siempre visiblemente sucia","Idéntica al agua potable","Solo se encuentra en líneas contra incendios"], re:"AWWA M14: el agua no potable es agua que no es segura para beber o que no es de calidad de agua potable aprobada, sin importar cómo se vea."},
  {id:10, q:"¿Cuál de las siguientes es la conexión cruzada cotidiana más común en una vivienda?", opts:["Una línea de servicio de cobre enterrada","Una manguera de jardín","Una válvula reductora de presión","Un medidor de agua"], re:"Manual CCC de la EPA / USC FCCCHR: la manguera de jardín común es la conexión cruzada residencial más frecuente porque se sumerge fácilmente en fuentes contaminadas."},
  {id:11, q:"Una caldera con agua tratada químicamente conectada por tubería al suministro potable como agua de reposición representa:", opts:["Un arreglo seguro que no necesita protección","Un espacio de aire aprobado por sí solo","Una conexión cruzada que debe protegerse contra el reflujo","Una condición que solo afecta el sabor del agua caliente"], re:"Manual CCC de la EPA: una línea de reposición de caldera tratada es una conexión cruzada; el agua tratada de caldera es un peligro que debe aislarse con un preventor de reflujo apropiado."},
  {id:12, q:"¿Cuál distingue mejor una conexión cruzada directa de una indirecta?", opts:["No hay diferencia real","Las directas siempre son temporales","Las indirectas siempre son tuberías más grandes","Las directas están conectadas por tubería; las indirectas descargan a través de la atmósfera abierta o por una entrada sumergida"], re:"AWWA M14 / Manual CCC de la EPA: una conexión cruzada directa es un enlace permanente por tubería; una indirecta ocurre en una entrada abierta o sumergida como una manguera o el llenado de un tanque."},
  {id:13, q:"Un lavabo donde la salida del grifo queda por debajo del borde de rebose crea:", opts:["Una entrada sumergida, que es una conexión cruzada","Un espacio de aire adecuado","Un punto de aislamiento del predio","Una zona de presión reducida"], re:"Manual CCC de la EPA: cuando una salida puede sumergirse por debajo del borde de rebose, se pierde el espacio de aire requerido y existe una conexión cruzada de entrada sumergida."},
  {id:14, q:"El control de conexiones cruzadas se ocupa principalmente de proteger:", opts:["La garantía del calentador de agua del cliente","El suministro público de agua potable contra la contaminación","El medidor de agua contra la congelación","Las tuberías de alcantarillado contra el colapso"], re:"Manual CCC de la EPA / Manual de Política de Control de Conexiones Cruzadas de la SWRCB de CA: el objetivo del control de conexiones cruzadas es proteger el suministro público de agua potable contra la contaminación por reflujo."},
  {id:15, q:"¿Cuál afirmación sobre las conexiones cruzadas es correcta?", opts:["Solo los sitios industriales pueden tenerlas","Existen solo cuando fluyen activamente hacia atrás","Una conexión potencial cuenta incluso si el reflujo no está ocurriendo en este momento","Siempre son visibles para el cliente"], re:"AWWA M14 / Manual CCC de la EPA: una conexión cruzada incluye cualquier conexión real O potencial; el peligro existe ocurra o no el reflujo en ese momento."},
  {id:16, q:"Un sistema de rociadores de protección contra incendios conectado al suministro potable es una conexión cruzada principalmente porque:", opts:["El agua de los rociadores siempre está a mayor presión que la red principal en todo momento","Elimina la necesidad de un medidor","La tubería de los rociadores siempre es metálica","El agua estancada y los aditivos del sistema pueden fluir de vuelta hacia el suministro potable"], re:"Manual CCC de la EPA / AWWA M14: los sistemas contra incendios contienen agua estancada y a veces aditivos; sin protección, esa agua puede refluir hacia el suministro potable."},
  {id:17, q:"La frase 'suministro de agua auxiliar' en el trabajo de conexiones cruzadas se refiere a:", opts:["Cualquier fuente de agua distinta del sistema público de agua, como un pozo o agua almacenada","Un segundo medidor de agua potable","Un suministro eléctrico de respaldo","Solo la conexión del cuerpo de bomberos"], re:"AWWA M14 / Título 17 de CA: un suministro de agua auxiliar es cualquier fuente distinta del sistema público de agua (pozo, estanque, agua recuperada, agua almacenada) que podría refluir hacia el suministro potable."},
  {id:18, q:"El reflujo se define mejor como:", opts:["El flujo normal hacia adelante del agua en una red principal","La inversión indeseable del flujo desde su dirección prevista a través de una conexión cruzada","El golpe de ariete en un sistema cerrado","La caída de presión a través de un medidor"], re:"AWWA M14 / Manual CCC de la EPA: el reflujo es la inversión indeseable de la dirección normal de flujo del agua u otras sustancias a través de una conexión cruzada hacia el suministro potable."},
  {id:19, q:"El sifonaje inverso es causado por:", opts:["Una bomba aguas abajo que empuja el agua de vuelta","Una válvula de retención mantenida abierta por residuos","Presión negativa (subatmosférica) en la tubería de suministro","La expansión térmica del agua caliente"], re:"Manual CCC de la EPA / AWWA M14: el sifonaje inverso resulta de presión negativa o reducida (un vacío parcial) en el sistema de suministro, que sifona el agua de vuelta a través de una conexión cruzada."},
  {id:20, q:"El reflujo por contrapresión ocurre cuando:", opts:["La presión de suministro excede la presión aguas abajo","La red principal de agua está cerrada","Se instala un espacio de aire","La presión aguas abajo se vuelve mayor que la presión de suministro"], re:"AWWA M14 / Manual CCC de la EPA: el reflujo por contrapresión ocurre cuando la presión del lado del cliente (de una bomba, caldera o tanque elevado) excede la presión de suministro y la supera."},
  {id:21, q:"¿Cuál evento es una causa típica de sifonaje inverso?", opts:["Una rotura de la red principal o una alta demanda de extinción de incendios cercana","Una bomba de refuerzo en el lado del cliente","Un tanque de almacenamiento elevado en el techo","Una caldera de vapor"], re:"Manual CCC de la EPA: las roturas de la red principal, el lavado de hidrantes y la alta demanda de extinción de incendios reducen la presión de suministro y pueden crear el vacío parcial que causa el sifonaje inverso."},
  {id:22, q:"¿Cuál fuente crea más comúnmente la contrapresión?", opts:["Un hidrante de incendios cercano que se abre","Una bomba, caldera o tanque elevado en el lado del cliente","Una rotura en la red principal de la ciudad","El lavado del sistema de distribución"], re:"AWWA M14 / Manual CCC de la EPA: las bombas, calderas, recipientes a presión y las tuberías o tanques elevados en el lado del cliente elevan la presión aguas abajo por encima de la red principal y causan contrapresión."},
  {id:23, q:"La analogía cotidiana de 'beber con una pajilla' describe mejor:", opts:["La contrapresión","Un espacio de aire","El sifonaje inverso","El golpe de ariete"], re:"Manual CCC de la EPA: el sifonaje inverso funciona como sorber con una pajilla, donde la presión reducida (succión) jala el líquido de vuelta por la línea."},
  {id:24, q:"Una conexión cruzada directa puede experimentar:", opts:["Solo sifonaje inverso","Solo contrapresión","Ninguna de las dos condiciones","Tanto sifonaje inverso como contrapresión"], re:"AWWA M14 / USC FCCCHR: debido a que una conexión cruzada directa está conectada sólidamente por tubería, puede estar sujeta tanto a contrapresión como a sifonaje inverso."},
  {id:25, q:"Durante una gran rotura de la red principal, la pérdida de presión en el sistema de distribución puede causar:", opts:["Sifonaje inverso que jala contaminantes hacia la red principal","Contrapresión de las calderas","Un aumento del cloro residual","Golpe de ariete solo en las líneas contra incendios"], re:"Manual CCC de la EPA: una rotura de la red principal reduce la presión del sistema y puede crear un vacío, arrastrando agua contaminada de vuelta a través de conexiones cruzadas sin protección (sifonaje inverso)."},
  {id:26, q:"La contrapresión es más probable donde el sistema del cliente incluye:", opts:["Solo accesorios alimentados por gravedad","Una fuente de presión como una bomba o un recipiente presurizado","Una sola llave de manguera","Un simple grifo de cocina"], re:"AWWA M14: la contrapresión requiere una fuente aguas abajo de mayor presión, como una bomba de refuerzo, una bomba de recirculación o un tanque o caldera presurizados."},
  {id:27, q:"¿Cuál es una causa común de presión negativa que conduce al sifonaje inverso?", opts:["Llenar lentamente un tanque de almacenamiento","Una válvula de aislamiento cerrada en un solo accesorio","Un evento de alta demanda como la extinción de incendios que reduce la presión de la red principal","La baja demanda nocturna normal"], re:"Manual CCC de la EPA: una extracción alta repentina (extinción de incendios, lavado de la red principal) o una rotura de la red principal puede reducir la presión por debajo de la atmosférica, produciendo sifonaje inverso."},
  {id:28, q:"Los dos tipos reconocidos de reflujo son:", opts:["Flujo estático y dinámico","Reflujo y desbordamiento","Flujo por sifón y por gravedad","Sifonaje inverso y contrapresión"], re:"AWWA M14 / Manual CCC de la EPA: el reflujo ocurre por exactamente dos mecanismos, el sifonaje inverso (presión de suministro reducida) y la contrapresión (presión aguas abajo elevada)."},
  {id:29, q:"Un tanque elevado en el techo conectado por tubería rígida al suministro potable puede crear:", opts:["Contrapresión por la carga estática del agua elevada","Solo sifonaje inverso","Un espacio de aire","Una zona de presión reducida"], re:"AWWA M14 / Manual CCC de la EPA: la carga estática de un tanque elevado o columna de agua puede exceder la presión de suministro y empujar el agua de vuelta, una condición de contrapresión."},
  {id:30, q:"¿Cuál afirmación es verdadera sobre el sifonaje inverso?", opts:["Requiere una bomba en el lado del cliente","Es impulsado por una caída en la presión del lado de suministro","No puede ocurrir durante una rotura de la red principal","Solo afecta las líneas de agua caliente"], re:"Manual CCC de la EPA: el sifonaje inverso es impulsado enteramente por una reducción en la presión del lado de suministro (un vacío parcial), no por ningún bombeo aguas abajo."},
  {id:31, q:"Un preventor de reflujo seleccionado para detener la contrapresión debe poder:", opts:["Depender solo de la gravedad","Funcionar solo cuando hay un vacío","Contener el flujo incluso cuando la presión aguas abajo excede la presión de suministro","Instalarse sin ninguna válvula de retención"], re:"AWWA M14: los conjuntos clasificados para contrapresión (como los conjuntos RP y de doble retención) deben sellar contra una mayor presión aguas abajo, a diferencia de los rompedores de vacío clasificados solo para sifonaje inverso."},
  {id:32, q:"¿Por qué es importante identificar el tipo de reflujo al seleccionar la protección?", opts:["Cambia el tamaño del medidor","No tiene efecto en la elección del dispositivo","Determina la factura del agua","Algunos dispositivos detienen solo el sifonaje inverso, mientras que otros también manejan la contrapresión"], re:"AWWA M14 / USC FCCCHR: la selección del dispositivo depende del modo de reflujo; por ejemplo, los rompedores de vacío atmosféricos protegen solo contra el sifonaje inverso, no contra la contrapresión."},
  {id:33, q:"La presión subatmosférica en una línea de agua significa que la presión está:", opts:["Por debajo de la presión atmosférica (un vacío parcial)","Por encima de la presión de la red principal de suministro","Exactamente a la presión atmosférica","Igual a la presión aguas abajo"], re:"Manual CCC de la EPA: la presión subatmosférica (negativa) está por debajo de la atmosférica, creando el vacío parcial responsable del sifonaje inverso."},
  {id:34, q:"Una bomba de refuerzo que eleva la presión de un cliente por encima de la red principal de la ciudad puede crear:", opts:["Sifonaje inverso","Reflujo por contrapresión si la retención de suministro falla o está ausente","Un espacio de aire","Condiciones de menor peligro"], re:"AWWA M14 / Manual CCC de la EPA: una bomba de refuerzo del cliente puede empujar la presión por encima de la red principal y causar reflujo por contrapresión a menos que haya un preventor adecuado en su lugar."},
  {id:35, q:"En la terminología de conexiones cruzadas, el 'grado de peligro' se refiere a:", opts:["Qué tan lejos está el conjunto del medidor","El diámetro de la tubería","Si la sustancia es un contaminante leve (no de salud) o un contaminante (peligro para la salud)","La presión del agua en psi"], re:"USC FCCCHR / AWWA M14: el grado de peligro clasifica una conexión cruzada según la sustancia involucrada, ya sea un contaminante leve (peligro no para la salud) o un contaminante (peligro para la salud)."},
  {id:36, q:"Un 'contaminante' en el control de conexiones cruzadas es una sustancia que:", opts:["Solo afecta el sabor, el olor o el color","Es inofensiva en cualquier cantidad","Siempre reduce la presión del agua","Podría crear un peligro para la salud, causando enfermedad o muerte si entra en el agua"], re:"USC FCCCHR / Manual CCC de la EPA: un contaminante es un peligro para la salud; si entra en el suministro potable podría causar enfermedad o muerte (por ejemplo aguas residuales o pesticidas)."},
  {id:37, q:"Un 'contaminante leve' en el control de conexiones cruzadas es una sustancia que:", opts:["Deterioraría la calidad del agua o sería objetable pero no es un peligro para la salud","Siempre causa enfermedad","Es lo mismo que un contaminante","No puede afectar el agua en absoluto"], re:"USC FCCCHR / AWWA M14: un contaminante leve es un peligro no para la salud (peligro bajo) que degrada la calidad o es estéticamente objetable pero no pone en peligro la salud."},
  {id:38, q:"¿Cuál se considera una conexión cruzada de ALTO peligro (para la salud)?", opts:["Una línea de bebida carbonatada de grado alimenticio","Una conexión a una fuente de aguas residuales o cloacales","Una línea de agua fría a una fuente para beber","Un colector de lluvia limpio en el techo solo para riego"], re:"USC FCCCHR / Manual CCC de la EPA: una conexión a aguas residuales o cloacales es un peligro grave para la salud porque podrían entrar patógenos al suministro potable."},
  {id:39, q:"Un peligro no para la salud (contaminante leve) normalmente se protegería con un espacio de aire, un conjunto de presión reducida, O:", opts:["Ninguna protección en absoluto","Una simple válvula de cierre","Un conjunto de válvula de doble retención","Un manómetro"], re:"USC FCCCHR / AWWA M14: los peligros bajos (no para la salud) pueden protegerse con un espacio de aire, un conjunto RP o un conjunto de válvula de doble retención; los peligros altos requieren un espacio de aire o un conjunto RP."},
  {id:40, q:"Una conexión cruzada de ALTO peligro (para la salud) debe protegerse al menos con:", opts:["Solo un rompedor de vacío de llave de manguera","Solo una válvula de retención","Solo un conjunto de válvula de doble retención","Un espacio de aire o un conjunto de principio de presión reducida"], re:"USC FCCCHR / Título 17 de CA: las conexiones cruzadas de peligro para la salud requieren la protección más alta, un espacio de aire o un conjunto de principio de presión reducida (RP)."},
  {id:41, q:"¿Quién determina típicamente el grado de peligro en el predio de un cliente?", opts:["El proveedor de agua o su programa de control de conexiones cruzadas, mediante encuesta","El cliente solo","El plomero que instaló los accesorios","El cuerpo de bomberos"], re:"Título 17 de CA / Manual de Política CCC de la SWRCB: el proveedor de agua evalúa el grado de peligro mediante encuestas y asigna el nivel de protección requerido."},
  {id:42, q:"¿Cuál clase de sustancia se trata generalmente como un contaminante (peligro para la salud)?", opts:["Decoloración estética por minerales inofensivos","Aguas residuales, químicos o pesticidas","Burbujas de aire en la línea","Agua ligeramente tibia"], re:"USC FCCCHR / Manual CCC de la EPA: las aguas residuales, los químicos tóxicos y los pesticidas son contaminantes porque representan un peligro directo para la salud si refluyen."},
  {id:43, q:"La selección de un preventor de reflujo debe ser 'proporcional al grado de peligro', lo que significa:", opts:["Usar el dispositivo más barato disponible","Usar siempre el dispositivo más pequeño","Ajustar el nivel de protección a qué tan peligrosa es la sustancia","El nivel de protección no depende del peligro"], re:"Título 17 de CA / AWWA M14: el tipo de protección debe ser proporcional al grado de peligro, por lo que los peligros más altos exigen conjuntos de mayor clasificación."},
  {id:44, q:"Una conexión que solo causaría un sabor u olor objetable, sin riesgo para la salud, se clasifica como un:", opts:["Peligro para la salud","Peligro de aguas residuales","Peligro letal","Peligro no para la salud (contaminante leve)"], re:"USC FCCCHR: una sustancia que afecta solo el sabor, el olor o la apariencia sin poner en peligro la salud es un peligro no para la salud (contaminante leve)."},
  {id:45, q:"¿Por qué una conexión de peligro para la salud nunca debe protegerse con un dispositivo clasificado solo para contaminantes leves?", opts:["Un dispositivo de menor clasificación puede no detener de forma confiable un contaminante peligroso","Costaría muy poco","Los dispositivos para contaminantes leves son ilegales en todas partes","No hay diferencia en la protección"], re:"USC FCCCHR / AWWA M14: subproteger un peligro para la salud arriesga permitir que un contaminante peligroso entre al suministro potable, por lo que el conjunto debe coincidir con el peligro."},
  {id:46, q:"¿Cuál de estos es más probablemente un peligro BAJO (no para la salud)?", opts:["Un aspirador médico","Una conexión a un sistema de aspersores de césped sin inyección de químicos","Una conexión a un tanque de galvanizado químico","Una mesa de mortuorio"], re:"Manual CCC de la EPA: un sistema básico de aspersores de césped sin químicos añadidos es generalmente un peligro bajo, mientras que las conexiones médicas, de galvanizado y de mortuorio son peligros altos."},
  {id:47, q:"Cuando el peligro en un sitio es incierto o podría cambiar, el programa generalmente:", opts:["Ignora la conexión","Retira toda la protección","La trata como el peligro mayor para estar seguro","Reduce el nivel de protección"], re:"AWWA M14 / Manual de Política CCC de la SWRCB: cuando el peligro es desconocido o variable, el enfoque conservador es asumir el peligro mayor y proteger en consecuencia."},
  {id:48, q:"Un sistema de inyección de químicos (como un inyector de fertilizante en el riego) eleva el peligro porque:", opts:["Reduce la presión en la línea","Hace el agua potable","Añade un espacio de aire automáticamente","Introduce químicos tóxicos que podrían refluir hacia el suministro potable"], re:"Manual CCC de la EPA / USC FCCCHR: añadir inyección de químicos convierte un sistema de riego que de otro modo sería de bajo peligro en un peligro para la salud, requiriendo un conjunto RP o un espacio de aire."},
  {id:49, q:"Los términos 'peligro para la salud' y 'peligro no para la salud' corresponden respectivamente a:", opts:["Contaminante y contaminante leve","Contaminante leve y contaminante","Directo e indirecto","Contrapresión y sifonaje inverso"], re:"USC FCCCHR / AWWA M14: un peligro para la salud es un contaminante; un peligro no para la salud es un contaminante leve."},
  {id:50, q:"Asignar el grado de peligro es importante porque:", opts:["Establece la tarifa de agua del cliente","Determina el tipo y la clasificación mínima de la protección contra el reflujo requerida","Determina el color del medidor","No tiene efecto práctico"], re:"Título 17 de CA / AWWA M14: el grado de peligro determina directamente qué método de prevención de reflujo es aceptable para la conexión."},
  {id:51, q:"Un espacio de aire es:", opts:["Una válvula de retención mecánica","Un puerto de alivio de presión","Una separación física vertical entre una salida de agua y el borde de rebose de un recipiente receptor","Un tipo de conexión de manguera"], re:"AWWA M14 / Manual CCC de la EPA: un espacio de aire es la separación física vertical sin obstrucciones entre el punto más bajo de una salida de agua y el borde de rebose del receptáculo debajo de ella."},
  {id:52, q:"El espacio de aire mínimo es generalmente:", opts:["Igual al diámetro de la salida","Al menos cuatro veces el diámetro de la tubería, mínimo 3 pulgadas","Exactamente 1/2 pulgada en todos los casos","Al menos el doble del diámetro de la abertura efectiva, pero nunca menos de 1 pulgada"], re:"AWWA M14 / Código Uniforme de Plomería / CA HSC: el espacio de aire mínimo es el doble del diámetro de la abertura efectiva y en ningún caso menos de 1 pulgada (la regla '2D, nunca menos de 1 pulgada')."},
  {id:53, q:"Un espacio de aire protege contra:", opts:["Tanto el sifonaje inverso como la contrapresión","Solo la contrapresión","Solo el sifonaje inverso","Ninguno de los dos tipos de reflujo"], re:"AWWA M14 / Manual CCC de la EPA: un espacio de aire correctamente dimensionado es el método más confiable y protege tanto contra el sifonaje inverso como contra la contrapresión porque no hay ninguna ruta física de tubería."},
  {id:54, q:"El espacio de aire se considera generalmente:", opts:["La protección contra reflujo menos efectiva","La protección máxima (más confiable) contra el reflujo","Igual a un rompedor de vacío de llave de manguera","Útil solo para baja presión"], re:"AWWA M14 / USC FCCCHR: cuando se instala y mantiene correctamente, el espacio de aire proporciona el grado de protección más alto de cualquier método."},
  {id:55, q:"Un espacio de aire se mide desde:", opts:["La parte superior de la manija del grifo hasta el piso","El centro de la tubería hasta la pared","El punto más bajo de la salida de agua hacia abajo hasta el borde de rebose del accesorio","La salida hasta el fondo del lavabo"], re:"AWWA M14 / UPC: el espacio de aire es la distancia vertical desde la abertura más baja de la salida de suministro hasta el borde de rebose del recipiente receptor."},
  {id:56, q:"Una limitación clave del espacio de aire como protección contra el reflujo es que:", opts:["No puede detener la contrapresión","Solo funciona por encima de 80 psi","Requiere pruebas eléctricas anuales","Puede anularse fácilmente añadiendo una manguera o extensión a la salida"], re:"Manual CCC de la EPA: aunque es altamente efectivo, un espacio de aire se anula fácilmente (por ejemplo conectando una manguera), por lo que debe mantenerse y no modificarse."},
  {id:57, q:"Si una salida de agua se sumerge por debajo del borde de rebose, el espacio de aire queda:", opts:["Eliminado, creando una conexión cruzada","Aumentado","Duplicado","Sin afectar"], re:"AWWA M14 / Manual CCC de la EPA: una vez que la salida está en o por debajo del borde de rebose es una entrada sumergida; el espacio de aire ya no existe y se forma una conexión cruzada."},
  {id:58, q:"Para una abertura efectiva de 1 pulgada, el espacio de aire mínimo sería:", opts:["1/2 pulgada","2 pulgadas","1 pulgada","4 pulgadas"], re:"AWWA M14 / UPC: el doble de la abertura efectiva de 1 pulgada equivale a 2 pulgadas, que también satisface el mínimo de 1 pulgada, por lo que el espacio requerido es de 2 pulgadas."},
  {id:59, q:"Para una salida muy pequeña (por ejemplo 1/4 de pulgada), el espacio de aire mínimo es:", opts:["1/2 pulgada (el doble de la abertura)","1/4 de pulgada","1 pulgada, porque el espacio nunca es menor de 1 pulgada","Cero"], re:"AWWA M14 / UPC: el doble de 1/4 de pulgada es solo 1/2 pulgada, pero la regla establece un mínimo absoluto de 1 pulgada, por lo que rige 1 pulgada."},
  {id:60, q:"Una pared cercana a la salida afecta el requisito del espacio de aire al:", opts:["Reducir el espacio requerido","Eliminar la necesidad de un espacio","No tener efecto","Aumentar el espacio requerido porque la pared puede alterar la separación de aire"], re:"UPC / código de plomería: una pared cercana puede interferir con la trayectoria libre del aire, por lo que los códigos requieren un espacio de aire mayor (por ejemplo 3 veces el diámetro) cuando la salida está cerca de una pared."},
  {id:61, q:"¿Cuál describe mejor por qué un espacio de aire no puede ser superado por la presión?", opts:["No hay ninguna tubería física que conecte los dos lados, por lo que no existe una ruta de presión","Usa una retención accionada por resorte","Funciona con electricidad","Depende de una válvula de alivio"], re:"AWWA M14 / Manual CCC de la EPA: debido a que el espacio de aire es una interrupción abierta a la atmósfera sin tubería que la cruce, ni la contrapresión ni el sifonaje inverso pueden llevar el agua a través de él."},
  {id:62, q:"Un espacio de aire es más apropiado donde:", opts:["Se requiere flujo presurizado continuo aguas abajo del espacio","Es aceptable una descarga abierta a un tanque o receptor","Hay una llama presente","Solo existe contrapresión"], re:"AWWA M14: un espacio de aire es adecuado para descargas abiertas (llenado de tanques, drenajes, receptores) donde no se necesita presión aguas abajo, ya que el espacio interrumpe la línea hacia la atmósfera."},
  {id:63, q:"El borde de rebose referenciado en la medición del espacio de aire es:", opts:["El fondo del lavabo","La salida del grifo","El borde superior por el cual el agua se desbordaría del recipiente","La abertura del drenaje"], re:"AWWA M14 / UPC: el borde de rebose es el borde superior de un accesorio o recipiente desde el cual el agua se desbordaría, y es el punto de referencia para el espacio de aire."},
  {id:64, q:"En comparación con un conjunto mecánico contra reflujo, un espacio de aire:", opts:["Tiene partes internas que pueden desgastarse","Requiere electricidad","Debe probarse con manómetros anualmente","No tiene partes móviles que se desgasten o fallen"], re:"USC FCCCHR / AWWA M14: un espacio de aire es no mecánico, sin partes móviles, por lo que no puede desgastarse, aunque puede anularse si se altera físicamente."},
  {id:65, q:"Un espacio de aire aceptable en el suministro de un fregadero de trapeador significa que el caño:", opts:["Termina al menos la distancia requerida por encima del borde de rebose","Descarga por debajo del borde","Está conectado a una manguera que toca el piso","Se sumerge cuando se llena el fregadero"], re:"AWWA M14 / Manual CCC de la EPA: el caño debe terminar al menos a la distancia requerida del espacio de aire por encima del borde de rebose para que nunca pueda sumergirse."},
  {id:66, q:"¿Por qué se considera el espacio de aire la forma básica de separación contra el reflujo?", opts:["Es la tecnología más nueva","Es la separación más simple y más positiva entre el agua potable y la no potable","Necesita el mayor mantenimiento","Solo funciona con agua caliente"], re:"Manual CCC de la EPA / AWWA M14: el espacio de aire es el método de separación original y más positivo, el punto de referencia con el que se comparan los conjuntos mecánicos."},
  {id:67, q:"Si un equipo requiere agua presurizada y no se puede usar un espacio de aire abierto, la alternativa es:", opts:["Dejar la conexión sin protección","Reducir la presión del agua a cero","Instalar un conjunto apropiado de prevención de reflujo mecánico","Sumergir la salida"], re:"AWWA M14 / USC FCCCHR: donde se necesita una conexión presurizada y cerrada, un conjunto mecánico aprobado (como un RP o una doble retención) reemplaza el espacio de aire."},
  {id:68, q:"En el control de conexiones cruzadas, la 'contención' (aislamiento del predio) significa instalar protección:", opts:["En cada accesorio dentro del edificio","Solo en el calentador de agua","Solo en la línea de agua caliente","En o cerca de la conexión de servicio para proteger la red principal pública de agua"], re:"Manual CCC de la EPA / Manual de Política CCC de la SWRCB de CA: la contención (aislamiento del predio) coloca un preventor de reflujo en la conexión de servicio para proteger la red principal pública de todo el predio."},
  {id:69, q:"El 'aislamiento' (protección de accesorios) en el control de conexiones cruzadas significa proteger:", opts:["Cada conexión cruzada o accesorio individual dentro del predio","Todo el sitio solo en el medidor","Solo la red principal de la ciudad","El hidrante de incendios"], re:"Manual CCC de la EPA: el aislamiento (protección interna/de accesorios) aborda cada conexión cruzada en su punto de uso dentro de la plomería del edificio."},
  {id:70, q:"Un conjunto de contención típicamente se ubica:", opts:["En el accesorio más alejado del medidor","Justo aguas abajo del medidor de agua o de la entrada de servicio","Dentro del calentador de agua","En el techo del edificio"], re:"Manual de Política CCC de la SWRCB de CA / Manual CCC de la EPA: el conjunto de contención (aislamiento del predio) se ubica inmediatamente aguas abajo del medidor o en la entrada de servicio."},
  {id:71, q:"El propósito principal de la contención es proteger:", opts:["A los ocupantes del edificio","Los electrodomésticos del cliente","El sistema público de distribución de agua del predio del cliente","El sistema de alcantarillado"], re:"Manual CCC de la EPA: la contención protege el sistema público de agua; por sí sola no protege a las personas dentro del edificio de las conexiones cruzadas internas."},
  {id:72, q:"El propósito principal del aislamiento (protección interna) es proteger:", opts:["Solo la red principal pública","El pavimento de la calle","El medidor de agua","A las personas y la calidad del agua dentro del edificio en cada conexión cruzada"], re:"Manual CCC de la EPA: el aislamiento protege a los ocupantes y la calidad del agua dentro del edificio al abordar cada conexión cruzada individual en su origen."},
  {id:73, q:"Un enfoque completo de control de conexiones cruzadas a menudo usa:", opts:["Tanto la contención en el servicio como el aislamiento en los peligros internos","Solo el aislamiento","Solo la contención","Ninguno, dependiendo del tratamiento del agua"], re:"Manual CCC de la EPA / AWWA M14: la mejor práctica combina la contención (aislamiento del predio) en el servicio con el aislamiento de los peligros internos para una protección por capas."},
  {id:74, q:"¿Por qué la contención por sí sola no protege a los ocupantes del edificio?", opts:["Porque detiene solo el agua caliente","Porque una conexión cruzada interna aún puede contaminar el agua dentro del edificio, aguas abajo del dispositivo de contención","Porque no tiene válvulas de retención","Porque aumenta la presión"], re:"Manual CCC de la EPA: un dispositivo de contención en el medidor no detiene la contaminación que ocurre por conexiones cruzadas dentro del edificio, aguas abajo de él."},
  {id:75, q:"¿Qué enfoque exigen más comúnmente los proveedores de agua como mínimo para proteger la red principal pública?", opts:["El aislamiento de cada accesorio por parte de la empresa de servicios","Ninguna protección","La contención (aislamiento del predio) en la conexión de servicio","El tratamiento en el grifo del cliente"], re:"Título 17 de CA / Manual de Política CCC de la SWRCB: las empresas de servicios generalmente exigen la contención en la conexión de servicio como su medio principal para proteger el sistema público de distribución."},
  {id:76, q:"El aislamiento del predio es otro nombre para:", opts:["La protección a nivel de accesorio","El aislamiento del alcantarillado","Un espacio de aire en cada fregadero","La contención en la conexión de servicio"], re:"Manual de Política CCC de la SWRCB de CA: el 'aislamiento del predio' y la 'contención' se refieren ambos a proteger el sistema público con un conjunto en la conexión de servicio."},
  {id:77, q:"La protección interna (en el punto de uso) de un solo grifo de laboratorio es un ejemplo de:", opts:["Aislamiento","Contención","Aislamiento del predio","Protección de servicio"], re:"Manual CCC de la EPA: proteger un accesorio específico, como un grifo de laboratorio, en su punto de uso es aislamiento (protección de accesorios), no contención de todo el predio."},
  {id:78, q:"Para una instalación de alto peligro, el proveedor de agua típicamente exige contención Y:", opts:["La remoción del medidor","El aislamiento interno de los peligros específicos por parte del propietario","Menor presión del agua","Ninguna acción adicional"], re:"AWWA M14 / Manual de Política CCC de la SWRCB: los sitios de alto peligro generalmente necesitan contención en el servicio más el aislamiento de los peligros internos provisto por el propietario."},
  {id:79, q:"¿Cuál afirmación contrasta correctamente la contención y el aislamiento?", opts:["El aislamiento se instala solo en el medidor","Son idénticos","La contención protege la red principal pública; el aislamiento protege cada conexión cruzada interna","La contención protege solo los accesorios"], re:"Manual CCC de la EPA / AWWA M14: la contención es protección a nivel de servicio del sistema público, mientras que el aislamiento es protección en el punto de uso de cada conexión cruzada interna."},
  {id:80, q:"Un conjunto contra reflujo instalado inmediatamente después del medidor en todo un edificio de apartamentos está realizando:", opts:["Aislamiento","Control de expansión térmica","Separación por espacio de aire","Contención (aislamiento del predio)"], re:"Manual de Política CCC de la SWRCB de CA: un conjunto que sirve a todo el edificio en el medidor es contención (aislamiento del predio) para el sistema público."},
  {id:81, q:"Desde el punto de vista del proveedor de agua, la contención es valiosa porque:", opts:["Proporciona una sola barrera comprobable que protege el sistema público de todo el predio","Elimina la necesidad de cualquier revisión de la plomería interna","Reduce la factura de agua del cliente","Elimina todos los peligros internos"], re:"Manual CCC de la EPA / AWWA M14: la contención le da al proveedor un conjunto definido y comprobable para proteger la red principal pública de todo lo que está más allá del servicio."},
  {id:82, q:"La protección por aislamiento generalmente es responsabilidad de:", opts:["Solo el proveedor de agua","El propietario / cliente para los peligros dentro de su plomería","El cuerpo de bomberos","Solo el estado"], re:"Título 17 de CA / Manual CCC de la EPA: la protección interna (de aislamiento) de las conexiones cruzadas dentro del edificio es responsabilidad del cliente/propietario, a menudo exigida mediante el código de plomería."},
  {id:83, q:"¿Cuál escenario muestra la necesidad de AMBAS, contención y aislamiento?", opts:["Una vivienda unifamiliar con solo un grifo de cocina","Un lote vacío","Un hospital con muchas conexiones internas de alto peligro servidas desde una sola red principal","Una fuente para beber en un parque"], re:"AWWA M14 / Manual CCC de la EPA: las instalaciones con múltiples peligros internos altos (como los hospitales) necesitan contención en el servicio más el aislamiento de cada peligro interno."},
  {id:84, q:"La 'conexión de servicio' en el control de conexiones cruzadas es:", opts:["La llave de manguera en la parte trasera de una casa","El registro de limpieza del alcantarillado","La entrada del calentador de agua","El punto donde el sistema público de agua se conecta con la tubería del cliente"], re:"AWWA M14 / Título 17 de CA: la conexión de servicio es el punto de entrega donde el sistema público de agua se une con la plomería del cliente, a menudo en o justo después del medidor."},
  {id:85, q:"Un 'proveedor de agua' (suministrador de agua) es:", opts:["La agencia o empresa de servicios que posee y opera el sistema público de agua","El plomero que instala los accesorios","El probador de reflujo","La legislatura estatal"], re:"AWWA M14 / Título 17 de CA: el proveedor o suministrador de agua es la entidad que posee y opera el sistema público de agua que entrega agua potable a los clientes."},
  {id:86, q:"Bajo el Título 17 de California, ¿quién es generalmente responsable de proteger el sistema público de agua en la conexión de servicio?", opts:["La compañía de seguros del cliente","El proveedor de agua (suministrador)","El cuerpo de bomberos","El tasador del condado"], re:"Título 17 de CA (CCR secciones 7583-7605): el proveedor de agua tiene la responsabilidad de proteger el sistema público de agua en cada conexión de servicio mediante un programa de control de conexiones cruzadas."},
  {id:87, q:"¿Quién típicamente paga e instala un conjunto requerido de prevención de reflujo en una conexión de servicio?", opts:["Siempre el fabricante","La junta estatal de agua","El usuario del agua (cliente), a su costa","La propiedad vecina"], re:"Título 17 de CA: un conjunto de reflujo requerido es instalado por el usuario del agua y a su costa en cada conexión donde el proveedor lo requiera."},
  {id:88, q:"¿Con qué frecuencia deben probarse generalmente los conjuntos de prevención de reflujo bajo los requisitos de California?", opts:["Una vez cada cinco años","Nunca después de la instalación","Solo cuando fallan","Al menos anualmente, y después de la instalación, reubicación o reparación"], re:"Título 17 de CA / Manual de Política CCC de la SWRCB: los conjuntos de reflujo deben probarse al menos una vez al año y al momento de la instalación, reubicación o reparación."},
  {id:89, q:"Un CONJUNTO de prevención de reflujo difiere de un DISPOSITIVO de prevención de reflujo principalmente porque un conjunto:", opts:["Incluye válvulas de cierre y llaves de prueba para que pueda probarse en el campo","No tiene partes internas","No puede probarse","Siempre es no mecánico"], re:"AWWA M14 / USC FCCCHR: un 'conjunto' comprobable incluye válvulas de cierre de asiento resiliente y llaves de prueba, lo que permite la prueba en línea en el campo, a diferencia de un 'dispositivo' no comprobable."},
  {id:90, q:"El rol principal de un probador certificado de conjuntos de reflujo es:", opts:["Diseñar la red principal de agua","Probar e informar sobre los conjuntos de reflujo para verificar que funcionan correctamente","Establecer las tarifas de agua del cliente","Leer el medidor eléctrico"], re:"AWWA M14 / Título 17 de CA: el probador certificado realiza las pruebas periódicas requeridas y documenta si cada conjunto está funcionando correctamente."},
  {id:91, q:"El objetivo general de un programa de control de conexiones cruzadas es:", opts:["Aumentar las ventas de agua","Reducir la factura de calefacción del edificio","Proteger el suministro público de agua potable contra la contaminación por reflujo","Acelerar el flujo del agua"], re:"Manual CCC de la EPA / Manual de Política CCC de la SWRCB de CA: un programa de control de conexiones cruzadas existe para salvaguardar el suministro público de agua potable contra la contaminación por reflujo."},
  {id:92, q:"Los conjuntos de reflujo 'aprobados' en California son generalmente aquellos:", opts:["Elegidos al azar por el instalador","Solo unidades caseras","Cualquier dispositivo vendido en una ferretería","Probados y listados por una autoridad reconocida como la USC FCCCHR"], re:"Título 17 de CA / USC FCCCHR: California reconoce los conjuntos que han pasado la evaluación de laboratorio y de campo, como los de la lista aprobada de la USC FCCCHR."},
  {id:93, q:"Una conexión cruzada sin protección con el suministro público de agua está:", opts:["Prohibida bajo las regulaciones de control de conexiones cruzadas","Permitida si el cliente está de acuerdo","Requerida por el código","Solo es un problema para los sitios industriales"], re:"Título 17 de CA: las conexiones cruzadas sin protección con el suministro público de agua están prohibidas; la protección requerida debe estar instalada y mantenida."},
  {id:94, q:"Una 'encuesta' o inspección de control de conexiones cruzadas se usa para:", opts:["Medir la factura del agua","Identificar las conexiones cruzadas y evaluar el grado de peligro en un predio","Probar el suelo","Leer el medidor de gas"], re:"Manual CCC de la EPA / Título 17 de CA: el proveedor realiza encuestas para localizar las conexiones cruzadas y evaluar el grado de peligro para que pueda exigirse la protección adecuada."},
  {id:95, q:"Los registros de las pruebas de conjuntos de reflujo son importantes porque:", opts:["Establecen la presión del agua","Reemplazan la necesidad de cualquier dispositivo","Documentan que cada conjunto fue probado y encontrado operable, como lo requiere la regulación","Determinan el color de la tubería"], re:"Título 17 de CA / AWWA M14: los registros de pruebas demuestran el cumplimiento regulatorio y confirman que cada conjunto fue probado y funcionaba, y se informan al proveedor."},
  {id:96, q:"El 'punto de entrega' generalmente marca:", opts:["El desagüe del alcantarillado","La planta de tratamiento de agua","El hidrante de incendios","El límite donde termina la responsabilidad del proveedor y comienza la del cliente"], re:"AWWA M14: el punto de entrega (conexión de servicio) es la línea divisoria entre los sistemas de agua y las responsabilidades del proveedor y del cliente."},
  {id:97, q:"¿Por qué un probador debe estar certificado antes de probar conjuntos en California?", opts:["Para asegurar que las pruebas se realicen correctamente de modo que la protección de la salud pública se verifique de forma confiable","Por motivos fiscales","Para establecer las tarifas de agua","En realidad no es requerido"], re:"Título 17 de CA / AWWA M14: solo los probadores certificados pueden probar los conjuntos, lo que asegura una verificación competente y consistente de que la barrera de salud pública funciona."},
  {id:98, q:"Si un conjunto de reflujo no pasa su prueba, la respuesta correcta es:", opts:["Ignorarlo hasta el próximo año","Repararlo o reemplazarlo de inmediato y volver a probarlo para restaurar la protección","Retirar toda la protección","Aumentar la presión del agua"], re:"AWWA M14 / Título 17 de CA: un conjunto que falla debe repararse o reemplazarse y volver a probarse sin demora porque la conexión cruzada queda sin protección hasta que pase."},
  {id:99, q:"La responsabilidad principal del cliente en el control de conexiones cruzadas es:", opts:["Operar la red principal pública de agua","Establecer las políticas del proveedor","Instalar, mantener y hacer probar la protección de reflujo requerida en su predio","Certificar a otros probadores"], re:"Título 17 de CA: el usuario del agua es responsable de instalar, mantener y gestionar las pruebas requeridas de la protección de reflujo en su lado de la conexión de servicio."},
  {id:100, q:"¿Qué agencia adoptó el Manual de Política de Control de Conexiones Cruzadas estatal de California que rige la protección contra el reflujo?", opts:["El Departamento de Energía de EE. UU.","El jefe de bomberos local","La Comisión Federal de Comunicaciones","La Junta Estatal de Control de Recursos Hídricos (SWRCB)"], re:"CA SWRCB: la Junta Estatal de Control de Recursos Hídricos adoptó el Manual de Política de Control de Conexiones Cruzadas (vigente desde el 1 de julio de 2024) que rige el control de conexiones cruzadas en todo el estado."},
  {id:101, q:"¿Qué dos componentes internos primarios de válvula forman el núcleo de un conjunto de principio de presión reducida (RP)?", opts:["Dos válvulas de retención de acción independiente con una válvula de alivio diferencial entre ellas","Una sola válvula de retención y una entrada de aire atmosférico","Una válvula de retención y dos válvulas de alivio en serie","Una entrada de aire accionada por flotador y una sola válvula de retención"], re:"Un RP consta de dos válvulas de retención de acción independiente y accionadas por resorte, con una válvula de alivio de presión diferencial de operación hidráulica y mecánicamente independiente ubicada entre ellas. Fuente: AWWA M14; USC FCCCHR 10th ed."},
  {id:102, q:"¿Contra qué condición(es) de reflujo es eficaz un conjunto RP?", opts:["Solo retrosifonaje","Solo contrapresión","Tanto contrapresión como retrosifonaje","Ninguna, solo reduce la presión"], re:"Un RP es eficaz tanto contra el reflujo por contrapresión como contra el retrosifonaje. Fuente: AWWA M14; USC FCCCHR 10th ed."},
  {id:103, q:"¿Contra qué nivel de peligro puede usarse un conjunto RP para proteger?", opts:["Solo peligros que no afectan la salud","Solo peligros estéticos (color/olor)","Solo peligros de retrosifonaje","Peligros para la salud (y peligros que no afectan la salud)"], re:"Un RP puede usarse para aislar peligros para la salud (alto riesgo) así como peligros que no afectan la salud, lo que lo convierte en el conjunto comprobable de mayor nivel. Fuente: AWWA M14; CA Title 17 §7603."},
  {id:104, q:"¿Dónde se ubica la válvula de alivio de presión diferencial en un conjunto RP?", opts:["Entre las dos válvulas de retención (en la zona de presión reducida)","Aguas arriba de ambas válvulas de retención","Aguas abajo de la segunda válvula de retención","Dentro de la carcasa de la segunda válvula de retención"], re:"La válvula de alivio se ubica en la zona entre las dos válvulas de retención y por debajo de la primera válvula de retención, detectando el diferencial a través de la primera retención. Fuente: AWWA M14; CA Title 17 §7603(c)."},
  {id:105, q:"Durante el funcionamiento normal, la presión en la zona entre las dos retenciones de un RP debe ser al menos cuánto más baja que la presión de suministro (entrada)?", opts:["2 psi más baja","10 psi más baja","Igual a la presión de suministro","0.5 psi más baja"], re:"La zona de presión reducida debe mantenerse al menos 2 psi por debajo de la presión del lado de suministro durante el funcionamiento normal. Fuente: AWWA M14; USC FCCCHR 10th ed."},
  {id:106, q:"¿Cuántas llaves de prueba se proporcionan en un conjunto RP estándar?", opts:["Dos","Tres","Cuatro","Una"], re:"Un RP estándar tiene cuatro llaves de prueba de asiento resiliente, correctamente ubicadas, para la comprobación en campo de las retenciones y la válvula de alivio. Fuente: AWWA M14; USC FCCCHR 10th ed."},
  {id:107, q:"¿Cuántas válvulas de cierre de asiento resiliente forman parte de un conjunto RP completo?", opts:["Una","Cuatro","Dos (entrada y salida)","Ninguna"], re:"Un RP completo incluye dos válvulas de cierre de asiento resiliente y cierre hermético, una en la entrada y otra en la salida. Fuente: AWWA M14; USC FCCCHR 10th ed."},
  {id:108, q:"¿Cuándo se abre la válvula de alivio de un RP y descarga agua a la atmósfera?", opts:["Solo durante el flujo directo normal","Continuamente siempre que el conjunto esté presurizado","Cuando el diferencial a través de la primera retención baja a aproximadamente 2 psi o la primera retención tiene fuga","Solo cuando ambas válvulas de cierre están cerradas"], re:"La válvula de alivio se abre para descargar la zona a la atmósfera cuando el diferencial a través de la primera retención cae hacia ~2 psi (p. ej., obstrucción de la primera retención o un evento de reflujo), manteniendo la zona de presión reducida. Fuente: AWWA M14."},
  {id:109, q:"¿Cómo debe terminarse la descarga de la válvula de alivio de un RP?", opts:["Conectada directamente a un alcantarillado sanitario","Tapada para evitar cualquier derrame","A través de un espacio de aire hacia un desagüe aprobado o al nivel del suelo","Reconducida de vuelta a la entrada del conjunto"], re:"La descarga de alivio debe terminar a través de un espacio de aire sobre un receptor aprobado o al nivel del suelo; está prohibida una conexión directa (sumergida) al alcantarillado. Fuente: AWWA M14; CA Title 17."},
  {id:110, q:"¿Por qué nunca debe instalarse un conjunto RP en un pozo o bóveda bajo el nivel del suelo sujeto a inundación?", opts:["La descarga de la válvula de alivio podría quedar sumergida, anulando el espacio de aire y creando una conexión cruzada","Las llaves de prueba se congelarían más rápido bajo tierra","Los resortes de la válvula de retención solo se corroen bajo el nivel del suelo","Los pozos aumentan demasiado la presión de suministro"], re:"Si un pozo inundado sumerge el puerto de alivio, se pierde el espacio de aire y se puede succionar agua contaminada de vuelta; los conjuntos RP no deben ubicarse donde la inundación pueda sumergir la válvula de alivio. Fuente: AWWA M14."},
  {id:111, q:"La parte más baja del puerto de descarga de la válvula de alivio del RP normalmente debe estar al menos a qué distancia por encima del piso/nivel del suelo o nivel de inundación?", opts:["12 in","1 in","6 in","36 in"], re:"El puerto de descarga de alivio generalmente debe estar a un mínimo de 12 in por encima del suelo, la parte superior de la abertura del recinto o el nivel máximo de inundación, lo que sea más alto. Fuente: guía de instalación AWWA M14."},
  {id:112, q:"¿Qué significa el acrónimo 'RP' en la terminología de conjuntos antirreflujo?", opts:["Preventor de Alivio","Conjunto de Presión Inversa","Conjunto de prevención de reflujo de principio de presión reducida","Conjunto de Tubería Regulada"], re:"RP significa conjunto de prevención de reflujo de principio de presión reducida (también escrito RPZ o RPBA). Fuente: AWWA M14; USC FCCCHR 10th ed."},
  {id:113, q:"Un RPDA (conjunto detector de presión reducida) se usa principalmente en qué tipo de servicio?", opts:["Fuentes de agua potable residenciales","Grifos de manguera","Líneas de protección contra incendios (rociadores) donde se requiere detección de fugas/robo","Salidas de riego atmosférico"], re:"Un RPDA es un conjunto basado en RP con un bypass medido que se usa en líneas de incendios para detectar bajos flujos por fugas o uso no autorizado de agua. Fuente: AWWA M14."},
  {id:114, q:"La línea de bypass medida de un RPDA contiene cuál de los siguientes?", opts:["Solo una segunda válvula de alivio","Un rompedor de vacío atmosférico","Un pequeño conjunto RP (o de retención) con un medidor detector de bajo flujo","Solo una válvula reductora de presión"], re:"El bypass del RPDA conduce los bajos flujos a través de un pequeño conjunto RP paralelo equipado con un medidor detector (de registro) para captar fugas o uso no autorizado. Fuente: AWWA M14."},
  {id:115, q:"En comparación con un conjunto de doble válvula de retención, el RP proporciona qué?", opts:["Menos protección","La misma protección","Un nivel de protección más alto (mayor)","Ninguna protección contra reflujo en absoluto"], re:"El RP proporciona un nivel de protección más alto que un DC porque su válvula de alivio descarga activamente la zona si una retención falla; está calificado para peligros para la salud, mientras que un DC no lo está. Fuente: AWWA M14; clasificación de peligros CA Title 17."},
  {id:116, q:"¿Cuál afirmación sobre la descarga de la válvula de alivio del RP durante una primera retención obstruida es correcta?", opts:["La descarga visible de agua del puerto de alivio puede indicar una primera válvula de retención obstruida o con fuga","El puerto de alivio nunca debe descargar bajo ninguna condición","La descarga significa que solo ha fallado la segunda retención","La descarga prueba que el conjunto está instalado al revés"], re:"La descarga de alivio intermitente o continua comúnmente señala una primera retención obstruida/con fuga (o presión de suministro fluctuante); la válvula de alivio está cumpliendo su función protectora al descargar la zona. Fuente: AWWA M14; literatura de servicio del fabricante."},
  {id:117, q:"En un RP, la operación de la válvula de alivio se describe como cuál de los siguientes?", opts:["Accionada eléctricamente","Abierta manualmente solo por el técnico","De operación hidráulica y mecánicamente independiente de las retenciones","Impulsada por un flotador en la entrada de aire"], re:"La válvula de alivio del RP es una válvula de alivio de presión diferencial de operación hidráulica y mecánicamente independiente, referenciada a la presión de suministro. Fuente: AWWA M14; CA Title 17 §7603(c)."},
  {id:118, q:"Un conjunto de doble válvula de retención (DC) consta de cuál disposición?", opts:["Una válvula de retención y una válvula de alivio","Una entrada de aire y una sola válvula de retención","Dos válvulas de retención de acción independiente en serie","Una válvula de alivio entre dos entradas de aire"], re:"Un DC son dos válvulas de retención individuales de acción independiente dispuestas en serie, con válvulas de cierre en cada extremo y llaves de prueba. Fuente: AWWA M14; USC FCCCHR 10th ed."},
  {id:119, q:"¿Para qué nivel de peligro está aprobado un conjunto de doble válvula de retención?", opts:["Peligros para la salud (alto riesgo)","Conexiones de aguas residuales","Solo peligros que no afectan la salud (bajo riesgo)","Sistemas de inyección de químicos"], re:"Un DC se usa para aislar únicamente peligros que no afectan la salud (contaminantes); no está aprobado para peligros para la salud. Fuente: AWWA M14; CA Title 17 §7603."},
  {id:120, q:"¿Contra qué condiciones de reflujo es eficaz un DC?", opts:["Solo retrosifonaje","Solo contrapresión","Tanto contrapresión como retrosifonaje","Ninguna condición"], re:"Un DC es eficaz tanto contra la contrapresión como contra el retrosifonaje (para peligros que no afectan la salud). Fuente: AWWA M14; USC FCCCHR 10th ed."},
  {id:121, q:"¿Cuántas llaves de prueba tiene un conjunto DC estándar?", opts:["Una","Dos","Cuatro","Seis"], re:"Un DC tiene cuatro llaves de prueba correctamente ubicadas que se usan para medir el diferencial a través de cada retención. Fuente: AWWA M14; ASSE 1015."},
  {id:122, q:"¿Cuál es el diferencial mínimo aceptable típico que debe mantener cada válvula de retención de un DC al comprobarse?", opts:["1.0 psid","5.0 psid","0.1 psid","10 psid"], re:"Generalmente se requiere que cada retención de un DC mantenga un mínimo de aproximadamente 1.0 psid en la dirección del flujo para pasar. Fuente: AWWA M14; USC FCCCHR 10th ed."},
  {id:123, q:"¿Por qué se usan dos retenciones en serie en un DC en lugar de una?", opts:["Para duplicar el caudal","Para crear un espacio de aire","Para eliminar la necesidad de válvulas de cierre","Para proporcionar redundancia de modo que la segunda retención aún selle si la primera tiene fuga"], re:"La disposición en serie proporciona redundancia: si una retención no sella, la otra aún proporciona protección. Fuente: AWWA M14."},
  {id:124, q:"Un conjunto detector de doble retención (DCDA) se instala más comúnmente en qué?", opts:["Fuentes de agua potable","Líneas de alimentación de calderas con químicos","Lavavajillas","Líneas de suministro de protección contra incendios (rociadores)"], re:"Un DCDA es un DC con un bypass medido instalado en líneas de incendios de peligro que no afecta la salud para detectar fugas o uso no autorizado. Fuente: AWWA M14."},
  {id:125, q:"El bypass de un DCDA está diseñado para registrar flujos hasta aproximadamente qué caudal antes de que se abran las retenciones principales?", opts:["Aproximadamente 2 a 5 gpm (bajo flujo)","Aproximadamente 50 gpm","Aproximadamente 500 gpm","Solo flujos por encima de 100 gpm"], re:"El medidor detector del bypass capta bajos flujos (aproximadamente hasta ~2-5 gpm); flujos mayores abren las retenciones de la línea principal. Fuente: AWWA M14 (diseño de bypass DCDA)."},
  {id:126, q:"En un DCDA, el ajuste de presión diferencial del bypass en relación con las retenciones principales está diseñado de modo que:", opts:["Los bajos flujos se fuerzan primero a través del bypass medido","Todo el flujo siempre evita las retenciones de la línea principal","La línea principal se abre antes de cualquier flujo del bypass","El bypass nunca registra flujo"], re:"El bypass se ajusta con un diferencial ligeramente más bajo que las retenciones de la línea principal, de modo que los bajos flujos se registran en el medidor del bypass antes de que se abran las retenciones principales. Fuente: AWWA M14."},
  {id:127, q:"Un propósito principal del medidor detector en una línea de incendios DCDA/RPDA es:", opts:["Aumentar la capacidad de flujo de incendios","Reducir la presión de suministro","Reemplazar la necesidad de comprobación anual","Revelar pequeñas fugas o uso de agua no autorizado (no medido)"], re:"El medidor detector alerta a la empresa de servicios sobre fugas o desvíos no autorizados que podrían pasar desapercibidos en una línea de incendios que de otro modo no está medida. Fuente: AWWA M14."},
  {id:128, q:"¿Cuántas válvulas de cierre se incluyen en un conjunto DC completo?", opts:["Ninguna","Una","Dos (entrada y salida)","Cuatro"], re:"Un DC incluye dos válvulas de cierre de asiento resiliente y cierre hermético para el aislamiento durante la comprobación y el mantenimiento. Fuente: AWWA M14; ASSE 1015."},
  {id:129, q:"¿Cuál de los siguientes es un ejemplo de un peligro que no afecta la salud que un DC normalmente protegería?", opts:["Un aspirador médico/dental","Una conexión de eyector de aguas residuales","Un sistema de alimentación (inyección) de químicos","Un sistema de riego de césped sin inyección de químicos"], re:"El riego simple sin inyección de químicos generalmente es un peligro que no afecta la salud (contaminante) adecuado para protección con DC; la inyección de químicos o las aguas residuales requerirían un RP o un espacio de aire. Fuente: AWWA M14; evaluación de peligros CA Title 17."},
  {id:130, q:"A diferencia de un RP, un conjunto de doble válvula de retención NO incluye cuál componente?", opts:["Una segunda válvula de retención","Una válvula de cierre de entrada","Una válvula de alivio de presión diferencial","Llaves de prueba"], re:"Un DC no tiene válvula de alivio; esa es la diferencia definitoria respecto a un RP y la razón por la que un DC no puede descargar la zona si una retención se obstruye. Fuente: AWWA M14."},
  {id:131, q:"Debido a que un DC no tiene puerto de alivio, puede instalarse en qué ubicación donde un RP no puede?", opts:["Sumergido en un alcantarillado","Directamente en una línea de aguas residuales","Dentro de un tanque químico presurizado","Bajo el nivel del suelo en una bóveda (donde la inundación de un puerto de alivio no es preocupación), si de otro modo está permitido"], re:"Al carecer de descarga de alivio, un DC puede colocarse en una bóveda/entorno bajo el nivel del suelo donde un RP estaría prohibido debido a la inundación de su puerto de alivio (sujeto a las reglas locales sobre acceso y drenaje). Fuente: AWWA M14."},
  {id:132, q:"Las válvulas de retención en un DC se describen como:", opts:["Cargadas por fuerza (por resorte) a la posición cerrada","Cargadas a la posición abierta","Mantenidas cerradas solo por gravedad","Mantenidas cerradas eléctricamente"], re:"Cada retención del DC está internamente cargada por fuerza (por resorte) a la posición cerrada para que selle de forma independiente. Fuente: AWWA M14; ASSE 1015."},
  {id:133, q:"¿Qué significa el acrónimo 'DCDA'?", opts:["Conjunto de Desagüe de Doble Retención","Arreglo Detector de Retención Diferencial","Aparato de Descarga de Doble Cilindro","Conjunto Detector de Doble Retención"], re:"DCDA significa Conjunto Detector de Doble Retención (Double Check Detector Assembly). Fuente: AWWA M14; USC FCCCHR 10th ed."},
  {id:134, q:"¿Qué norma se aplica comúnmente a los conjuntos de prevención de reflujo de doble válvula de retención?", opts:["ASSE 1015 / AWWA C510","Solo ASSE 1056","40 CFR Part 82","Código de calderas ASME"], re:"Los conjuntos DC comúnmente cumplen con ASSE 1015 y AWWA C510 (y la aprobación USC FCCCHR). Fuente: AWWA M14; ASSE 1015; AWWA C510."},
  {id:135, q:"Un conjunto de rompedor de vacío de presión (PVB) contiene cuáles dos elementos operativos?", opts:["Dos válvulas de retención y una válvula de alivio","Una válvula de alivio y un espacio de aire","Dos entradas de aire en serie","Una sola válvula de retención por resorte y una válvula de entrada de aire cargada por fuerza"], re:"Un PVB tiene una válvula de retención de operación independiente y accionada por resorte (cargada por fuerza a cerrado) y una válvula de entrada de aire aguas abajo que está cargada por fuerza a la posición abierta. Fuente: AWWA M14; ASSE 1020."},
  {id:136, q:"¿Contra qué condición de reflujo está aprobado un PVB?", opts:["Solo contrapresión","Ninguna","Tanto contrapresión como retrosifonaje","Solo retrosifonaje"], re:"Un PVB protege solo contra el retrosifonaje; no debe usarse donde pueda producirse contrapresión. Fuente: AWWA M14; CA Title 17 §7603."},
  {id:137, q:"Un PVB debe instalarse al menos a qué distancia por encima de la tubería/salida aguas abajo más alta?", opts:["6 in","24 in","1 in","12 in"], re:"Un PVB debe instalarse al menos 12 in por encima de toda la tubería aguas abajo y la salida más alta (o el borde del nivel de inundación). Fuente: CA Title 17 §7603(b); AWWA M14; UPC/IPC."},
  {id:138, q:"¿Cuántas llaves de prueba tiene un conjunto PVB estándar?", opts:["Una","Ninguna","Cuatro","Dos"], re:"Un PVB tiene dos llaves de prueba (una aguas arriba y otra aguas abajo de la retención), además de sus válvulas de cierre de entrada/salida. Fuente: AWWA M14; ASSE 1020."},
  {id:139, q:"Una ventaja clave de un PVB sobre un rompedor de vacío atmosférico (AVB) es que el PVB:", opts:["Puede someterse a presión de agua continua","Proporciona protección contra contrapresión","No necesita válvulas de cierre","No requiere comprobación"], re:"Debido a que su retención es accionada por resorte y tiene llaves de prueba/válvulas de cierre, un PVB puede mantenerse bajo presión continua, a diferencia de un AVB. Fuente: AWWA M14; ASSE 1020."},
  {id:140, q:"En un PVB, la válvula de entrada de aire está cargada a qué posición?", opts:["Cerrada (cargada por fuerza a cerrado)","Bloqueada cerrada durante el servicio","Flotante, sin resorte","Abierta (cargada por fuerza a abierto)"], re:"La entrada de aire del PVB está cargada por fuerza a la posición ABIERTA para que se abra y admita aire y rompa un vacío cuando la presión de suministro cae. Fuente: AWWA M14; ASSE 1020."},
  {id:141, q:"En un PVB, la válvula de retención única está cargada a qué posición?", opts:["Abierta","Inversa","Neutral/equilibrada","Cerrada (cargada por fuerza a cerrado)"], re:"La válvula de retención del PVB está cargada por fuerza a la posición cerrada para sellar contra el retrosifonaje. Fuente: AWWA M14; ASSE 1020."},
  {id:142, q:"La principal diferencia funcional de un rompedor de vacío resistente a derrames (SVB) en comparación con un PVB es que el SVB:", opts:["Proporciona protección contra contrapresión","Tiene cuatro llaves de prueba","No requiere elevación por encima de la tubería aguas abajo","Está diseñado para minimizar/contener el derrame cuando se abre la entrada de aire"], re:"Un SVB utiliza un diseño de entrada de aire sellada/de diafragma para minimizar el derrame de agua al activarse, lo que lo hace más adecuado para ubicaciones interiores. Fuente: ASSE 1056; AWWA M14."},
  {id:143, q:"¿Cuántas llaves de prueba tiene típicamente un SVB, distinguiéndolo físicamente de un PVB?", opts:["Una (más una válvula de purga/sangrado)","Dos","Cuatro","Tres"], re:"Un SVB típicamente tiene una sola llave de prueba más una válvula de purga (sangrado), mientras que un PVB tiene dos llaves de prueba. Fuente: ASSE 1056."},
  {id:144, q:"Al igual que el PVB, el SVB está aprobado contra qué condición de reflujo?", opts:["Solo contrapresión","Solo expansión térmica","Ambas condiciones","Solo retrosifonaje"], re:"El SVB, al igual que el PVB, protege solo contra el retrosifonaje y no debe usarse donde exista contrapresión. Fuente: ASSE 1056; AWWA M14."},
  {id:145, q:"Un SVB, al igual que un PVB, debe instalarse al menos a qué distancia por encima de la salida aguas abajo más alta?", opts:["12 in","6 in","1 in","Sin mínimo"], re:"Un SVB debe instalarse al menos 12 in por encima de toda la tubería/salidas aguas abajo, el mismo mínimo que un PVB. Fuente: ASSE 1056; AWWA M14; CA Title 17."},
  {id:146, q:"Una aplicación común y apropiada para un PVB es:", opts:["Una caldera con tratamiento químico bajo contrapresión","Una línea de bebida carbonatada (carbonatador)","Una estación elevadora de aguas residuales","Un sistema de riego de césped sin inyección de químicos y sin contrapresión"], re:"Los PVB se usan ampliamente en sistemas de riego donde solo puede producirse retrosifonaje; la inyección de químicos (peligro para la salud) o las situaciones de contrapresión requieren un RP. Fuente: AWWA M14; CA Title 17."},
  {id:147, q:"¿Por qué debe instalarse un PVB/SVB en orientación vertical (en posición vertical)?", opts:["Para que las llaves de prueba miren hacia el técnico","Para permitir solo el flujo horizontal","Para aumentar la presión aguas abajo","Para que la entrada de aire y la retención funcionen correctamente por acción de gravedad/resorte"], re:"Los conjuntos PVB/SVB están diseñados para funcionar en posición vertical de modo que la entrada de aire de flotador/obturador y la retención asienten correctamente; otras orientaciones anulan la certificación. Fuente: requisitos de instalación ASSE 1020/1056."},
  {id:148, q:"¿Cuál es la norma que describe físicamente el rendimiento de los conjuntos de rompedor de vacío resistente a derrames?", opts:["ASSE 1056","ASSE 1015","ASSE 1013","AWWA C511"], re:"ASSE 1056 cubre los requisitos de rendimiento para los conjuntos de rompedor de vacío resistente a derrames. Fuente: ASSE 1056."},
  {id:149, q:"¿Cuál es la norma que describe comúnmente el rendimiento de los conjuntos de rompedor de vacío de presión?", opts:["ASSE 1020","ASSE 1056","ASSE 1015","ASSE 1011"], re:"ASSE 1020 cubre los requisitos de rendimiento para los conjuntos de rompedor de vacío de presión. Fuente: ASSE 1020."},
  {id:150, q:"Cuando la presión de suministro cae por debajo de la atmosférica en un PVB, la entrada de aire:", opts:["Permanece cerrada y mantiene el vacío","Aumenta la presión aguas abajo","Descarga agua al alcantarillado","Se abre para admitir aire, rompiendo el sifón"], re:"Ante la pérdida de presión, la entrada de aire cargada por fuerza se abre para admitir aire, rompiendo el vacío y evitando el retrosifonaje más allá de la retención cerrada. Fuente: AWWA M14; ASSE 1020."},
  {id:151, q:"La característica resistente a derrames de un SVB lo hace preferible a un PVB en qué situación?", opts:["Riego exterior en un clima de congelación","Aplicaciones de contrapresión","Aplicaciones de aguas residuales","Instalaciones interiores donde no se puede tolerar el derrame atmosférico"], re:"Debido a que contiene el derrame, el SVB es preferible para ubicaciones interiores donde la descarga del respiradero abierto de un PVB sería inaceptable. Fuente: ASSE 1056; AWWA M14."},
  {id:152, q:"Un rompedor de vacío atmosférico (AVB) está aprobado para proteger solo contra qué condición?", opts:["Contrapresión","Expansión térmica","Ambas condiciones","Retrosifonaje"], re:"Un AVB protege solo contra el retrosifonaje y nunca contra la contrapresión. Fuente: AWWA M14; CA Title 17 §7603."},
  {id:153, q:"Una regla de instalación crítica para un AVB es que debe haber:", opts:["Una bomba aguas abajo","Contrapresión continua","Cuatro llaves de prueba","Ninguna válvula de cierre o válvula de control aguas abajo del AVB"], re:"No puede ubicarse ninguna válvula de cierre o de control aguas abajo de un AVB, porque eso lo mantendría bajo presión continua y podría atascar la entrada de aire. Fuente: AWWA M14; CA Title 17 §7603."},
  {id:154, q:"Un AVB debe instalarse al menos a qué distancia por encima de la salida aguas abajo más alta o el borde del nivel de inundación?", opts:["6 in","12 in","1 in","18 in"], re:"Un AVB debe instalarse al menos 6 in por encima de toda la tubería aguas abajo y la salida más alta/borde del nivel de inundación. Fuente: CA Title 17 §7603; AWWA M14; UPC/IPC."},
  {id:155, q:"Un AVB NO puede someterse a presión continua durante más de cuánto tiempo en cualquier período de 24 horas?", opts:["12 horas","24 horas","1 hora","Sin límite"], re:"Un AVB puede estar bajo presión no más de 12 horas de cualquier período de 24 horas; más tiempo puede hacer que el disco de entrada de aire se atasque. Fuente: CA Title 17 §7603; AWWA M14."},
  {id:156, q:"¿Cuántas llaves de prueba tiene un rompedor de vacío atmosférico (AVB) estándar?", opts:["Cuatro","Dos","Ninguna (es un dispositivo no comprobable)","Una"], re:"Un AVB no tiene llaves de prueba ni válvulas de cierre como parte del dispositivo; no puede comprobarse en campo como un conjunto y se considera un dispositivo, no un conjunto comprobable. Fuente: AWWA M14; USC FCCCHR."},
  {id:157, q:"La parte móvil interna de un AVB se describe mejor como:", opts:["Una válvula de retención por resorte y una válvula de alivio","Una válvula de alivio de diafragma","Dos retenciones en serie","Un flotador/obturador (disco de entrada de aire) que sella el puerto de aire bajo flujo y cae para admitir aire ante la pérdida de presión"], re:"Un AVB utiliza un disco/obturador flotante que se mantiene arriba para sellar el puerto atmosférico durante el flujo y cae para abrir el puerto (admitiendo aire) cuando se pierde la presión. Fuente: AWWA M14; ASME A112.1.3."},
  {id:158, q:"¿Por qué nunca debe aplicarse contrapresión aguas abajo a un AVB?", opts:["Sobrepresurizaría la red de suministro principal","La contrapresión mejora su rendimiento","Abriría la válvula de alivio","No tiene válvula de retención para resistir la contrapresión y permitiría el reflujo"], re:"Un AVB depende únicamente de su entrada de aire para el retrosifonaje; no tiene retención cargada capaz de soportar la contrapresión, por lo que la contrapresión empujaría agua contaminada más allá de él. Fuente: AWWA M14."},
  {id:159, q:"Un rompedor de vacío de conexión de manguera (grifo de manguera) generalmente se clasifica como qué tipo de dispositivo?", opts:["Un conjunto de presión reducida","Un conjunto de rompedor de vacío de presión","Un conjunto de doble válvula de retención","Un rompedor de vacío de tipo atmosférico (solo retrosifonaje)"], re:"Un rompedor de vacío de grifo de manguera (HBVB/HCVB) es un rompedor de vacío de tipo atmosférico que protege contra el retrosifonaje y no debe dejarse bajo presión continua. Fuente: AWWA M14; ASSE 1011."},
  {id:160, q:"Un espacio de aire se define por qué separación vertical mínima en relación con la abertura efectiva?", opts:["Dos veces el diámetro de la abertura efectiva, y nunca menos de 1 in","La mitad del diámetro de la tubería","Igual al diámetro de la tubería, sin mínimo","Diez veces el diámetro de la tubería"], re:"Un espacio de aire aprobado es de al menos dos veces el diámetro de la abertura efectiva y en ningún caso menos de 1 in. Fuente: CA Title 17 §7602; AWWA M14; USC FCCCHR."},
  {id:161, q:"Entre los métodos aprobados, ¿cuál proporciona el nivel más alto de protección contra reflujo?", opts:["Rompedor de vacío atmosférico","Conjunto de doble válvula de retención","Separación por espacio de aire","Rompedor de vacío de presión"], re:"Un espacio de aire (una separación física) proporciona el nivel más alto de protección porque ninguna parte mecánica puede fallar. Fuente: AWWA M14; clasificación CA Title 17."},
  {id:162, q:"Un AVB es una elección aceptable solo cuando se cumplen qué condiciones?", opts:["Sin contrapresión y sin presión continua (y sin válvula de cierre aguas abajo)","Hay contrapresión presente","Está instalado por debajo de las salidas","Hay una bomba ubicada aguas abajo"], re:"Un AVB se aplica solo donde no hay contrapresión, no hay presión continua más allá de 12 h y no hay válvula aguas abajo. Fuente: AWWA M14; CA Title 17."},
  {id:163, q:"¿Qué dispositivo protege solo contra el retrosifonaje y NO PUEDE comprobarse en campo con manómetros como un conjunto?", opts:["RP","DC","AVB","PVB"], re:"El AVB es un dispositivo no comprobable (sin llaves de prueba/válvulas de cierre); RP, DC y PVB son conjuntos comprobables. Fuente: AWWA M14; USC FCCCHR."},
  {id:164, q:"En comparación con un AVB, un PVB añade qué capacidad mientras sigue siendo solo de retrosifonaje?", opts:["Protección contra contrapresión","Operación de presión continua y comprobabilidad en campo (llaves de prueba/válvulas de cierre)","Una válvula de alivio interna","Un espacio de aire"], re:"Un PVB mantiene la entrada de aire accionada por resorte y añade llaves de prueba/válvulas de cierre, lo que permite la operación de presión continua y la comprobación en campo que el AVB no puede proporcionar. Fuente: AWWA M14; ASSE 1020."},
  {id:165, q:"¿Por qué un espacio de aire es inmune a los modos de falla de los conjuntos mecánicos?", opts:["Contiene resortes más fuertes","Es una separación física (no mecánica) que no puede obstruirse ni desgastarse","Está presurizado en todo momento","Utiliza dos válvulas de alivio"], re:"Un espacio de aire no tiene partes móviles que puedan obstruirse, atascarse o desgastarse, por lo que no puede fallar como pueden hacerlo una retención o una válvula de alivio. Fuente: AWWA M14; USC FCCCHR."},
  {id:166, q:"Un grifo de laboratorio con una salida dentada (rosca de manguera) en un edificio utiliza qué clase de dispositivo de punto de uso para protegerse contra el retrosifonaje?", opts:["Solo conjunto de presión reducida","Rompedor de vacío (de tipo atmosférico/rompedor de vacío de conexión de manguera)","Conjunto detector de doble retención","Válvula de alivio de entrada de aire"], re:"Las salidas de laboratorio/utilitarias con rosca de manguera comúnmente se protegen con rompedores de vacío de conexión de manguera (de tipo atmosférico) contra el retrosifonaje. Fuente: AWWA M14; ASSE 1011."},
  {id:167, q:"Si es posible que haya presión continua o contrapresión en una salida de peligro que no afecta la salud que de otro modo podría usar un AVB, la actualización adecuada es a un:", opts:["Tapón de grifo de manguera","PVB/DC (o RP para un peligro para la salud) capaz de soportar la condición de servicio","AVB más grande","Segundo AVB en serie"], re:"Debido a que un AVB no puede soportar presión continua ni contrapresión, el servicio se actualiza a un PVB (retrosifonaje, presión continua) o DC/RP según dicten el peligro y las condiciones. Fuente: AWWA M14; CA Title 17."},
  {id:168, q:"¿Cuál es el propósito de las llaves de prueba en un conjunto antirreflujo?", opts:["Drenar el edificio","Proporcionar puntos de conexión de manómetro para la comprobación en campo de las retenciones/válvula de alivio","Aliviar la expansión térmica","Admitir aire durante el retrosifonaje"], re:"Las llaves de prueba son válvulas pequeñas que permiten a un técnico certificado conectar un manómetro diferencial para medir la hermeticidad de la retención y la apertura de la válvula de alivio. Fuente: AWWA M14; USC FCCCHR."},
  {id:169, q:"En un conjunto antirreflujo, las válvulas de cierre de asiento resiliente se usan principalmente para:", opts:["Reducir la presión de suministro de forma permanente","Aislar el conjunto para comprobación y mantenimiento","Admitir aire al sistema","Reemplazar la válvula de alivio"], re:"Las válvulas de cierre de entrada y salida aíslan el conjunto para que pueda comprobarse o repararse. Fuente: AWWA M14; normas ASSE."},
  {id:170, q:"La válvula de alivio es un componente interno definitorio de cuál conjunto?", opts:["Doble retención (DC)","Rompedor de vacío de presión (PVB)","Principio de presión reducida (RP)","Rompedor de vacío atmosférico (AVB)"], re:"Solo el RP contiene una válvula de alivio de presión diferencial; el DC, el PVB y el AVB no la tienen. Fuente: AWWA M14."},
  {id:171, q:"La válvula de entrada de aire es un componente interno definitorio de cuál dispositivo/conjunto?", opts:["Conjunto de presión reducida","Rompedores de vacío de presión/atmosféricos (PVB/AVB/SVB)","Conjunto de doble retención","Conjunto detector RP"], re:"La válvula de entrada de aire (respiradero) es el componente característico de los rompedores de vacío (PVB/SVB/AVB), usada para romper un sifón; el DC/RP no tienen entrada de aire. Fuente: AWWA M14."},
  {id:172, q:"Las válvulas de retención usadas en los conjuntos RP y DC se caracterizan como:", opts:["De acción independiente y cargadas por fuerza (por resorte) a cerrado","Cargadas a abierto por resortes","Retenciones de aleta solo por gravedad","De operación manual"], re:"Tanto el RP como el DC usan válvulas de retención de acción independiente, cargadas internamente por fuerza (por resorte), que sellan contra el flujo inverso. Fuente: AWWA M14; ASSE 1013/1015."},
  {id:173, q:"Un 'asiento resiliente' en una válvula de retención o de cierre se refiere a:", opts:["Un asiento metal con metal","Una superficie de sellado elastomérica (de tipo caucho) para un sello hermético y de cierre gota a gota","Un disco de cerámica sin junta","Un tapón de latón roscado"], re:"Los asientos resilientes (elastoméricos) proporcionan el sello de cierre gota a gota requerido para los conjuntos antirreflujo y sus válvulas de cierre. Fuente: AWWA M14; AWWA C510/C511."},
  {id:174, q:"En un conjunto de cuatro llaves de prueba, la llave de prueba No. 1 generalmente se ubica:", opts:["Aguas abajo de la segunda retención","Solo en la válvula de alivio","Aguas arriba de la válvula de cierre de entrada/primera retención (lado de suministro)","En la entrada de aire"], re:"Por convención, la llave de prueba No. 1 está en el lado de suministro (aguas arriba de la primera retención), con las llaves siguientes numeradas a través de la zona y aguas abajo. Fuente: procedimientos de comprobación AWWA M14."},
  {id:175, q:"En un RP, la llave de prueba ubicada en la zona entre las dos retenciones permite al técnico medir:", opts:["La demanda del sistema aguas abajo","La presión de la zona de presión reducida y el punto de apertura de la válvula de alivio","La posición del flotador de entrada de aire","El caudal de la red de suministro principal"], re:"La llave de prueba de la zona lee la presión de la zona de presión reducida y se usa para determinar el diferencial de apertura de la válvula de alivio. Fuente: procedimiento de comprobación de RP AWWA M14."},
  {id:176, q:"En un PVB, ¿qué componente está cargado por fuerza hacia ABIERTO, la carga opuesta a la de la válvula de retención?", opts:["La válvula de cierre de entrada","La válvula de entrada de aire","La llave de prueba aguas abajo","El perno de la tapa"], re:"La entrada de aire del PVB está cargada por fuerza a abierto (la retención está cargada por fuerza a cerrado), por lo que se abre de golpe para admitir aire ante la pérdida de presión. Fuente: AWWA M14; ASSE 1020."},
  {id:177, q:"¿Qué componente encontraría en un SVB que NO se encuentra en un PVB estándar?", opts:["Una entrada de aire sellada por diafragma (resistente a derrames) con una válvula de purga/sangrado","Una segunda válvula de alivio","Dos válvulas de retención adicionales","Un espacio de aire accionado por flotador"], re:"El SVB añade una entrada de aire sellada por diafragma y una válvula de purga (sangrado) para contener el derrame, y usa una sola llave de prueba. Fuente: ASSE 1056."},
  {id:178, q:"El número de válvulas de retención de acción independiente en un RP y en un DC es:", opts:["Una en cada uno","Dos en cada uno","Tres en el RP, dos en el DC","Dos en el RP, una en el DC"], re:"Tanto el RP como el DC contienen dos válvulas de retención de acción independiente; el RP adicionalmente tiene una válvula de alivio entre ellas. Fuente: AWWA M14."},
  {id:179, q:"¿Cuál es la función principal de la(s) válvula(s) de retención en cualquiera de estos conjuntos?", opts:["Admitir aire a la línea","Permitir el flujo en una dirección y sellar contra el flujo inverso","Reducir la presión de la línea a cero","Medir bajos flujos"], re:"Las válvulas de retención permiten el flujo directo y se cierran para evitar el flujo inverso (de reflujo), la barrera básica en el DC, el RP y los rompedores de vacío. Fuente: AWWA M14."},
  {id:180, q:"En un RP, la válvula de alivio detecta el diferencial de presión referenciado a qué punto?", opts:["La salida aguas abajo","La presión de suministro (entrada) frente a la presión de la zona","Solo la presión atmosférica","La entrada de aire"], re:"La válvula de alivio compara la presión de suministro (entrada) con la presión de la zona de presión reducida y se abre cuando ese diferencial cae hacia ~2 psi. Fuente: AWWA M14."},
  {id:181, q:"Una válvula de purga/sangrado en un SVB se usa durante la comprobación para:", opts:["Presurizar la tubería aguas abajo","Ventilar la cámara de la tapa/entrada de aire para que pueda comprobarse la apertura de la entrada de aire","Aumentar la carga del resorte","Drenar todo el edificio"], re:"La válvula de purga (sangrado) del SVB libera la presión en la cámara de entrada de aire para que el técnico pueda verificar que la entrada de aire se abre en el punto correcto. Fuente: procedimiento de comprobación ASSE 1056."},
  {id:182, q:"¿Por qué se requiere que las dos válvulas de retención en un RP/DC operen de forma INDEPENDIENTE?", opts:["Para que el técnico deba abrir ambas a la vez","Para que la falla o la obstrucción de una retención no impida que la otra selle","Para compartir un solo resorte","Para eliminar las llaves de prueba"], re:"La operación independiente significa que cada retención sella por sí misma, preservando la redundancia si la otra se obstruye o falla. Fuente: AWWA M14; ASSE 1013/1015."},
  {id:183, q:"¿Qué componente interno permite que un RP expulse activamente agua de la zona central a la atmósfera cuando se amenaza la protección?", opts:["La retención aguas abajo","La válvula de cierre de entrada","La válvula de alivio de presión diferencial","Una llave de prueba"], re:"La válvula de alivio de presión diferencial descarga la zona a la atmósfera a través de un espacio de aire cuando el diferencial cae, lo cual es exclusivo del RP. Fuente: AWWA M14."},
  {id:184, q:"Un carbonatador de restaurante (sistema de bebidas con CO2) conectado al suministro potable requiere qué protección?", opts:["Un conjunto de doble válvula de retención","Un conjunto de principio de presión reducida (RP)","Un rompedor de vacío de presión","Un rompedor de vacío atmosférico"], re:"Un carbonatador presenta un peligro para la salud (CO2 reaccionando con el cobre más contrapresión) y requiere un conjunto RP. Fuente: AWWA M14; tablas de peligros CA Title 17."},
  {id:185, q:"Un sistema de riego que inyecta químicos fertilizantes/pesticidas (quimigación) requiere qué nivel de protección?", opts:["Rompedor de vacío atmosférico","Rompedor de vacío de presión","Conjunto de doble válvula de retención","Conjunto de presión reducida (RP) o espacio de aire"], re:"La inyección de químicos convierte el sistema en un peligro para la salud, lo que requiere un conjunto RP (o espacio de aire); un DC/PVB/AVB no es suficiente. Fuente: AWWA M14; CA Title 17."},
  {id:186, q:"Al seleccionar un conjunto, ¿qué dos factores impulsan más directamente la elección?", opts:["El color y la marca de la tubería","El grado de peligro (salud frente a no salud) y el tipo de reflujo (contrapresión frente a solo retrosifonaje)","Solo la preferencia y el precio del instalador","La época del año y el clima"], re:"La selección se rige por el nivel de peligro (salud/no salud) y por si puede producirse contrapresión (frente a solo retrosifonaje). Fuente: AWWA M14; CA Title 17."},
  {id:187, q:"Para un servicio de peligro que no afecta la salud donde PUEDE producirse contrapresión, ¿qué conjunto es apropiado?", opts:["Rompedor de vacío atmosférico","Rompedor de vacío de presión","Conjunto de doble válvula de retención","Rompedor de vacío de grifo de manguera"], re:"Un DC maneja peligros que no afectan la salud tanto bajo contrapresión como bajo retrosifonaje; el PVB/AVB no pueden soportar la contrapresión. Fuente: AWWA M14; CA Title 17."},
  {id:188, q:"Un PVB o AVB NO debe seleccionarse cuando está presente qué condición?", opts:["Solo retrosifonaje","Contrapresión (bomba aguas abajo, elevación o expansión térmica)","Una salida atmosférica abierta","Una sola zona de riego"], re:"Los rompedores de vacío (PVB/AVB) protegen solo contra el retrosifonaje y nunca deben usarse donde exista contrapresión. Fuente: AWWA M14; CA Title 17."},
  {id:189, q:"Un conjunto RP debe instalarse en qué orientación/ubicación para el funcionamiento adecuado de la válvula de alivio (a menos que esté certificado de otro modo)?", opts:["Sumergido en un sumidero","Horizontalmente por encima del nivel del suelo con el puerto de alivio despejado y un espacio de aire adecuado hacia el drenaje","Invertido por debajo de las salidas","Dentro de una bóveda sellada y llena de agua"], re:"Un RP normalmente se instala horizontalmente por encima del nivel del suelo con la descarga de alivio libre de sumersión y drenando a través de un espacio de aire; no debe instalarse donde la inundación pueda sumergir el puerto de alivio. Fuente: AWWA M14."},
  {id:190, q:"Se requiere un espacio libre adecuado alrededor de un conjunto instalado principalmente para:", opts:["Mejorar la apariencia","Permitir el acceso para comprobación, reparación y descarga de alivio/entrada de aire","Aumentar la presión del agua","Reducir el número de llaves de prueba"], re:"Los espacios libres (p. ej., alrededor y debajo del conjunto) se requieren para que un técnico pueda alcanzar las llaves de prueba y las válvulas de cierre y para que la descarga de alivio/entrada de aire esté libre de obstrucciones. Fuente: guía de instalación AWWA M14."},
  {id:191, q:"Un local con una fuente de agua auxiliar (pozo privado) con conexión cruzada al suministro público generalmente requiere qué protección en el servicio?", opts:["Rompedor de vacío atmosférico","Conjunto de doble válvula de retención","Conjunto de presión reducida (RP) o espacio de aire","Ninguna protección"], re:"Un suministro auxiliar no aprobado se trata como un peligro para la salud, lo que requiere un conjunto RP o un espacio de aire en la conexión de servicio. Fuente: AWWA M14; CA Title 17."},
  {id:192, q:"Una oficina médica/dental (aspiradores, esterilizadores) conectada a agua potable típicamente requiere:", opts:["Un conjunto de presión reducida (RP)","Un conjunto de doble válvula de retención","Un rompedor de vacío atmosférico","Un rompedor de vacío de grifo de manguera"], re:"Las instalaciones médicas/dentales son peligros para la salud (riesgo de reflujo de contaminantes) y requieren protección RP. Fuente: AWWA M14; tablas de peligros CA Title 17."},
  {id:193, q:"Para que un PVB funcione, la relación entre el conjunto y el sistema al que sirve debe ser:", opts:["El PVB al menos 12 in por encima de la salida aguas abajo más alta","El PVB por debajo de la salida más baja","El PVB al mismo nivel que las salidas","El PVB sumergido para enfriamiento"], re:"La entrada de aire del PVB debe estar al menos 12 in por encima de la salida aguas abajo más alta para que no pueda inundarse por reflujo y pueda romper el sifón. Fuente: AWWA M14; CA Title 17 §7603(b)."},
  {id:194, q:"¿Por qué nunca debe instalarse un RP en una ubicación sujeta a inundación aunque proporcione la protección de conjunto más alta?", opts:["El espacio de aire de su descarga de alivio puede quedar sumergido, creando una conexión cruzada","Perdería toda su clasificación de contrapresión","La inundación aumenta la presión de suministro","Las llaves de prueba se vuelven decorativas"], re:"Sumergir la descarga de alivio anula el espacio de aire y puede sifonear agua de inundación contaminada de vuelta a la línea potable; los puertos de alivio del RP deben permanecer por encima del nivel de inundación. Fuente: AWWA M14."},
  {id:195, q:"Una línea de rociadores contra incendios que usa aditivos no potables (anticongelante/espuma) es un peligro para la salud y requiere qué conjunto?", opts:["Conjunto detector de doble retención (DCDA)","Conjunto detector de presión reducida (RPDA)","Rompedor de vacío atmosférico","Rompedor de vacío de presión"], re:"Cuando una línea de incendios contiene aditivos químicos, se convierte en un peligro para la salud que requiere protección de nivel RP, es decir, un RPDA (RP con detector). Un DCDA simple es solo para líneas de incendios de peligro que no afecta la salud. Fuente: AWWA M14; CA Title 17."},
  {id:196, q:"Una línea de rociadores contra incendios estándar (sin aditivos) que es un peligro que no afecta la salud pero requiere detección de fugas/uso típicamente usa:", opts:["Un conjunto detector de presión reducida","Un conjunto detector de doble retención (DCDA)","Un rompedor de vacío atmosférico","Un rompedor de vacío de grifo de manguera"], re:"Una línea de incendios de peligro que no afecta la salud que necesita detección usa un DCDA; un RPDA se reserva para sistemas de incendios de peligro para la salud. Fuente: AWWA M14."},
  {id:197, q:"Cuando es posible la contrapresión en una conexión de peligro para la SALUD, la selección correcta es:", opts:["Rompedor de vacío de presión","Rompedor de vacío atmosférico","Conjunto de presión reducida (RP) o espacio de aire","Conjunto de doble válvula de retención"], re:"El peligro para la salud más la contrapresión requiere el conjunto mecánico más alto (RP) o un espacio de aire; el PVB/AVB no pueden soportar la contrapresión y un DC no está calificado para peligros para la salud. Fuente: AWWA M14; CA Title 17."},
  {id:198, q:"¿Qué práctica de instalación es correcta para un PVB que sirve riego de césped?", opts:["Instalarlo en una caja enterrada por debajo de los aspersores","Instalarlo en posición vertical al menos 12 in por encima del aspersor más alto, accesible para comprobación","Colocarlo de lado al nivel del suelo","Conectar su respiradero de tapa al alcantarillado"], re:"Un PVB debe estar en posición vertical, al menos 12 in por encima de la salida aguas abajo más alta y accesible para la comprobación anual. Fuente: AWWA M14; ASSE 1020; CA Title 17 §7603(b)."},
  {id:199, q:"La clasificación general de protección de la más alta a la más baja entre los métodos aprobados es:", opts:["AVB > PVB > DC > RP > Espacio de aire","Espacio de aire > RP > PVB > DC > AVB","DC > RP > Espacio de aire > PVB > AVB","PVB > AVB > RP > DC > Espacio de aire"], re:"Listados en protección decreciente: espacio de aire, luego RP, luego PVB, luego DC, luego AVB. Fuente: CA Title 17; clasificación de peligros AWWA M14."},
  {id:200, q:"Antes de seleccionar un conjunto, el paso más fundamental requerido por los programas de control de conexiones cruzadas es:", opts:["Pedir el conjunto más grande disponible","Evaluar el grado de peligro y el tipo de reflujo posible en la conexión","Elegir el dispositivo más barato","Instalar el dispositivo y luego comprobar el peligro"], re:"La protección adecuada sigue a una evaluación de peligros: determinar el peligro para la salud/no salud y si puede producirse contrapresión o solo retrosifonaje, luego seleccionar el conjunto correspondiente. Fuente: AWWA M14; CA Title 17 §7583 et seq."},
  {id:201, q:"¿Qué mide en realidad el instrumento de prueba utilizado para probar en campo los conjuntos de prevención de reflujo?", opts:["La diferencia de presión entre dos puntos, en libras por pulgada cuadrada diferencial (psid)","El caudal de agua a través del conjunto en galones por minuto","La presión estática absoluta de la línea en la tubería de suministro","La temperatura del agua en la descarga de la válvula de alivio"], re:"Un probador de reflujo utiliza un manómetro diferencial que lee la diferencia de presión entre sus lados alto y bajo en psid. Fuente: Manual AWWA M14; USC FCCCHR Field Test Procedures, 10.ª ed."},
  {id:202, q:"¿En qué rango de lectura está calibrado un manómetro diferencial estándar para reflujo?", opts:["0 a 150 psid","0 a 15 psid","0 a 5 psid","0 a 60 psid"], re:"Los manómetros de prueba de campo normalmente leen 0-15 psid (0-100 kPa), lo que cubre los pequeños diferenciales que se ven a través de las válvulas de retención y de alivio. Fuente: especificación del manómetro Mid-West Instrument 845-5; AWWA M14."},
  {id:203, q:"En un kit de prueba con manómetro diferencial de 3 válvulas, ¿cómo se llaman comúnmente las tres válvulas de aguja?", opts:["Válvulas de entrada, de salida y de drenaje","Válvulas roja, verde y azul","Control de alto, control de bajo y derivación (purga/vent)","Válvulas primaria, secundaria y terciaria"], re:"Un kit de 3 válvulas tiene un control del lado alto, un control del lado bajo y una válvula de derivación/purga (bleed). Fuente: USC FCCCHR Field Test Procedures; descripción del kit de prueba con manómetro diferencial de AWWA M14."},
  {id:204, q:"En comparación con un kit de 3 válvulas, ¿qué válvulas adicionales agrega un kit de prueba con manómetro diferencial de 5 válvulas?", opts:["Una válvula reductora de presión y una válvula de alivio","Un segundo manómetro y un caudalímetro","Solo dos conexiones de manguera adicionales, sin válvulas agregadas","Dos válvulas de purga adicionales (una purga alta y una purga baja)"], re:"Un kit de 5 válvulas agrega válvulas de purga dedicadas para el lado alto y el lado bajo a las válvulas de alto, bajo y derivación, lo que simplifica la eliminación del aire. Fuente: kit Mid-West 845-5 de 5 válvulas; AWWA M14."},
  {id:205, q:"Antes de registrar cualquier prueba, ¿por qué se debe purgar todo el aire de las mangueras y del cuerpo del manómetro?", opts:["Porque el aire atrapado se comprime y da una lectura diferencial falsa (inexacta)","Para evitar que las mangueras se congelen","Para reducir la presión de la línea de suministro antes de probar","Para evitar que las llaves de prueba goteen"], re:"El aire atrapado es compresible y distorsiona la lectura diferencial, por lo que las mangueras y el manómetro se deben purgar de aire antes de tomar las lecturas. Fuente: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:206, q:"¿Dónde se debe colocar el manómetro diferencial con respecto al conjunto durante una prueba?", opts:["Al menos 3 pies por encima del conjunto","Aproximadamente a la misma elevación que el conjunto","Siempre por debajo del conjunto, en el suelo","La elevación no importa para las lecturas diferenciales"], re:"El manómetro y las mangueras se deben mantener a la misma altura que el conjunto para que la columna de agua en las mangueras no agregue un error de elevación a la lectura diferencial. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:207, q:"Según los requisitos reglamentarios comunes, ¿con qué frecuencia se debe calibrar el manómetro diferencial de un probador de reflujo?", opts:["Una vez cada cinco años","Solo cuando se compra por primera vez","Al menos una vez al año","Una vez al mes"], re:"La mayoría de las jurisdicciones exigen que el manómetro diferencial de prueba se calibre al menos una vez al año, y la fecha de calibración se registra en el informe de prueba. Fuente: AWWA M14; reglas de los programas estatales de conexiones cruzadas (p. ej., NY DOH, informe de prueba de Denver Water)."},
  {id:208, q:"¿Cuál es el propósito de la válvula de purga (vent) en un kit de prueba con manómetro diferencial?", opts:["Aumentar la presión de suministro al conjunto","Cortar el suministro de agua del cliente","Medir el caudal a través de la válvula de retención N.º 1","Permitir que el aire y el agua atrapados escapen para poder purgar las mangueras"], re:"La válvula de purga/vent permite que el aire y el agua escapen del kit y de las mangueras para que las líneas se puedan llenar y queden sin aire antes de una lectura. Fuente: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:209, q:"En un kit de prueba codificado por colores típico, la manguera del lado ALTO y la del lado BAJO suelen ser de qué colores?", opts:["Alto = rojo, Bajo = verde (o azul)","Alto = verde, Bajo = rojo","Alto = amarillo, Bajo = negro","Ambas mangueras son blancas"], re:"Los kits de prueba suelen colorear la manguera del lado alto de rojo y la del lado bajo de verde (o azul) para que el probador conecte cada una a la llave de prueba correcta. Fuente: AWWA M14; ilustraciones del procedimiento de prueba de PNW-AWWA."},
  {id:210, q:"Muchos kits de prueba incluyen mallas filtrantes de 90 micrones en las conexiones de las mangueras. ¿Cuál es su propósito principal?", opts:["Reducir la presión del agua que entra al manómetro","Evitar que la incrustación, la arena y los residuos obstruyan los conductos del manómetro","Calentar el agua antes de que llegue al manómetro","Agregar cloro al agua de prueba"], re:"Las mallas filtrantes en línea evitan que la arena, la incrustación y la suciedad entren y obstruyan los pequeños conductos internos del manómetro diferencial. Fuente: literatura del kit de prueba de Mid-West Instrument; AWWA M14."},
  {id:211, q:"¿Qué debe hacer un probador con las llaves de prueba antes de conectar las mangueras del manómetro?", opts:["Dejarlas tapadas y conectar sobre las tapas","Pintarlas para marcar cuál es cuál","Abrir cada una brevemente para expulsar los residuos y luego conectar las mangueras","Quitarlas por completo del conjunto"], re:"Cada llave de prueba se abre brevemente para expulsar la suciedad y los residuos del puerto antes de conectar la manguera, lo que protege el manómetro. Fuente: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:212, q:"La exactitud declarada de un manómetro diferencial típico para reflujo es la más cercana a qué valor?", opts:["Más o menos 0.001 psid","Más o menos 2 psid","Más o menos 5 psid","Más o menos 0.2 psid"], re:"Un manómetro de campo típico tiene una exactitud de aproximadamente más o menos 0.2 psid en la lectura descendente. Fuente: especificación del Mid-West Instrument 845-5; AWWA M14."},
  {id:213, q:"Cuando un kit de prueba está conectado con las mangueras de alto y bajo en la misma retención cerrada, ¿qué lectura debe mostrar un manómetro exacto y bien purgado?", opts:["Aproximadamente cero psid (sin diferencial) hasta que las presiones difieran","La presión total de la línea","Aproximadamente 15 psid","Una lectura negativa igual a la presión atmosférica"], re:"Con ambos lados detectando la misma presión y sin diferencial aplicado, un manómetro bien purgado lee cerca de cero; una lectura estática distinta de cero indica aire atrapado o un problema del manómetro. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:214, q:"¿Cuál es la función de la válvula de 'derivación' (vent) al establecer condiciones de flujo a través de un manómetro durante la configuración?", opts:["Aísla permanentemente el lado bajo del lado alto","Conecta los lados alto y bajo para que el agua se mueva a través y purgue el kit","Ventea la tubería de suministro a la atmósfera","Calibra la aguja a cero automáticamente"], re:"Abrir la derivación conecta las cámaras alta y baja para que el agua fluya a través del kit, lo que permite arrastrar el aire atrapado durante la purga. Fuente: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:215, q:"¿Por qué la válvula de control del lado alto suele dejarse abierta durante toda una prueba diferencial de RP o DC una vez que el kit está configurado?", opts:["Para evitar que la válvula de alivio se abra alguna vez","Para drenar lentamente el calentador de agua del cliente","Para mantener la presión de suministro continuamente detectada en el lado alto del manómetro","Porque cerrarla dañaría el manómetro"], re:"Mantener abierta la válvula del lado alto conserva la presión de referencia aguas arriba/de suministro en el lado alto del manómetro durante toda la prueba. Fuente: procedimientos de RP y DC de USC FCCCHR / PNW-AWWA."},
  {id:216, q:"Los fabricantes describen un kit de prueba de 5 válvulas como capaz de probar qué conjuntos?", opts:["Solo conjuntos de principio de presión reducida (RP)","Solo conjuntos detectores de línea contra incendios","Solo interruptores de vacío de presión","Conjuntos RP, doble retención (DC) e interruptor de vacío de presión (PVB)"], re:"Un kit de 5 válvulas puede realizar pruebas de campo en conjuntos RP, DC y PVB y está calificado para los procedimientos de ASSE, AWWA, CSA y USC. Fuente: literatura del kit Mid-West 845-5; AWWA M14."},
  {id:217, q:"Antes de comenzar la prueba, se debe verificar que el manómetro diferencial lea qué cuando no se aplica presión?", opts:["Cero (la aguja descansa en la marca de cero)","Exactamente 15 psid","Media escala","La presión barométrica local"], re:"Sin diferencial aplicado, la aguja debe descansar en cero; una aguja fuera de cero indica que el manómetro necesita atención antes de confiarse para una prueba. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:218, q:"Para APROBAR, la válvula de alivio de un conjunto de principio de presión reducida (RP) debe comenzar a abrir (aliviar) a una presión diferencial de al menos cuánto?", opts:["1.0 psid","2.0 psid","5.0 psid","0.5 psid"], re:"La válvula de alivio del RP debe abrir a un diferencial mínimo de 2.0 psid para aprobar la prueba de campo. Fuente: Manual AWWA M14; USC FCCCHR Field Test Procedures, 10.ª ed."},
  {id:219, q:"Para que un conjunto RP apruebe, la válvula de retención N.º 1 debe sostener una presión diferencial de al menos cuánto en la dirección del flujo?", opts:["1.0 psid","2.0 psid","5.0 psid","10.0 psid"], re:"La válvula de retención N.º 1 de un RP debe sostener al menos 5.0 psid en la dirección del flujo para aprobar. Fuente: AWWA M14; USC FCCCHR Field Test Procedures, 10.ª ed."},
  {id:220, q:"Además de su valor mínimo, ¿qué relación debe tener el diferencial de la válvula de retención N.º 1 con el punto de apertura de la válvula de alivio en un RP?", opts:["Debe ser igual al punto de apertura de la válvula de alivio","No tiene ninguna relación requerida con la válvula de alivio","Debe ser inferior al punto de apertura de la válvula de alivio","Debe ser al menos 3 psid superior al punto de apertura de la válvula de alivio"], re:"La primera retención debe sostener un diferencial al menos 3.0 psid mayor que el punto de apertura de la válvula de alivio (un 'margen'), de modo que la válvula de alivio abra antes de que la primera retención gotee. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:221, q:"¿Cuántas llaves de prueba tiene un conjunto RP típico?", opts:["Cuatro","Dos","Una","Seis"], re:"Un conjunto RP tiene cuatro llaves de prueba (N.º 1 aguas arriba de la retención N.º 1, N.º 2 y N.º 3 en la región de la zona de presión reducida, N.º 4 aguas abajo de la retención N.º 2). Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:222, q:"En el procedimiento de RP de la 10.ª edición de USC, ¿qué componente se prueba PRIMERO?", opts:["La válvula de retención N.º 2","El punto de apertura de la válvula de alivio","La válvula de retención N.º 1","La válvula de cierre aguas abajo"], re:"La 10.ª edición de USC prueba primero el punto de apertura de la válvula de alivio, lo que también confirma que el conjunto está en condición estática antes de probar las retenciones. Fuente: USC FCCCHR Field Test Procedures, 10.ª ed."},
  {id:223, q:"¿Qué hace la válvula de alivio de un conjunto RP cuando el diferencial entre el suministro y la zona cae a su punto de apertura?", opts:["Se cierra con más fuerza para sostener la presión","Aumenta la presión de suministro","Se abre y descarga agua de la zona a la atmósfera","Bloquea las válvulas de retención abiertas"], re:"Cuando el diferencial de la zona cae a aproximadamente 2 psid, la válvula de alivio se abre y vierte la zona de presión reducida a la atmósfera, evitando el reflujo. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:224, q:"Durante una prueba de RP, ¿para qué se utiliza principalmente la llave de prueba N.º 4?", opts:["Ajustar el resorte de la válvula de alivio","Drenar el sistema de riego del cliente","Montar el cuerpo del manómetro diferencial","Detectar la presión aguas abajo de la válvula de retención N.º 2"], re:"La llave de prueba N.º 4 está ubicada aguas abajo de la segunda retención y se utiliza para detectar la presión aguas abajo al probar la retención N.º 2. Fuente: AWWA M14; procedimiento de prueba de RP de PNW-AWWA."},
  {id:225, q:"Al probar el punto de apertura de la válvula de alivio, ¿en qué momento se registra la lectura?", opts:["Cuando la válvula de alivio comienza a descargar por primera vez (el agua gotea/fluye por primera vez del puerto de alivio)","Después de que la válvula de alivio haya estado descargando durante cinco minutos","Cuando la aguja del manómetro alcanza 15 psid","Cuando la válvula de cierre aguas abajo está completamente abierta"], re:"El diferencial se lee en el instante en que la válvula de alivio se abre por primera vez y el agua comienza a descargar del puerto de alivio. Fuente: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:226, q:"¿Qué válvula de cierre se debe cerrar para aislar un conjunto RP para probar las retenciones (de modo que se pueda establecer un diferencial estático)?", opts:["La válvula de cierre N.º 1 (aguas arriba)","La válvula de cierre N.º 2 (aguas abajo)","Ambas válvulas de cierre a la vez","No se cierra ninguna válvula de cierre"], re:"El cierre aguas abajo (N.º 2) se cierra para aislar el conjunto de la demanda aguas abajo, de modo que se pueda leer un diferencial estático estable a través de las retenciones. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:227, q:"Si la válvula de alivio de un RP descarga agua continuamente durante el servicio normal, ¿qué indica esto típicamente?", opts:["El conjunto funciona perfectamente","La presión de suministro es demasiado alta para probar","Una primera retención N.º 1 obstruida o un problema de válvula de alivio/zona que hace que el diferencial de la zona caiga","La válvula de cierre aguas abajo está abierta"], re:"La descarga de alivio continua suele significar que el diferencial de la zona ha caído (a menudo una primera retención obstruida o un asiento de alivio con fugas), y se debe diagnosticar y reparar la causa. Fuente: USC FCCCHR Field Test Procedures; resolución de problemas de AWWA M14."},
  {id:228, q:"Para la prueba de apertura de la válvula de alivio en un RP usando el manómetro, ¿qué llaves de prueba se utilizan comúnmente para detectar la presión alta (suministro) y la de la zona?", opts:["No se utiliza ninguna llave de prueba para este paso","Solo la llave de prueba N.º 1 y la llave de prueba N.º 4","Solo la llave de prueba N.º 4","La llave de prueba N.º 2 (lado alto/suministro) y la llave de prueba N.º 3 (lado de la zona)"], re:"La manguera de alto detecta la región del suministro/primera retención (N.º 2) y la manguera de bajo detecta la zona (N.º 3), de modo que el manómetro sigue el diferencial de la zona a medida que se abre la válvula de alivio. Fuente: procedimiento de prueba de RP de PNW-AWWA / USC."},
  {id:229, q:"En el procedimiento de RP de USC, después de la prueba de la válvula de alivio, ¿qué retención se prueba antes de la primera retención?", opts:["La válvula de retención N.º 2 (con contrapresión)","No hay segunda retención que probar","Se vuelve a probar la válvula de alivio","La retención de derivación"], re:"La secuencia de USC prueba la válvula de alivio, luego la retención N.º 2 bajo contrapresión y finaliza con la retención N.º 1 en la dirección del flujo. Fuente: USC FCCCHR Field Test Procedures, 10.ª ed."},
  {id:230, q:"¿Por qué la primera válvula de retención del RP debe sostener un diferencial MÁS ALTO que el punto de apertura de la válvula de alivio?", opts:["Para que el manómetro lea cero","Para que la válvula de alivio descargue antes de que la primera retención tenga fugas hacia atrás, manteniendo la zona segura","Para que la segunda retención nunca tenga que cerrar","Para reducir la presión de suministro"], re:"El margen garantiza que la válvula de alivio vierta la zona antes de que la primera retención pueda dejar pasar agua hacia atrás, preservando la protección de presión reducida. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:231, q:"La válvula de alivio de un RP abre exactamente a 2.0 psid y la retención N.º 1 sostiene 4.0 psid. ¿Aprueba el conjunto?", opts:["Sí, ambos valores cumplen todos los requisitos","Sí, porque solo importa la válvula de alivio","No, porque la primera retención debe sostener al menos 5.0 psid Y estar 3 psid por encima de la apertura del alivio","No, porque la válvula de alivio abrió demasiado bajo"], re:"La válvula de alivio (2.0 psid) aprueba, pero la retención N.º 1 a 4.0 psid no cumple el mínimo de 5.0 psid ni la regla del margen de 3 psid, por lo que el conjunto no aprueba. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:232, q:"¿Qué se debe hacer antes de iniciar una prueba de campo de RP, con respecto al cliente?", opts:["Nada; la prueba nunca afecta el servicio","Desconectar el medidor de agua","Cortar la electricidad del cliente","Notificar al cliente que el servicio de agua se interrumpirá durante la prueba"], re:"El probador debe notificar al cliente porque el cierre aguas abajo se cierra y el servicio se interrumpe durante la prueba. Fuente: USC FCCCHR Field Test Procedures; procedimientos estatales de RP (p. ej., GAWP)."},
  {id:233, q:"Si la válvula de alivio de un RP abre a solo 1.5 psid durante la prueba, ¿cuál es el resultado?", opts:["No aprueba porque el punto de apertura está por debajo del mínimo de 2.0 psid","Aprueba porque abrió","Aprueba si las retenciones están herméticas","La lectura se debe ignorar"], re:"Un punto de apertura por debajo de 2.0 psid no cumple el requisito de la válvula de alivio y el conjunto no puede aprobar hasta que se repare. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:234, q:"En un RP, ¿dónde está ubicada la llave de prueba N.º 1?", opts:["Aguas abajo de la segunda válvula de retención","Aguas arriba de la primera válvula de retención (lado de suministro)","Dentro de la válvula de alivio","En la válvula de cierre aguas abajo"], re:"La llave de prueba N.º 1 está en el lado de suministro, aguas arriba de la primera retención, y se utiliza para leer la presión de la línea de suministro. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:235, q:"Para que un conjunto de doble retención (DC) apruebe, ¿qué presión diferencial debe sostener cada válvula de retención como mínimo en la dirección del flujo?", opts:["5.0 psid","2.0 psid","1.0 psid","0.5 psid"], re:"Cada retención de un conjunto DC debe sostener un mínimo de 1.0 psid en la dirección normal del flujo para aprobar. Fuente: Manual AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:236, q:"¿Cuántas llaves de prueba tiene un conjunto de válvula de doble retención típico?", opts:["Una","Dos","Ocho","Cuatro"], re:"Un conjunto DC tiene cuatro llaves de prueba: N.º 1 aguas arriba de la retención 1, N.º 2 entre el cierre y la retención 1, N.º 3 entre las retenciones y N.º 4 aguas abajo de la retención 2. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:237, q:"Al probar la hermeticidad de la válvula de retención N.º 1 de un DC, ¿entre qué dos llaves de prueba se mide el diferencial?", opts:["La llave de prueba N.º 2 (alto) y la llave de prueba N.º 3 (bajo)","La llave de prueba N.º 1 y la llave de prueba N.º 4","Solo la llave de prueba N.º 4","Solo la llave de prueba N.º 3, venteada"], re:"La hermeticidad de la retención N.º 1 se lee con la manguera de alto en el lado aguas arriba (llave de prueba N.º 2) y la manguera de bajo entre las retenciones (llave de prueba N.º 3). Fuente: AWWA M14; procedimiento de prueba de DC de PNW-AWWA."},
  {id:238, q:"Al probar la hermeticidad de la válvula de retención N.º 2 de un DC, ¿dónde se conectan comúnmente las mangueras del manómetro?", opts:["Manguera de alto a la llave de prueba N.º 1 y manguera de bajo a la llave de prueba N.º 2","Manguera de alto a la llave de prueba N.º 3 y manguera de bajo a la llave de prueba N.º 4","Ambas mangueras a la llave de prueba N.º 1","Ninguna manguera; es una prueba visual"], re:"La hermeticidad de la retención N.º 2 se lee con la manguera de alto entre las retenciones (llave de prueba N.º 3) y la manguera de bajo aguas abajo (llave de prueba N.º 4). Fuente: AWWA M14; procedimiento de prueba de DC de PNW-AWWA."},
  {id:239, q:"Una válvula de retención de DC sostiene 1.0 psid en la dirección del flujo. ¿Qué se concluye sobre su hermeticidad en flujo inverso?", opts:["Tendrá fugas en sentido inverso y no aprueba","No se puede inferir el flujo inverso y es obligatoria una segunda prueba","Se asume que también se mantendrá hermética en la dirección inversa del flujo","Debe sostener 5.0 psid en sentido inverso para aprobar"], re:"AWWA M14 sostiene que si una retención sella a 1.0 psid o más en la dirección normal, se asume que se mantendrá hermética contra el flujo inverso. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:240, q:"¿Qué válvula de cierre se cierra para aislar un conjunto DC de modo que se pueda leer un diferencial estático a través de las retenciones?", opts:["No se cierra ningún cierre","La válvula de cierre N.º 1 (aguas arriba)","Ambos cierres simultáneamente","La válvula de cierre N.º 2 (aguas abajo)"], re:"El cierre aguas abajo (N.º 2) se cierra para eliminar la demanda aguas abajo y establecer una condición estática para las lecturas diferenciales. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:241, q:"Cuando la lectura del manómetro se estabiliza y el agua deja de fluir de la llave de prueba aguas abajo durante una prueba de retención de DC, ¿qué se registra?", opts:["La lectura estabilizada en psid, y la retención se registra como hermética a ese valor","La presión de la línea de suministro","El caudal en gpm","La temperatura del agua"], re:"Cuando el flujo se detiene y la aguja se asienta, se registra el diferencial estabilizado; si es de 1.0 psid o más, la retención se registra como hermética. Fuente: AWWA M14; procedimiento de prueba de DC de PNW-AWWA."},
  {id:242, q:"La retención N.º 1 de un DC sostiene 0.8 psid y la retención N.º 2 sostiene 2.5 psid. ¿Cuál es el resultado general de la prueba?", opts:["Aprueba, porque las dos retenciones promedian por encima de 1.0 psid","No aprueba, porque la retención N.º 1 está por debajo del mínimo de 1.0 psid","Aprueba, porque al menos una retención supera 1.0 psid","No aprueba, porque la retención N.º 2 sostuvo demasiado"], re:"Cada retención se juzga de forma independiente; la retención N.º 1 a 0.8 psid está por debajo del mínimo de 1.0 psid, por lo que el conjunto no aprueba. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:243, q:"¿Qué afirmación sobre un conjunto DC es correcta en comparación con un RP?", opts:["Un DC tiene una válvula de alivio como un RP","Un DC tiene solo una válvula de retención","Un DC no tiene válvula de alivio; depende de dos válvulas de retención que operan de forma independiente","Un DC ventea a la atmósfera entre las retenciones como un RP"], re:"Un DC tiene dos retenciones con resorte independientes y ninguna válvula de alivio atmosférica, por lo que no vierte a la atmósfera como lo hace un RP. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:244, q:"En un DC, ¿qué lee la llave de prueba N.º 1?", opts:["La presión entre las dos retenciones","La descarga de la válvula de alivio","La presión aguas abajo de la segunda retención","La presión de la línea de suministro, aguas arriba de la primera retención"], re:"La llave de prueba N.º 1 está aguas arriba de la retención N.º 1 y se utiliza para leer la presión de la línea de suministro. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:245, q:"¿Por qué se debe purgar el aire de las mangueras del manómetro antes de leer cualquiera de las retenciones de un DC?", opts:["Porque el aire compresible da una lectura diferencial falsamente baja o inestable","Para elevar el diferencial artificialmente","Para enfriar el conjunto","Para abrir la segunda válvula de retención"], re:"El aire en las líneas se comprime y corrompe el pequeño diferencial que se está midiendo, por lo que se deben purgar las mangueras antes de leer el diferencial de la retención. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:246, q:"Una 'válvula de cierre N.º 2 con fugas' puede afectar una prueba de la retención N.º 2 de un DC. ¿Qué característica protege la prueba contra esto?", opts:["Abrir completamente la llave de prueba N.º 1","Instalar un arreglo de válvula de purga en la llave de prueba del lado alto para el procedimiento de una manguera","Quitar el manómetro por completo","Cerrar el cierre aguas arriba en su lugar"], re:"El procedimiento de USC agrega una válvula de purga en la llave de prueba del lado alto para que un cierre N.º 2 con fugas no invalide la lectura de la retención N.º 2 con una manguera. Fuente: USC FCCCHR Field Test Procedures, 10.ª ed."},
  {id:247, q:"Durante la prueba de la retención N.º 2 de un DC con el método de una manguera, ¿qué llave de prueba se abre a la atmósfera en el lado aguas abajo?", opts:["La llave de prueba N.º 2","La llave de prueba N.º 1","La llave de prueba N.º 4","El puerto de la válvula de alivio"], re:"Con la manguera de alto en la llave de prueba N.º 3, se abre la llave de prueba N.º 4 para que el lado aguas abajo detecte la atmósfera para el diferencial de la retención N.º 2. Fuente: AWWA M14; procedimiento de prueba de DC de PNW-AWWA."},
  {id:248, q:"Si, al probar la retención N.º 1 de un DC, el diferencial no se acumula y el agua sigue moviéndose, ¿cuál es una causa probable?", opts:["La primera retención sella perfectamente","La presión aguas abajo es cero por diseño","El rango del manómetro es demasiado alto","La primera retención está obstruida/con fugas o un cierre deja pasar agua"], re:"La incapacidad de acumular y sostener un diferencial indica una primera retención con fugas o una válvula de cierre que deja pasar agua, lo que se debe diagnosticar. Fuente: resolución de problemas de AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:249, q:"Para un DC, la presión de la línea de suministro para el informe normalmente se lee en qué punto?", opts:["En la llave de prueba N.º 1 con el cierre N.º 1 abierto","En la llave de prueba N.º 4 con ambos cierres cerrados","En la válvula de alivio","Solo en la llave de prueba N.º 3"], re:"La presión de suministro/línea se lee en la llave de prueba N.º 1 en el lado de suministro. Fuente: AWWA M14; instrucciones del informe de prueba estatal (p. ej., Denver Water)."},
  {id:250, q:"Ambas retenciones de un DC deben cerrar 'herméticamente al goteo'. En términos de prueba, ¿qué requiere realmente la aprobación?", opts:["Cada retención sostiene al menos 5.0 psid","Cada retención sostiene al menos 1.0 psid de diferencial estático en la dirección del flujo","Las retenciones juntas sostienen 1.0 psid","No se permite ningún diferencial medible"], re:"Cada retención aprueba cuando sostiene un diferencial estático de 1.0 psid o más en la dirección del flujo, lo que confirma un sellado hermético. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:251, q:"En un conjunto de DOBLE retención DETECTOR (DCDA), la pequeña línea del medidor de derivación también contiene qué para la prueba?", opts:["Ninguna protección contra reflujo","Una válvula de alivio idéntica a la de un RP","Su propio conjunto de doble retención que también se debe probar","Solo un interruptor de vacío de presión"], re:"Un conjunto de doble retención detector tiene una derivación medida que contiene su propia doble retención, que se prueba con los mismos criterios de 1.0 psid por retención. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:252, q:"Para que un interruptor de vacío de presión (PVB) apruebe, la válvula de entrada de aire debe comenzar a abrir a una presión de al menos cuánto por encima de la atmosférica?", opts:["0.5 psi","2.0 psi","5.0 psi","1.0 psi"], re:"La entrada de aire del PVB debe abrir cuando la presión interna no sea inferior a 1.0 psi por encima de la atmosférica para aprobar. Fuente: Manual AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:253, q:"Para que un PVB apruebe, la única válvula de retención debe sostener una presión diferencial de al menos cuánto?", opts:["1.0 psid","2.0 psid","5.0 psid","0.5 psid"], re:"La válvula de retención del PVB debe sostener al menos 1.0 psid para aprobar. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:254, q:"¿Cuántas llaves de prueba tiene un PVB típico?", opts:["Una","Dos","Cuatro","Seis"], re:"Un PVB tiene dos llaves de prueba, una a cada lado, utilizadas para probar la válvula de retención y el punto de apertura de la entrada de aire. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:255, q:"¿En qué se diferencia estructuralmente un interruptor de vacío resistente a derrames (SVB) de un PVB para la prueba?", opts:["Un SVB tiene cuatro llaves de prueba","Un SVB tiene una válvula de alivio como un RP","Un SVB tiene una sola llave de prueba más una válvula de vent (purga) en lugar de dos llaves de prueba","Un SVB no tiene entrada de aire"], re:"Un SVB tiene solo una única llave de prueba junto con una válvula de vent/purga, mientras que un PVB tiene dos llaves de prueba. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:256, q:"Para que un SVB apruebe, la entrada de aire debe abrir a un mínimo de cuánto, y además debe hacer qué?", opts:["5.0 psi mínimo, y descargar agua","2.0 psi mínimo, y solo abrir un poco","0.5 psi mínimo, y permanecer cerrada","1.0 psi mínimo, y la entrada de aire debe abrir por completo"], re:"La entrada de aire del SVB debe abrir a 1.0 psi o más y debe abrir por completo. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:257, q:"Para un SVB, ¿qué diferencial debe sostener la válvula de retención como mínimo para aprobar?", opts:["1.0 psid","2.0 psid","3.0 psid","0.5 psid"], re:"La válvula de retención del SVB debe sostener al menos 1.0 psid para aprobar. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:258, q:"En un PVB, ¿qué válvula de cierre se cierra al aislar el conjunto para probar la válvula de retención y la entrada de aire?", opts:["Solo el cierre aguas arriba","El cierre aguas abajo (con el cierre aguas arriba verificado abierto)","Ambos cierres a la vez","Ninguno; los PVB no tienen cierres"], re:"El cierre aguas abajo se cierra (y se confirma que el cierre aguas arriba está abierto) para que el cuerpo se pueda aislar para las pruebas de entrada de aire y de retención. Fuente: AWWA M14; procedimiento de prueba de PVB de PNW-AWWA."},
  {id:259, q:"Debido a cómo funciona un PVB, ¿dónde se debe instalar con respecto a todas las salidas aguas abajo?", opts:["Por debajo de la salida más baja","Al mismo nivel que las salidas","Al menos 12 pulgadas por encima de toda la tubería y salidas aguas abajo que protege","Bajo tierra en una bóveda"], re:"Un PVB se debe instalar al menos 12 pulgadas por encima de toda la tubería/salidas aguas abajo, porque solo protege contra la sifonación inversa, no contra la contrapresión. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:260, q:"¿Por qué un PVB o SVB NO se puede usar donde pueda ocurrir contrapresión?", opts:["Leería demasiado alto en el manómetro","Solo funciona con agua caliente","Tiene demasiadas llaves de prueba","Su entrada de aire proporciona protección contra sifonación inversa únicamente, no contra contrapresión"], re:"Los conjuntos PVB y SVB protegen contra la sifonación inversa únicamente; bajo contrapresión la entrada de aire no puede evitar el reflujo, por lo que no se deben usar donde pueda existir contrapresión. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:261, q:"En la secuencia de prueba estándar de PVB/SVB, ¿qué se prueba primero?", opts:["La válvula de retención primero, luego el punto de apertura de la entrada de aire","El punto de apertura de la entrada de aire, luego la válvula de retención","Ambos al mismo tiempo","La válvula de alivio, luego la retención"], re:"Los procedimientos de USC y AWWA prueban la válvula de retención primero y luego el punto de apertura de la entrada de aire. Fuente: AWWA M14; USC FCCCHR Field Test Procedures (SVB/PVB)."},
  {id:262, q:"Durante la prueba de la entrada de aire del PVB, ¿en qué instante se toma la lectura?", opts:["Después de que la entrada de aire haya estado abierta durante 10 minutos","Cuando la entrada de aire se abre por primera vez (el punto en el que el aire comienza a entrar / el obturador se levanta)","Cuando el manómetro alcanza 15 psid","Cuando la válvula de retención se cierra"], re:"El diferencial se lee en el instante en que la entrada de aire se abre, observado visualmente cuando el obturador se levanta o el aire entra. Fuente: AWWA M14; procedimiento de prueba de PVB de PNW-AWWA."},
  {id:263, q:"En una prueba de la válvula de retención de un PVB, ¿a qué llave de prueba se conecta la manguera del lado alto?", opts:["A ninguna; se lee en la entrada de aire","A la llave de prueba N.º 1","A la llave de prueba N.º 2","A ambas llaves de prueba a la vez"], re:"Para la prueba de la retención del PVB, la manguera del lado alto se conecta a la llave de prueba N.º 2 (aguas abajo de la retención), luego se abre la purga para leer el diferencial de la retención. Fuente: AWWA M14; procedimiento de prueba de PVB de PNW-AWWA."},
  {id:264, q:"En una prueba de la válvula de retención de un SVB, ¿cuándo se registra la lectura del manómetro?", opts:["Cuando la presión de suministro alcanza 80 psi","Tan pronto como se conecta la manguera","Después de que falle la entrada de aire","Cuando el agua deja de drenar de la válvula de vent"], re:"Para el SVB, la purga se abre lentamente hasta que el agua deja de drenar de la válvula de vent; esa lectura estabilizada (1.0 psi o más) se registra para la retención. Fuente: AWWA M14; procedimiento de prueba de SVB de Mid-West."},
  {id:265, q:"La entrada de aire de un PVB abre a 0.7 psi durante la prueba. ¿Cuál es el resultado?", opts:["No aprueba, porque el punto de apertura está por debajo del mínimo de 1.0 psi","Aprueba, porque abrió de todos modos","Aprueba, si la retención sostiene 1.0 psid","La lectura se descarta"], re:"Un punto de apertura de la entrada de aire por debajo de 1.0 psi no cumple el requisito; el PVB no puede aprobar hasta que se repare. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:266, q:"¿Qué ventaja tiene un SVB ('resistente a derrames') sobre un PVB estándar?", opts:["Se puede instalar bajo nivel del suelo","Está diseñado para resistir el derrame de agua de la entrada de aire durante el arranque/presurización normal","Proporciona protección contra contrapresión","No necesita prueba"], re:"El SVB está diseñado para minimizar el derrame de agua por la entrada de aire durante la presurización, que un PVB estándar puede liberar. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:267, q:"Para la prueba de la entrada de aire del PVB, la purga del lado alto se abre lentamente mientras se observa qué?", opts:["El medidor de agua del cliente","El manómetro de presión de la tubería de suministro","El obturador de la entrada de aire, para captar la lectura del manómetro en el momento en que se abre","La descarga de la válvula de alivio"], re:"El probador purga lentamente la presión mientras observa la entrada de aire y registra la lectura del manómetro en el momento en que la entrada se abre. Fuente: AWWA M14; procedimiento de prueba de PVB de PNW-AWWA."},
  {id:268, q:"Al probar un SVB, ¿dónde se deben mantener el kit de prueba y la manguera?", opts:["Al menos 5 pies por encima del SVB","La elevación es irrelevante para un SVB","Por debajo del SVB","Al mismo nivel (elevación) que el SVB"], re:"El kit de prueba y la manguera se mantienen al mismo nivel que el SVB para que la elevación no agregue error a las lecturas. Fuente: AWWA M14; procedimiento de prueba de SVB de Mid-West."},
  {id:269, q:"Mientras se lee un diferencial de válvula de retención, la aguja del manómetro sigue derivando hacia abajo y no se estabiliza. ¿Qué significa esto con mayor probabilidad?", opts:["La retención tiene fugas (no se mantiene hermética) o queda aire en las líneas","La retención sella perfectamente","La presión de suministro es exactamente correcta","La válvula de alivio aprobó"], re:"Una aguja que no se sostiene y deriva hacia abajo indica una retención con fugas o aire residual; una retención que aprueba sostiene un diferencial estable. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:270, q:"Una lectura diferencial se describe como 'aparente' si existe qué condición?", opts:["El manómetro es nuevo","Las mangueras todavía contienen aire atrapado que afecta la lectura","El agua está fría","El conjunto es un RP"], re:"El aire atrapado hace que una lectura sea 'aparente' en lugar de verdadera; las líneas se deben purgar por completo para que el manómetro muestre el diferencial real. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:271, q:"Cuando se abre la purga del lado alto durante una prueba de la retención N.º 1 de un RP y la aguja sube y luego se mantiene estable, ¿qué representa el valor sostenido?", opts:["La presión barométrica","El caudal a través del conjunto","El diferencial estático que sostiene la primera retención","La tasa de fuga del cierre aguas abajo"], re:"El valor estable sostenido es el diferencial estático a través de la primera retención; debe ser de 5.0 psid o más (y 3 psid por encima de la apertura del alivio) para aprobar en un RP. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:272, q:"Si, durante una prueba de retención de DC, el manómetro lee un diferencial negativo o cero que no se puede elevar, ¿qué se indica?", opts:["La retención se mantiene hermética","La válvula de alivio abrió","El manómetro está fuera de rango","La retención no se mantiene (deja pasar agua) o la conexión es incorrecta"], re:"Un diferencial que permanece en cero o por debajo señala que la retención no sella (deja pasar) o que las mangueras están conectadas incorrectamente. Fuente: resolución de problemas de AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:273, q:"Durante la prueba de apertura de la válvula de alivio en un RP, una aguja que CAE de manera constante y que se observa para el punto de apertura, ¿qué representa?", opts:["El diferencial de la zona disminuyendo hacia el punto de apertura de la válvula de alivio","La presión de suministro aumentando","La tasa de fuga de la retención N.º 2","La apertura de la entrada de aire"], re:"A medida que el probador purga el lado alto, el manómetro muestra el diferencial de la zona cayendo; la lectura se captura cuando la válvula de alivio abre (aproximadamente 2 psid). Fuente: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:274, q:"El agua que gotea continuamente del puerto de alivio de un RP mientras se intenta leer un diferencial de retención, ¿qué le indica más directamente al probador?", opts:["El manómetro está calibrado","La zona de presión reducida está venteando; la primera retención o el asiento de alivio pueden estar dejando pasar agua","La segunda retención es perfecta","El suministro está cerrado"], re:"La descarga de alivio durante una lectura de retención muestra que la zona está venteando (comúnmente una primera retención obstruida o un asiento de alivio con fugas), lo que se debe diagnosticar antes de un resultado válido. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:275, q:"En una prueba de la entrada de aire de un PVB, si la aguja cae a un valor y la entrada de aire se abre visiblemente en ese punto, ¿como qué se registra ese valor?", opts:["La presión de la línea de suministro","La hermeticidad de la válvula de retención","El punto de apertura de la entrada de aire","El ajuste de la válvula de alivio"], re:"El valor del manómetro en el instante en que la entrada de aire se abre se registra como el punto de apertura de la entrada de aire y debe ser de 1.0 psi o más. Fuente: AWWA M14; procedimiento de prueba de PVB de PNW-AWWA."},
  {id:276, q:"¿Por qué debe el probador leer el diferencial al PRIMER signo de descarga de la válvula de alivio en lugar de más tarde?", opts:["Porque la presión de suministro aumenta después","Porque el manómetro solo funciona brevemente","Porque el cliente está esperando","Porque el punto de apertura se define por el momento en que la válvula alivia por primera vez"], re:"El punto de apertura es, por definición, el diferencial al que la válvula abre por primera vez; leer más tarde subestima el verdadero punto de apertura. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:277, q:"Un manómetro que lee de 2 a 3 psid de diferencial incluso cuando ambas mangueras están en el mismo punto indica qué?", opts:["Aire atrapado, un manómetro obstruido o un manómetro descalibrado","Un manómetro correctamente puesto en cero","Una válvula de alivio de RP que aprueba","Comportamiento normal que se debe ignorar"], re:"Un desfase estático falso apunta a aire atrapado o a un manómetro que necesita purga o recalibración antes de poder confiarse. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:278, q:"Durante una prueba de RP, un salto repentino de la aguja hacia cero cuando se abre el alivio se interpreta como qué?", opts:["Un manómetro defectuoso","La válvula de alivio venteando la zona (un evento normal que marca la apertura)","La presión de suministro duplicándose","La retención N.º 1 sellando"], re:"Cuando el alivio se abre, vierte la zona y el diferencial colapsa hacia cero; este es el comportamiento esperado que se usa para marcar el punto de apertura. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:279, q:"Si una retención de DC sostiene muy por encima de 1.0 psid pero la aguja rebota de forma errática, ¿qué es lo PRIMERO que se debe sospechar?", opts:["Un cierre aguas abajo demasiado apretado","Una válvula de alivio que deja pasar agua","Aire residual en las mangueras que necesita más purga","Una entrada de aire descalibrada"], re:"El movimiento errático de la aguja generalmente significa que queda aire en las líneas; purgue de nuevo y vuelva a leer antes de juzgar la retención. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:280, q:"¿Qué le indica un diferencial estable y sostenido de 1.0 psid o más en una retención de DC?", opts:["La retención tiene fugas","El suministro está cerrado","La válvula de alivio abrió","La retención se mantiene hermética y aprueba esa parte de la prueba"], re:"Un diferencial estable de 1.0 psid o más significa que la retención sella herméticamente y esa retención aprueba. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:281, q:"En la prueba de la válvula de alivio, ¿por qué es importante establecer una condición estática (sin flujo) antes de leer?", opts:["Para que el diferencial refleje el conjunto en sí, no la caída de presión inducida por el flujo","Para que el manómetro lea 15 psid","Para que el agua del cliente se encienda","Para que la entrada de aire se abra"], re:"Una condición estática garantiza que el diferencial medido provenga de los resortes/asientos del conjunto y no del flujo, lo que da una lectura válida del punto de apertura. Fuente: USC FCCCHR Field Test Procedures; AWWA M14."},
  {id:282, q:"Durante una prueba de la retención de un SVB, el agua que NO deja de drenar de la válvula de vent mientras se purga indica qué?", opts:["La retención se mantiene perfectamente","La retención tiene fugas/deja pasar agua y puede no cumplir el criterio de 1.0 psid","El manómetro está fuera de rango","La entrada de aire está atascada cerrada"], re:"Si el drenaje no se detiene, la retención deja pasar agua y probablemente no apruebe; una retención hermética hace que el vent deje de drenar a 1.0 psi o más. Fuente: AWWA M14; procedimiento de prueba de SVB de Mid-West."},
  {id:283, q:"Una lectura tomada con el manómetro mantenido muy POR ENCIMA del conjunto, en comparación con una lectura a la misma elevación, ¿cómo se verá afectada?", opts:["En nada","Duplicando el valor verdadero","Por un error de elevación (columna) que desplaza el diferencial","Volviéndose siempre negativa"], re:"Mantener el manómetro fuera de la elevación del conjunto agrega un error de columna de agua al diferencial, por lo que el kit se debe mantener nivelado con el conjunto. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:284, q:"Si la presión de la línea de suministro leída en la llave de prueba N.º 1 es inusualmente baja o fluctuante, ¿qué debe hacer el probador?", opts:["Registrar cualquier valor y aprobar el conjunto","Ignorar por completo la presión de suministro","Aumentar el rango del manómetro a 150 psid","Anotarlo y resolver la condición de suministro, ya que un suministro inestable puede corromper las lecturas diferenciales"], re:"Una presión de suministro inestable o anormal puede distorsionar la prueba, por lo que la condición se anota y se aborda antes de confiar en los resultados diferenciales. Fuente: AWWA M14; orientación del informe de prueba estatal."},
  {id:285, q:"En un RP, si la retención N.º 1 sostiene 6 psid pero la válvula de alivio abre a 4 psid, ¿qué significa la brecha de 2 psid?", opts:["Un margen insuficiente, porque el margen debe ser de al menos 3 psid","Un margen saludable muy por encima del mínimo","Que el conjunto es un SVB","Que el manómetro está roto"], re:"Aunque ambos valores superan sus propios mínimos, un margen de 2 psid está por debajo de la diferencia requerida de 3 psid entre la primera retención y la apertura del alivio, por lo que este punto no aprueba. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:286, q:"¿Qué conjunto de valores mínimos de aprobación es correcto para un conjunto RP?", opts:["La válvula de alivio abre a >= 1.0 psid; cada retención sostiene >= 1.0 psid","La válvula de alivio abre a >= 2.0 psid; la retención N.º 1 sostiene >= 5.0 psid y >= 3 psid por encima de la apertura del alivio","La válvula de alivio abre a >= 5.0 psid; la retención N.º 1 sostiene >= 2.0 psid","La entrada de aire abre a >= 1.0 psi; la retención sostiene >= 1.0 psid"], re:"Un RP aprueba cuando el alivio abre a 2.0 psid o más y la primera retención sostiene 5.0 psid o más con al menos un margen de 3 psid sobre la apertura del alivio. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:287, q:"¿Qué conjunto de valores mínimos de aprobación es correcto para un conjunto DC?", opts:["La entrada de aire abre a >= 1.0 psi","La válvula de alivio abre a >= 2.0 psid","Cada válvula de retención sostiene >= 1.0 psid en la dirección del flujo","La retención N.º 1 sostiene >= 5.0 psid"], re:"Un DC aprueba cuando cada retención sostiene de forma independiente 1.0 psid o más en la dirección del flujo. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:288, q:"¿Qué conjunto de valores mínimos de aprobación es correcto para un conjunto PVB?", opts:["La entrada de aire abre a >= 2.0 psi; sin prueba de retención","La válvula de alivio abre a >= 2.0 psid; la retención sostiene >= 5.0 psid","Cada una de las dos retenciones sostiene >= 1.0 psid","La entrada de aire abre a >= 1.0 psi; la válvula de retención sostiene >= 1.0 psid"], re:"Un PVB aprueba cuando la entrada de aire abre a 1.0 psi o más y la válvula de retención sostiene 1.0 psid o más. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:289, q:"¿Qué conjunto de valores mínimos de aprobación es correcto para un conjunto SVB?", opts:["La retención sostiene >= 1.0 psid; la entrada de aire abre a >= 1.0 psi y abre por completo","La válvula de alivio abre a >= 2.0 psid","Dos retenciones sostienen cada una >= 1.0 psid","La entrada de aire abre a >= 5.0 psi"], re:"Un SVB aprueba cuando la retención sostiene 1.0 psid o más y la entrada de aire abre a 1.0 psi o más y abre por completo. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:290, q:"¿Qué información es OBLIGATORIA en un informe de prueba de conjunto de prevención de reflujo?", opts:["El color favorito del cliente","El número de serie, la marca, el modelo y el tamaño del conjunto","La factura del teléfono de la casa del probador","La marca del calentador de agua del cliente"], re:"El informe debe identificar el conjunto por marca, modelo, tamaño y número de serie (que debe coincidir con el sello del dispositivo). Fuente: AWWA M14; formularios de informe estatales (p. ej., NY DOH, Denver Water)."},
  {id:291, q:"¿Por qué debe coincidir el número de serie registrado en el informe con el estampado en el conjunto?", opts:["Solo por decoración","Para establecer la presión de suministro","Para demostrar que el conjunto correcto e instalado fue el que realmente se probó","Para calibrar el manómetro"], re:"Los números de serie coincidentes documentan que se probó el conjunto instalado específico, evitando fraudes o confusiones. Fuente: AWWA M14; instrucciones de informe de los programas estatales de conexiones cruzadas."},
  {id:292, q:"Además de la fecha de la prueba, ¿qué fecha se requiere normalmente en el informe con respecto al manómetro del probador?", opts:["No se requiere ninguna fecha del manómetro","La fecha del precio de compra del manómetro","La fecha en que se limpió el manómetro","La fecha de calibración del manómetro"], re:"La fecha de calibración del manómetro se registra para que la autoridad pueda confirmar que el manómetro estaba dentro de su calibración anual cuando se utilizó. Fuente: AWWA M14; formularios de informe estatales (p. ej., Denver Water)."},
  {id:293, q:"¿Qué identifica a la persona que realizó la prueba en el informe?", opts:["El nombre del probador certificado y el número de certificación/licencia","Solo un nombre de pila","Solo la firma del cliente","El logotipo del fabricante"], re:"El nombre del probador certificado y el número de certificación (licencia) deben aparecer para que la autoridad pueda verificar que el probador está calificado. Fuente: AWWA M14; formularios de informe estatales."},
  {id:294, q:"Si un conjunto NO APRUEBA y luego se repara, ¿qué debe documentar también el informe?", opts:["No se necesita nada más","Las reparaciones realizadas, las piezas utilizadas y una repetición de prueba aprobada después de la reparación","Solo la hora del día","La contraseña de la cuenta del cliente"], re:"Después de la reparación, el informe documenta qué se reparó/reemplazó y los resultados de la repetición de prueba aprobada. Fuente: AWWA M14; formularios de informe estatales (sección de reparación)."},
  {id:295, q:"La retención N.º 1 de un DC lee exactamente 1.0 psid. ¿Cómo se registra?", opts:["Como un fallo, porque debe superar 1.0 psid","Como sin necesidad de entrada","Como una aprobación, porque cumple el mínimo de 1.0 psid (>= 1.0 psid)","Como una lectura de la válvula de alivio"], re:"El criterio es 1.0 psid o más, por lo que exactamente 1.0 psid cumple el mínimo y la retención aprueba. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:296, q:"Al registrar un resultado de RP, ¿qué lecturas se ingresan en el informe?", opts:["Solo la presión de suministro","Solo el valor de la entrada de aire","Solo el valor de la válvula de alivio","El diferencial de la retención N.º 1, el resultado de la retención N.º 2 y el valor de apertura de la válvula de alivio"], re:"Un informe de RP registra el diferencial de la primera retención, el resultado de la segunda retención y el diferencial de apertura de la válvula de alivio, además de aprobado/no aprobado. Fuente: AWWA M14; formularios de prueba de campo de muestra (USC FCCCHR)."},
  {id:297, q:"Para un PVB, ¿qué dos resultados se registran en el informe?", opts:["El valor de apertura de la entrada de aire y el diferencial de la válvula de retención","Dos diferenciales de válvula de retención","Una apertura de válvula de alivio y una retención","Solo la presión de suministro"], re:"Un informe de PVB registra el punto de apertura de la entrada de aire y el diferencial de la válvula de retención, con aprobado/no aprobado. Fuente: AWWA M14; procedimiento de prueba de PVB de PNW-AWWA / campos del informe."},
  {id:298, q:"¿Cuál es la disposición correcta si cualquier lectura requerida en un conjunto cae por debajo de su mínimo?", opts:["Registrar el conjunto como aprobado de todos modos","Registrar el conjunto como NO APROBADO hasta que se repare y se vuelva a probar con resultado aprobado","Promediar todas las lecturas para decidir","Dejar el informe en blanco"], re:"Cualquier lectura por debajo de su mínimo requerido significa que el conjunto no aprueba y se debe reparar y volver a probar antes de poder registrarse como aprobado. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:299, q:"¿Qué condición de las válvulas de cierre se anota típicamente en el informe?", opts:["Solo su color","Su peso","Si los cierres N.º 1 y N.º 2 son operables/se mantienen (p. ej., herméticos o con fugas)","El par utilizado para abrirlos"], re:"Los informes anotan la condición de las válvulas de cierre (p. ej., manteniéndose herméticas o con fugas), ya que un cierre que se mantiene afecta la validez de la prueba y el aislamiento. Fuente: AWWA M14; formularios de informe estatales."},
  {id:300, q:"Después de completar la prueba, ¿qué debe hacer el probador antes de salir del sitio?", opts:["Dejar el cierre aguas abajo cerrado y las llaves de prueba abiertas","Drenar el calentador de agua del cliente","Quitar el conjunto de la línea","Restaurar el conjunto al servicio (cierres y llaves de prueba devueltos a sus posiciones de funcionamiento normales)"], re:"El probador devuelve el conjunto al servicio normal: llaves de prueba cerradas/tapadas y válvulas de cierre restauradas a sus posiciones de funcionamiento adecuadas. Fuente: AWWA M14; USC FCCCHR Field Test Procedures."},
  {id:301, q:"Una columna de agua de aproximadamente cuántos pies de altura produce 1 psi de presión en su base?", opts:["2.31 ft","1.0 ft","0.433 ft","14.7 ft"], re:"Una columna de agua de 1 psi tiene 2.31 ft de altura (1 / 0.433). Esta conversión de presión a carga es hidráulica fundamental usada en toda AWWA M14 y en los cálculos de bomba/elevación."},
  {id:302, q:"Cuánta presión ejerce en su base cada pie de columna de agua vertical?", opts:["1.0 psi","0.433 psi","2.31 psi","4.33 psi"], re:"El agua pesa 62.4 lb/ft3, por lo que una columna de 1 ft x 1 in2 pesa unas 0.433 lb, es decir 0.433 psi por pie de carga (el recíproco de 2.31 ft/psi)."},
  {id:303, q:"Un pie cúbico de agua pesa aproximadamente:", opts:["8.34 lb","100 lb","62.4 lb","2.31 lb"], re:"El agua dulce pesa unas 62.4 lb/ft3 (y 8.34 lb por galón). Este peso específico es la base de las conversiones de carga de 0.433 psi/ft y 2.31 ft/psi."},
  {id:304, q:"Elevar la salida de un conjunto 23 pies por encima de la entrada agrega aproximadamente cuánta presión estática que el suministro debe vencer?", opts:["Alrededor de 5 psi","Alrededor de 50 psi","Alrededor de 23 psi","Alrededor de 10 psi"], re:"Pérdida por elevación = altura x 0.433 psi/ft. 23 ft x 0.433 = unos 10 psi. Conversión hidráulica estándar de carga (hidráulica AWWA M14)."},
  {id:305, q:"La presión estática del agua es la presión medida cuando el agua está:", opts:["Sin fluir (en reposo)","Fluyendo a la demanda máxima","Siendo bombeada cuesta arriba","Descargando por la válvula de alivio"], re:"La presión estática es la presión en la línea sin caudal. Una vez que el agua se mueve, la fricción y la velocidad la reducen a una presión dinámica (residual) más baja. Hidráulica básica, AWWA M14."},
  {id:306, q:"Cuando el agua comienza a fluir por una tubería, la presión aguas abajo en comparación con la presión estática normalmente:", opts:["Permanece exactamente igual","Disminuye debido a la pérdida por fricción","Aumenta","Se vuelve atmosférica"], re:"El caudal crea fricción y carga de velocidad, por lo que la presión dinámica (residual) es más baja que la presión estática. Cuanto más rápido el caudal, mayor la caída. Hidráulica AWWA M14."},
  {id:307, q:"La pérdida por fricción en una tubería dada aumenta más bruscamente cuando:", opts:["El agua deja de fluir","La tubería se acorta","El caudal (velocidad) aumenta","Se elimina la presión"], re:"La pérdida por fricción aumenta aproximadamente con el cuadrado de la velocidad, por lo que un mayor caudal por una tubería fija causa una caída de presión mucho mayor. Por eso el sobredimensionamiento reduce la pérdida de carga. AWWA M14."},
  {id:308, q:"A medida que el agua se acelera por un paso estrechado, su velocidad aumenta y su presión estática:", opts:["Aumenta","Se duplica","Permanece constante","Disminuye"], re:"Por el principio de energía/Bernoulli, el agua que se mueve más rápido intercambia energía de presión por energía de velocidad, por lo que la presión estática disminuye donde la velocidad es mayor. Hidráulica AWWA M14."},
  {id:309, q:"La caída de presión a través del primer check de un conjunto RP durante caudal alto es principalmente el resultado de:", opts:["La carga del resorte más la fricción/velocidad a través del check","La expansión térmica","Error del manómetro","Ventilación atmosférica"], re:"El agua debe empujar el check cargado para abrirlo y pasar por él; la carga del resorte más la fricción del caudal crea el diferencial. Si esa caída supera el ajuste de alivio, el alivio puede gotear. AWWA M14 / USC FCCCHR."},
  {id:310, q:"Un conjunto que está subdimensionado para la demanda del edificio causará muy probablemente:", opts:["Exceso de presión estática","Pérdida de carga excesiva y baja presión aguas abajo en el caudal pico","Ningún caudal en ningún momento","Mayor precisión del manómetro"], re:"Un conjunto demasiado pequeño fuerza alta velocidad y gran pérdida por fricción en la demanda pico, privando a los accesorios y a veces levantando la válvula de alivio del RP. Dimensione según la demanda conforme a AWWA M14."},
  {id:311, q:"La presión diferencial a través de una válvula check se define como la:", opts:["Presión de suministro más la presión de zona","Solo la presión atmosférica","Diferencia entre la presión aguas arriba y la presión aguas abajo a través de ese check","Presión en la salida de la válvula de alivio"], re:"La presión diferencial es la presión aguas arriba menos la presión aguas abajo a través del check. El manómetro del equipo de prueba lo lee directamente cuando se conecta a los grifos de prueba. AWWA M14 / USC FCCCHR."},
  {id:312, q:"La presión normal del servicio de agua municipal entregada a la mayoría de los edificios suele estar en el rango de:", opts:["5 a 15 psi","Más de 300 psi","150 a 200 psi","40 a 80 psi"], re:"Los sistemas públicos de agua comúnmente entregan aproximadamente 40-80 psi; se agrega una PRV donde la presión de calle es más alta. Los conjuntos deben sellar en este rango de presión de trabajo. AWWA M14."},
  {id:313, q:"El reflujo por contrapresión ocurre cuando la presión aguas abajo se vuelve:", opts:["Mayor que la presión de suministro","Menor que la presión de suministro","Igual a la atmosférica","Exactamente cero"], re:"La contrapresión es la presión aguas abajo que supera la presión de suministro (por bombas, calderas, elevación, expansión térmica), lo que puede empujar el agua de vuelta hacia la red principal. AWWA M14."},
  {id:314, q:"La presión atmosférica estándar al nivel del mar es de aproximadamente:", opts:["7.0 psi","14.7 psi","29.9 psi","50.0 psi"], re:"La presión atmosférica estándar al nivel del mar es de unos 14.7 psia (1 atmósfera). El sifonamiento inverso y los efectos de vacío se refieren respecto a la presión atmosférica. — fundamentos de hidráulica / AWWA M14."},
  {id:315, q:"La zona de presión reducida entre los dos checks de un conjunto RP normalmente se mantiene cómo, en relación con el suministro?", opts:["A una presión mayor que el suministro","Exactamente igual al suministro","Al menos unos 2 psi por debajo del suministro","A presión atmosférica plena en todo momento"], re:"El primer check mantiene la zona central al menos unos 2 psi por debajo del suministro; si se pierde ese margen, la válvula de alivio se abre para mantener la zona por debajo del suministro. USC FCCCHR / AWWA M14."},
  {id:316, q:"Un manómetro que indica 'psig' está midiendo la presión en relación con:", opts:["El vacío absoluto","El ajuste de la válvula de alivio","La presión de suministro","La presión atmosférica"], re:"La presión manométrica (psig) se refiere a la presión atmosférica local; una lectura de 0 psig significa atmosférica. Las lecturas diferenciales de reflujo son manométricas. Hidráulica general."},
  {id:317, q:"La velocidad en una tubería para un caudal dado aumenta cuando el diámetro de la tubería se:", opts:["Hace más pequeño","Hace más grande","Deja sin cambios","Aísla"], re:"Para un caudal fijo, una sección transversal más pequeña fuerza una velocidad más alta (continuidad). Una mayor velocidad eleva la pérdida por fricción y puede aumentar el diferencial del check. Hidráulica AWWA M14."},
  {id:318, q:"En un conjunto RP, la descarga continua de la válvula de alivio mientras el sistema está en reposo (sin caudal) indica con mayor frecuencia:", opts:["Un primer check que sella perfectamente","Un primer check sucio que no cierra herméticamente","Funcionamiento normal","Un conjunto sobredimensionado"], re:"En reposo sin caudal, la descarga continua significa que el primer check tiene fuga y no puede mantener la zona por debajo del suministro, por lo que el alivio se abre. El primer check necesita servicio. Diagnóstico USC FCCCHR / AWWA M14."},
  {id:319, q:"La causa más común de una válvula check sucia que no se asienta es:", opts:["Tensión correcta del resorte","Un manómetro calibrado","Residuos, sedimentos o incrustaciones alojados en el asiento o el disco","Altura de instalación adecuada"], re:"La arenilla, las incrustaciones de tubería y los residuos atrapados entre el disco y el asiento son la causa principal de un check que no cierra herméticamente; la solución es limpiar o reemplazar las piezas afectadas. AWWA M14 / orientación del fabricante."},
  {id:320, q:"La descarga continua de alivio que aparece solo cuando el lado aguas abajo está bajo contrapresión apunta a un check sucio:", opts:["Primer check","Llave de cierre de entrada","Válvula de aguja del manómetro","Segundo check"], re:"Si el segundo check se ensucia y la contrapresión empuja el agua de vuelta a la zona, la presión de zona sube, el alivio se abre y la descarga continúa bajo esa contrapresión. Diagnóstico AWWA M14."},
  {id:321, q:"La descarga intermitente de alivio que comienza y se detiene a medida que la presión de suministro sube y baja suele ser el conjunto:", opts:["Respondiendo correctamente a la presión de suministro fluctuante","Fallando y necesitando reemplazo","Sufriendo un cuerpo agrietado","Leyendo un manómetro defectuoso"], re:"Cuando la presión de entrada cae momentáneamente, el alivio ventila para mantener la zona por debajo del suministro, luego se reasienta cuando la presión se recupera. Esta descarga molesta sigue la fluctuación del suministro. AWWA M14 / USC FCCCHR."},
  {id:322, q:"En un sistema cerrado aguas abajo, una válvula de alivio RP que gotea después de un uso prolongado de agua caliente o durante la noche es comúnmente causada por:", opts:["Un grifo de prueba flojo","Expansión térmica que eleva la presión aguas abajo","Un primer check sobredimensionado","Cambios de presión atmosférica"], re:"El agua calentada en un circuito cerrado se expande y eleva la presión aguas abajo, empujando de vuelta por el segundo check y levantando el alivio. Un tanque de expansión correctamente cargado suele resolverlo. AWWA M14."},
  {id:323, q:"Una onda de choque por golpe de ariete que llega a un conjunto RP puede hacer que la válvula de alivio:", opts:["Selle más herméticamente para siempre","Invierta la dirección del flujo permanentemente","Se abra momentáneamente y descargue agua","Se recalibre a sí misma"], re:"Un aumento repentino de presión puede alterar momentáneamente el diferencial de zona y levantar el alivio; se usan amortiguadores o un check de amortiguación para atenuarlo. AWWA M14 / diagnóstico en campo."},
  {id:324, q:"Los discos de check de goma desgastados o endurecidos típicamente fallan porque:", opts:["Se vuelven más flexibles con el tiempo","Reducen la pérdida por fricción","Crecen más grandes y sellan mejor","Pierden su resiliencia y ya no sellan contra el asiento"], re:"La goma toma una deformación permanente, se endurece, se agrieta o se rasga con la edad y la exposición al cloro, por lo que el disco no puede ajustarse al asiento y el check gotea. Reemplace la goma. AWWA M14 / fabricante."},
  {id:325, q:"Una válvula de alivio que no se abre en absoluto (sin descarga incluso cuando debería) es peligrosa porque puede:", opts:["Enmascarar una condición de reflujo y permitir la contaminación de la zona","Ahorrar agua","Mejorar la precisión del manómetro","Aumentar la presión de suministro"], re:"Un alivio atascado cerrado anula la última línea de defensa del RP; la zona podría contaminarse sin advertencia. Ambos checks y el alivio deben comprobarse en cada prueba. USC FCCCHR / AWWA M14."},
  {id:326, q:"La acumulación de incrustaciones minerales en el asiento de un check con el tiempo muy probablemente:", opts:["No tiene efecto","Impide que el disco se asiente completamente y causa fuga","Aumenta la presión de apertura del alivio","Aprieta el sello"], re:"Las incrustaciones de agua dura en el asiento mantienen el disco separado de su asiento, creando una vía de fuga; el desincrustado o el reemplazo del asiento/disco restaura el sello. Mantenimiento AWWA M14 / fabricante."},
  {id:327, q:"El clima helado daña con mayor frecuencia un conjunto sobre el suelo al:", opts:["Mejorar los sellos","Calibrar el manómetro","Agrietar el cuerpo, la tapa o la válvula de alivio por la expansión del hielo","Bajar el ajuste de alivio"], re:"El agua se expande al congelarse y puede partir el cuerpo fundido, la tapa o la carcasa de alivio. Se requiere protección contra heladas o drenaje para el invierno. Orientación de instalación AWWA M14."},
  {id:328, q:"Un resorte de válvula check roto o fatigado normalmente se manifiesta en una prueba como:", opts:["Un diferencial de check más alto de lo normal","Ningún efecto en la lectura","Una válvula de alivio que se abre más tarde","Un check que no mantiene el diferencial mínimo"], re:"Un resorte débil o roto no puede cargar el disco sobre el asiento, por lo que el check no mantiene su presión de retención mínima en la prueba. Reemplace el resorte/módulo. AWWA M14 / fabricante."},
  {id:329, q:"Un conjunto instalado con la flecha de flujo apuntando en la dirección equivocada:", opts:["No protegerá porque los checks miran en la dirección equivocada","Funcionará normalmente","Leerá un diferencial más alto","Abrirá el alivio con menor frecuencia"], re:"Instalado al revés, los checks se oponen al flujo previsto y el conjunto no puede funcionar; la orientación debe coincidir con la flecha de flujo del cuerpo. Instalación AWWA M14."},
  {id:330, q:"Es más probable que los residuos ensucien un conjunto justo después de:", opts:["Un largo período sin uso","Trabajos cercanos en la red principal, reparaciones o purgas que remueven sedimentos","Calibrar el manómetro","Pintar el edificio"], re:"Las roturas de la red principal, las reparaciones, la purga de hidrantes y la nueva construcción desprenden incrustaciones y arenilla que viajan aguas abajo y se alojan en los checks y el alivio. Espere suciedad tras la perturbación. AWWA M14."},
  {id:331, q:"Un agujero o desgarro en el diafragma de goma de una válvula de alivio diferencial típicamente hará que el alivio:", opts:["Permanezca sellado permanentemente","Se abra a una presión más alta","Gotee o descargue continuamente porque no puede mantener su diferencial","No tenga ningún síntoma"], re:"El diafragma de alivio detecta el diferencial suministro-a-zona; un diafragma desgarrado no puede mantenerlo, por lo que el alivio gotea. Reemplace el módulo/diafragma de alivio. AWWA M14 / fabricante."},
  {id:332, q:"Si una válvula de alivio RP descarga solo durante los pocos minutos de demanda pico matutina, la explicación más probable es:", opts:["Un cuerpo de conjunto agrietado","Una llave de cierre de entrada demasiado apretada","Una válvula de alivio congelada","Caudal alto que baja el diferencial del primer check por debajo del ajuste de alivio (a menudo subdimensionamiento)"], re:"En el caudal pico, la caída de presión a través del primer check puede caer por debajo del diferencial de alivio y el alivio ventila; el dimensionamiento correcto o un conjunto más grande lo resuelve. USC FCCCHR / AWWA M14."},
  {id:333, q:"Ambos checks sucios y con fuga en un RP de alto riesgo es lo más grave porque:", opts:["Elimina la barrera contra la contaminación, aunque el alivio aún ventila la zona","Solo desperdicia un poco de agua","Mejora la protección","No tiene consecuencias"], re:"Con ambos checks con fuga el conjunto no puede bloquear el flujo inverso; el alivio que ventila la zona a la atmósfera es la salvaguarda restante, pero el conjunto debe repararse de inmediato. AWWA M14."},
  {id:334, q:"Una línea de detección o paso de la válvula de alivio obstruido con residuos muy probablemente hará que el alivio:", opts:["Responda más rápido","Responda lentamente o no se abra/cierre en el diferencial adecuado","Mejore la precisión","Baje la presión de suministro"], re:"El alivio reacciona a la presión alimentada por su paso de detección; si ese paso está sucio, el alivio no puede detectar el diferencial real y se comporta mal. Limpie el paso. Diagnóstico AWWA M14."},
  {id:335, q:"En una prueba de campo de RP, el primer check se juzga satisfactorio cuando mantiene un diferencial de al menos:", opts:["1.0 psid","2.0 psid","5.0 psid","10.0 psid"], re:"El primer check de un RP debe mantener al menos 5.0 psid (y el alivio no debe estar abierto) para conservar un margen seguro por encima del punto de apertura del alivio. Criterios de prueba USC FCCCHR / AWWA M14."},
  {id:336, q:"Cada válvula check de un conjunto de doble check (DCVA) debe mantener un diferencial de al menos:", opts:["0.0 psid","2.0 psid","5.0 psid","1.0 psid"], re:"En un DCVA, cada check debe mantener al menos 1.0 psid en la dirección del flujo; si mantiene 1.0 psid hacia adelante se asume hermético contra el flujo inverso. AWWA M14 / USC FCCCHR."},
  {id:337, q:"Un primer check que mantiene solo 3.5 psid en una prueba de RP debe registrarse como:", opts:["Fallido, porque está por debajo del mínimo de 5.0 psid","Aprobado","Aprobado si el alivio está cerrado","No comprobable"], re:"Por debajo del mínimo de 5.0 psid el primer check falla aunque no tenga fuga visible; ya no conserva el margen requerido por encima de la apertura del alivio. Repare y vuelva a probar. USC FCCCHR / AWWA M14."},
  {id:338, q:"Durante una prueba de válvula check, el agua sigue saliendo de la línea de purga/visor y el manómetro no se estabiliza. Esto indica que el check está:", opts:["Reteniendo herméticamente","Con fuga (no cierra herméticamente)","Demasiado apretado","Congelado abierto por diseño"], re:"Un check se registra como hermético solo cuando el caudal se detiene y el diferencial se estabiliza. El caudal continuo significa que el disco no sella - un check con fuga. Método de prueba AWWA M14."},
  {id:339, q:"La suposición detrás de probar un check solo en la dirección del flujo es que si mantiene el diferencial mínimo hacia adelante:", opts:["Tendrá fuga en reversa","Necesitará reemplazo de todos modos","Mantendrá hermético en la dirección inversa (sin flujo)","Abrirá la válvula de alivio"], re:"La lógica de prueba de AWWA M14 asume que un check que mantiene su diferencial mínimo en la dirección del flujo también sellará contra el flujo inverso, la condición que importa para la protección contra reflujo. AWWA M14."},
  {id:340, q:"El aire atrapado en las mangueras del equipo de prueba durante una prueba de check muy probablemente hará que la lectura del diferencial sea:", opts:["Falsamente baja","Negativa","Exactamente correcta","Falsamente alta"], re:"El aire en las mangueras hace que el manómetro lea un diferencial más alto del que realmente existe, lo que puede ocultar un check con fuga (falso aprobado). Purgue todo el aire antes de leer. Orientación de equipo de prueba BAVCO / AWWA M14."},
  {id:341, q:"Para aislar cuál check tiene fuga en un DCVA, el inspector lee cada check por separado usando:", opts:["Los grifos de prueba apropiados y el manómetro diferencial para cada check","Solo la llave de cierre de entrada","La descarga de la válvula de alivio","Un manómetro de presión solo en el lado del edificio"], re:"Los cuatro grifos de prueba permiten al inspector leer el check 1 y el check 2 independientemente con el manómetro diferencial, identificando cuál check falla su mínimo de 1.0 psid. AWWA M14 / USC FCCCHR."},
  {id:342, q:"Una válvula check que prueba bien un día pero falla intermitentemente después muy probablemente tiene:", opts:["Un disco desgarrado permanentemente","Residuos intermitentes que se alojan y se despejan en el asiento","Un cuerpo congelado","Solo un manómetro mal calibrado"], re:"La arenilla suelta que a veces cae en el asiento y a veces se enjuaga produce una fuga intermitente; el disco y el asiento deben inspeccionarse y limpiarse. Diagnóstico AWWA M14."},
  {id:343, q:"En un RP, si el primer check falla pero el segundo check es hermético, el conjunto:", opts:["Aún aprueba completamente","No necesita acción","Falla y debe repararse y volver a probarse","Debe tener su alivio retirado"], re:"Cualquier componente fallido hace fallar el conjunto. Un primer check fallido (incluso con un buen segundo check) debe repararse y el conjunto volver a probarse antes de regresar al servicio. USC FCCCHR / AWWA M14."},
  {id:344, q:"Un disco de check oscilante o de bisagra que ya no oscila libremente (atascándose en su pasador) muy probablemente:", opts:["Sellará perfectamente","No tendrá efecto en la prueba","Aumentará la presión de suministro","Se atascará parcialmente abierto o cerrado y no se asentará correctamente"], re:"Un disco que se atasca en una bisagra/pasador corroído o sucio no puede asentarse o abrirse completamente, causando fuga o restricción. Libere, limpie o reemplace las piezas móviles. AWWA M14 / fabricante."},
  {id:345, q:"Al registrar una prueba de check, el valor que se anota es el diferencial en el momento en que:", opts:["El caudal se detiene y el manómetro se estabiliza (check cerrado herméticamente)","El caudal comienza por primera vez","El alivio se abre","La llave de cierre se cierra"], re:"El número registrado es el diferencial estabilizado después de que el caudal por la línea de visor se detiene, lo que significa que el check ha cerrado herméticamente. Método de informe AWWA M14."},
  {id:346, q:"Un disco de check que está correcto pero asentado sobre un asiento picado o corroído:", opts:["Mantendrá hermético de todos modos","Tendrá fuga a través de la superficie del asiento dañada","Elevará el ajuste de alivio","Detendrá todo el caudal"], re:"Ni siquiera un buen disco puede sellar contra un asiento picado, rayado o corroído; el asiento debe limpiarse, repararse o reemplazarse. Orientación de reparación AWWA M14 / fabricante."},
  {id:347, q:"Si ambos checks de un DCVA leen por encima de 1.0 psid y se mantienen estables, el inspector registra el conjunto como:", opts:["Fallido","Necesitando reemplazo del alivio","Aprobado","No comprobable"], re:"Ambos checks manteniendo el mínimo de 1.0 psid o más con lecturas estables es un resultado aprobatorio de DCVA. Criterios AWWA M14 / USC FCCCHR."},
  {id:348, q:"Un primer check con fuga en un RP a veces puede confirmarse porque la válvula de alivio:", opts:["Permanecerá seca","Cerrará la entrada","Leerá una presión más alta","Descargará en reposo sin caudal hasta que el check reciba servicio"], re:"Un primer check que tiene fuga en reposo deja que la zona suba hacia el suministro, por lo que el alivio descarga continuamente en condición estática - un indicio de suciedad del primer check. USC FCCCHR / AWWA M14."},
  {id:349, q:"Antes de condenar un check con fuga, el inspector debe verificar primero que la fuga no sea causada por:", opts:["Aire en las mangueras o un grifo de prueba/válvula de aguja no completamente asentado","Calibración correcta del manómetro","El edificio estando ocupado","Dirección de flujo adecuada"], re:"El aire atrapado o una conexión de prueba con fuga puede imitar un check con fuga (falso fallo o lectura extraña); confirme que el equipo esté purgado y apretado antes de juzgar el conjunto. BAVCO / AWWA M14."},
  {id:350, q:"Las válvulas check en un conjunto RP o DC son cargadas por resorte para que:", opts:["Se abran solo con flujo inverso","Cierren positivamente contra el flujo inverso incluso con bajo diferencial","Permanezcan abiertas en todo momento","Estrangulen el caudal continuamente"], re:"La carga del resorte impulsa el disco sobre el asiento para que el check cierre contra el flujo inverso incluso antes de que se acumule la contrapresión, a diferencia de un check oscilante sin carga. AWWA M14 / USC FCCCHR."},
  {id:351, q:"Un check que mantiene un diferencial mucho más alto de lo normal (muy rígido) puede indicar:", opts:["Nada malo, siempre ideal","Un diafragma desgarrado","Un paso obstruido o un disco atascado/sobrecargado que agrega restricción","Una batería de manómetro agotada"], re:"Un diferencial anormalmente alto puede significar restricción por residuos o un disco atascado que agrega pérdida de carga; inspeccione si hay suciedad o atasco mecánico aunque 'mantenga'. Diagnóstico AWWA M14."},
  {id:352, q:"En una prueba de campo de RP, la válvula de alivio debe comenzar a abrirse (punto de apertura del alivio) en un diferencial de al menos:", opts:["0.5 psid","1.0 psid","5.0 psid","2.0 psid"], re:"La válvula de alivio diferencial del RP debe abrirse a no menos de 2.0 psid entre el suministro y la zona. Por debajo de 2.0 psid de apertura falla. Criterios de prueba USC FCCCHR / AWWA M14."},
  {id:353, q:"Una válvula de alivio registrada como abriéndose a 1.4 psid en una prueba de RP debe marcarse:", opts:["Fallida, porque está por debajo del mínimo de 2.0 psid","Aprobada","Aprobada si los checks están bien","No aplicable"], re:"Un punto de apertura por debajo de 2.0 psid falla; el alivio debe abrirse a 2.0 psid o más para ventilar la zona antes de que pueda subir a la presión de suministro. USC FCCCHR / AWWA M14."},
  {id:354, q:"La válvula de alivio siempre debe abrirse a un diferencial que es de qué manera en relación con el valor de retención del primer check?", opts:["Más alto que el valor del check","Más bajo que el valor del check, dejando un margen de seguridad","Exactamente igual a él","Negativo"], re:"El punto de apertura del alivio (>=2.0 psid) debe permanecer por debajo de la retención del primer check (>=5.0 psid) para que el check mantenga la zona con seguridad por encima del ajuste de alivio. Requisito de margen USC FCCCHR / AWWA M14."},
  {id:355, q:"Para demostrar que el alivio de un RP que descarga está funcionando, un inspector puede establecer caudal a través del grifo de prueba No. 4; si la descarga se detiene, muestra que el alivio:", opts:["Está roto","Se abrió demasiado tarde","Cerró y está funcionando - la fuga provenía de un check sucio","Tiene un diafragma desgarrado"], re:"Con ambos checks mantenidos abiertos por el caudal del No. 4, un alivio que luego se asienta demuestra que el alivio está bien y la descarga previa provenía de un check sucio. Si aún tiene fuga, sospeche del alivio o su paso de detección. AWWA M14 / Backflow Prevention Journal."},
  {id:356, q:"Si el alivio del RP aún descarga mientras el agua sale por el grifo de prueba No. 4 (ambos checks mantenidos abiertos), la falla es muy probablemente:", opts:["El primer check","El segundo check","La llave de cierre de entrada","Residuos en la válvula de alivio o su línea de detección"], re:"Con ambos checks forzados a abrir por el caudal del No. 4, los checks quedan fuera de la ecuación; la fuga continua del alivio apunta a residuos en el alivio o su paso de detección. AWWA M14 / Backflow Prevention Journal."},
  {id:357, q:"Una válvula de alivio que se abre correctamente pero luego no se reasienta (permanece abierta) muy probablemente está:", opts:["Sucia o tiene goma desgastada en su asiento","Perfectamente bien","Ajustada demasiado alto","Congelada cerrada"], re:"Un alivio que se abre pero no puede reasentarse usualmente tiene residuos o goma desgastada/desgarrada en el asiento de alivio; limpie o reemplace el módulo de alivio. Orientación de reparación AWWA M14 / fabricante."},
  {id:358, q:"La válvula de alivio diferencial de un RP detecta la diferencia entre la presión de suministro y la:", opts:["Presión atmosférica exterior","Presión en la zona entre los dos checks","Presión del edificio aguas abajo","Voltaje de la batería del manómetro"], re:"El alivio compara continuamente la presión de suministro con la presión de la zona central; cuando la zona sube a unos 2 psi del suministro, el alivio se abre. USC FCCCHR / AWWA M14."},
  {id:359, q:"En una prueba de PVB (interruptor de vacío de presión), la válvula de entrada de aire debe abrirse a un diferencial de al menos:", opts:["5.0 psid","2.0 psid","1.0 psid","0.0 psid"], re:"Una válvula de entrada de aire de PVB debe abrirse a 1.0 psid o más (y el check debe estar cargado a al menos 1.0 psid). Criterios de PVB USC FCCCHR / AWWA M14."},
  {id:360, q:"Una válvula de alivio que 'escupe' brevemente y luego se reasienta durante una caída de presión de suministro está:", opts:["Fallando y debe reemplazarse","Leyendo un manómetro defectuoso","Atascada abierta","Funcionando normalmente al ventilar y reasentarse"], re:"La ventilación breve y luego el reasentamiento a medida que el suministro fluctúa es un comportamiento protector normal, no una falla - mantiene la zona por debajo del suministro. La descarga persistente es el problema a perseguir. AWWA M14 / USC FCCCHR."},
  {id:361, q:"Para verificar el punto de apertura del alivio con un equipo de prueba, el inspector purga lentamente la presión de suministro y anota el diferencial en el que el alivio:", opts:["Comienza a descargar por primera vez (se abre)","Se cierra completamente","Alcanza la presión de suministro","Lee cero"], re:"El punto de apertura es el diferencial en el que el alivio recién comienza a descargar a medida que se purga el suministro; debe ser 2.0 psid o más. Procedimiento USC FCCCHR / AWWA M14."},
  {id:362, q:"Un módulo de válvula de alivio con un diafragma de goma endurecido y deformado muy comúnmente:", opts:["Se abrirá más tarde y sellará mejor","No mantendrá su diferencial y goteará o se abrirá en el punto equivocado","No tendrá ningún síntoma","Aumentará el diferencial del check"], re:"Un diafragma que ha perdido resiliencia no puede mantener con precisión el diferencial suministro-a-zona, por lo que el alivio gotea o se abre fuera de especificación. Reemplace el módulo de alivio. AWWA M14 / fabricante."},
  {id:363, q:"El puerto de descarga (espacio de aire) de la válvula de alivio debe mantenerse:", opts:["Bien tapado","Obstruido con residuos","Despejado y no sumergido ni conectado directamente a un desagüe","Por debajo de la línea de agua del desagüe del piso"], re:"El alivio debe descargar a través de un espacio de aire abierto; taparlo o sumergir la salida anula el espacio de aire y puede causar una conexión cruzada. Instalación AWWA M14 / USC FCCCHR."},
  {id:364, q:"Una válvula de alivio RP que se abre en el punto correcto y se reasienta limpiamente cuando se establece el caudal se registra como:", opts:["Fallida","No comprobable","Necesitando reemplazo","Aprobada"], re:"Un alivio que se abre a 2.0 psid o más y se reasienta correctamente cumple los criterios y se registra como aprobado, siempre que ambos checks también aprueben. USC FCCCHR / AWWA M14."},
  {id:365, q:"Una válvula de alivio que descarga de forma constante aunque ambos checks prueben herméticos por separado sugiere que el problema está:", opts:["Dentro de la propia válvula de alivio o su paso de detección","Definitivamente en el primer check","En el tamaño de la tubería aguas abajo","Solo en la calibración del manómetro"], re:"Si ambos checks aprueban pero el alivio sigue descargando, el módulo de alivio, su diafragma o su paso de detección tiene la falla y debe recibir servicio. Diagnóstico AWWA M14."},
  {id:366, q:"El propósito de que la válvula de alivio se abra cuando el diferencial cae hacia 2 psi es:", opts:["Aumentar la presión aguas abajo","Vaciar la zona a la atmósfera para que el agua contaminada no pueda llegar al suministro","Recalibrar los checks","Detener la lectura del manómetro"], re:"Al ventilar la zona central a la atmósfera, el alivio asegura que cualquier fuga que pase el segundo check se derrame en lugar de regresar al suministro potable. USC FCCCHR / AWWA M14."},
  {id:367, q:"Un error de campo común que hace que una buena válvula de alivio parezca estar fallando es:", opts:["Purgar las mangueras correctamente","Registrar el punto de apertura","No notar la expansión térmica o una fluctuación del suministro que causa una descarga legítima","Cerrar la llave de cierre de entrada de último"], re:"La descarga molesta legítima por expansión térmica o oscilaciones del suministro puede confundirse con un alivio defectuoso; confirme la causa antes de condenar el alivio. Diagnóstico AWWA M14 / USC FCCCHR."},
  {id:368, q:"En un PVB, la válvula check debe estar cargada internamente y hermética a las gotas en la dirección del flujo con al menos:", opts:["10.0 psid","2.0 psid","5.0 psid","1.0 psid"], re:"Un check de PVB debe estar cargado y hermético a las gotas a al menos 1.0 psid en la dirección del flujo; la entrada de aire debe abrirse a 1.0 psid o más. Criterios de PVB USC FCCCHR / AWWA M14."},
  {id:369, q:"El primer paso correcto antes de abrir un conjunto para reemplazar piezas internas es:", opts:["Cerrar las llaves de cierre y aliviar (despresurizar) el conjunto a través de un grifo de prueba","Abrir todos los grifos de prueba completamente","Quitar la tapa de la válvula de alivio bajo presión","Desconectar el manómetro"], re:"Siempre aísle con las llaves de cierre y purgue la presión a través de un grifo de prueba antes del desmontaje; abrir un conjunto presurizado es inseguro. Procedimiento de servicio AWWA M14 / fabricante."},
  {id:370, q:"Un 'kit de goma' del fabricante para un conjunto RP típicamente contiene:", opts:["Un manómetro y mangueras nuevos","Discos/sellos de check de repuesto, juntas tóricas y goma de la válvula de alivio","Solo una llave de cierre nueva","Pesas de calibración"], re:"Los kits de reparación de goma proveen las piezas de desgaste - discos/sellos de check, juntas tóricas y goma del diafragma/asiento de alivio - para que la goma desgastada o sucia pueda renovarse. Listados de kits de reparación del fabricante (Watts/Febco)."},
  {id:371, q:"Al reacondicionar una válvula check, un asiento rayado o picado contra el que el disco no puede sellar debe:", opts:["Dejarse como está","Pintarse encima","Limpiarse, repararse o reemplazarse según el fabricante","Apretarse más fuerte"], re:"Un asiento dañado tendrá fuga incluso con un disco nuevo; límpielo, repárelo (si está diseñado para ello) o reemplácelo siguiendo las instrucciones del fabricante. Orientación de reparación AWWA M14 / fabricante."},
  {id:372, q:"Un resorte de check débil o roto se corrige:", opts:["Estirando el resorte viejo","Invirtiendo el disco","Agregando arandelas debajo del asiento","Instalando el resorte o módulo de check de repuesto del fabricante"], re:"Los resortes que se han debilitado o roto se reemplazan con el resorte/módulo correcto del fabricante para que el check se cargue adecuadamente y mantenga su diferencial mínimo. Orientación de reparación del fabricante."},
  {id:373, q:"Al reemplazar piezas, usar componentes no originales (no OEM) o no coincidentes puede:", opts:["Anular la aprobación del conjunto y hacer que falle o pruebe incorrectamente","Siempre mejorar el rendimiento","No tener efecto","Elevar el ajuste de alivio de forma segura"], re:"Solo las piezas especificadas por el fabricante mantienen el conjunto dentro de su aprobación USC/ASSE; las piezas incorrectas pueden cambiar las cargas del resorte y el asentamiento e invalidar el listado. USC FCCCHR / fabricante."},
  {id:374, q:"Antes de reensamblar un check limpio, el técnico debe:", opts:["Dejar los residuos en su lugar","Enjuagar la arenilla e inspeccionar el disco, el asiento y el resorte en busca de daños","Omitir la inspección para ahorrar tiempo","Aplicar sellador de tuberías a la goma"], re:"Enjuagar los residuos restantes e inspeccionar cada pieza asegura que el check reacondicionado se asiente; los productos derivados del petróleo en la goma se evitan porque la degradan. AWWA M14 / fabricante."},
  {id:375, q:"La válvula de alivio de un RP recibe servicio al:", opts:["Soldarla cerrada","Quitarla permanentemente","Reemplazar el módulo de alivio / diafragma y la goma del asiento y limpiar el paso de detección","Tapar su salida"], re:"Los problemas de alivio se solucionan renovando la goma/diafragma del módulo de alivio y el asiento y despejando el paso de detección para que detecte el diferencial correctamente. Orientación de reparación del fabricante / AWWA M14."},
  {id:376, q:"Un lubricante usado en las juntas tóricas durante un reacondicionamiento de reflujo debe ser:", opts:["Grasa de petróleo","Sellador de roscas de tubería","Aceite de motor","Un lubricante aprobado no tóxico, seguro para agua (FDA/NSF) compatible con la goma"], re:"Solo se usan lubricantes seguros para agua potable y compatibles con la goma; los productos derivados del petróleo hinchan y destruyen los sellos y pueden contaminar el agua. Orientación del fabricante / NSF."},
  {id:377, q:"Si las piezas de reparación ya no están disponibles o el cuerpo está agrietado, la acción adecuada es:", opts:["Reemplazar todo el conjunto con una unidad aprobada","Improvisar piezas","Dejarlo fuera de servicio indefinidamente sin un plan","Tapar el alivio y reutilizarlo"], re:"Un cuerpo agrietado o una unidad obsoleta sin piezas debe reemplazarse con un conjunto aprobado actualmente; las piezas improvisadas en campo no están permitidas. AWWA M14 / USC FCCCHR."},
  {id:378, q:"Al reinstalar piezas internas, apretar los pernos de manera desigual o con torque excesivo puede:", opts:["Mejorar el sello","Deformar la tapa/asiento y causar fugas","Recalibrar el alivio","No tener efecto"], re:"El torque desigual o excesivo deforma tapas y asientos y pellizca las juntas tóricas, creando fugas; siga el patrón y los valores de torque del fabricante. Orientación de servicio del fabricante."},
  {id:379, q:"Después de limpiar una válvula de alivio sucia, el agua que aún gotea de ella usualmente significa:", opts:["El trabajo está terminado","Los checks están mal","La goma del asiento o el diafragma del alivio está desgastada y debe reemplazarse, no solo limpiarse","El manómetro está mal"], re:"Si la limpieza no detiene el goteo, la goma del alivio ha tomado una deformación permanente o está dañada y el módulo/diafragma debe reemplazarse. AWWA M14 / fabricante."},
  {id:380, q:"Las llaves de cierre (de compuerta o de bola con asiento resiliente) de un conjunto se prueban antes que los checks porque el inspector debe verificar que:", opts:["Estén pintadas","Lean el manómetro","Abran el alivio","Cierren herméticamente a las gotas para poder aislar el conjunto para una prueba precisa"], re:"Las llaves de cierre deben asentarse herméticamente; una llave de cierre No. 1 o No. 2 con fuga deja que el suministro o la contrapresión eviten la prueba y corrompe las lecturas. Procedimiento AWWA M14 / USC FCCCHR."},
  {id:381, q:"Durante el desmontaje, mantener las piezas organizadas y seguir la vista despiezada del fabricante ayuda a asegurar:", opts:["La orientación correcta y que no se omita ningún resorte, disco o junta tórica al reensamblar","Un trabajo más lento","Que el alivio se abra más bajo","Que el manómetro se recalibre"], re:"Seguir el diagrama de piezas del fabricante previene discos invertidos, resortes faltantes o juntas tóricas pellizcadas que harían fallar el conjunto reacondicionado. Orientación de servicio del fabricante."},
  {id:382, q:"Un primer check desgastado que no puede alcanzar 5.0 psid después de la limpieza debe:", opts:["Devolverse al servicio como está","Reacondicionarse con disco/sello y resorte nuevos (o módulo) hasta que cumpla el mínimo","Dejarse con fuga","Derivarse"], re:"Si la limpieza por sí sola no restaura el mínimo de 5.0 psid, renueve el disco/sello y el resorte (o reemplace el módulo de check) para que el check cumpla los criterios. AWWA M14 / fabricante."},
  {id:383, q:"Los aceites o grasas a base de petróleo se mantienen alejados de las piezas de goma de reflujo porque:", opts:["Ayudan a que la goma dure más","Mejoran el ajuste de alivio","Hinchan, ablandan y deterioran la goma, causando fugas","Limpian el asiento"], re:"Los productos derivados del petróleo son incompatibles con la goma usada en los checks y los diafragmas de alivio; causan hinchazón y falla. Use solo lubricantes aprobados seguros para agua. Orientación del fabricante / NSF."},
  {id:384, q:"Al regresar lentamente un conjunto reparado al servicio, la secuencia correcta es generalmente:", opts:["Abrir la llave de cierre aguas abajo (No. 2) primero, rápido","Dejar la entrada cerrada","Abrir ambas completamente a la vez","Abrir la llave de cierre aguas arriba (No. 1) lentamente primero para llenar, luego abrir la de aguas abajo (No. 2)"], re:"Abra la llave de cierre aguas arriba lentamente para llenar y presurizar el conjunto, luego abra la llave de cierre aguas abajo; esto evita la sobrepresión y el golpe de ariete que podrían levantar el alivio. Arranque AWWA M14 / fabricante."},
  {id:385, q:"Cualquier fuga observada más allá de un grifo de prueba o accesorio después de un reacondicionamiento debe corregirse porque puede:", opts:["Corromper las lecturas de prueba posteriores e indicar que el conjunto no está bien cerrado","Ignorarse","Mejorar la precisión","Bajar la presión de suministro de forma segura"], re:"Las fugas en los grifos de prueba o accesorios desperdician agua y sesgan las lecturas diferenciales futuras; vuelva a sellar o reemplace el accesorio para que el conjunto quede hermético. AWWA M14 / fabricante."},
  {id:386, q:"Un manómetro de prueba diferencial de reflujo debe mantener una precisión de al menos:", opts:["+/- 2.0 psid","+/- 0.2 psid","+/- 5.0 psid","+/- 10 psid"], re:"El manómetro de prueba de campo debe leer dentro de +/- 0.2 psid (según ASSE 1064 / orientación de la industria) para que los criterios de 2 psid y 5 psid puedan juzgarse de forma confiable. BAVCO / TCEQ / ASSE 1064."},
  {id:387, q:"Con qué frecuencia se requiere normalmente comprobar la precisión / calibrar un equipo de prueba de reflujo?", opts:["Cada 5 años","Solo cuando se rompe","Al menos una vez al año (anualmente)","Una vez en la vida del equipo"], re:"La mayoría de las jurisdicciones y la orientación de la industria requieren que la precisión del manómetro se compruebe al menos anualmente (y se recalibre si se desvía más de +/- 0.2 psid). BAVCO / TCEQ."},
  {id:388, q:"La calibración de un manómetro de prueba de reflujo debe ser trazable a:", opts:["La factura de agua local","La presión del edificio","El código de color de la pintura del fabricante","Un estándar de referencia trazable a NIST"], re:"La verificación de precisión debe rastrearse hasta un estándar de referencia con calibración trazable a NIST para que las lecturas sean defendibles. TCEQ / BAVCO / ASSE 1064."},
  {id:389, q:"Un manómetro de prueba que lee 0.5 psid alto hará de la manera más peligrosa que un inspector:", opts:["Apruebe un alivio o check que en realidad está por debajo de su mínimo","Falle solo buenos conjuntos","No tenga efecto real","Lea la presión de suministro"], re:"Un manómetro que lee alto puede hacer que un alivio o check por debajo del mínimo parezca cumplir los criterios de 2.0/5.0/1.0 psid, aprobando un conjunto inseguro. De ahí el límite de +/- 0.2 psid y la comprobación anual. BAVCO / TCEQ."},
  {id:390, q:"Antes de cada prueba, el inspector debe purgar todo el aire de las mangueras del equipo porque el aire atrapado:", opts:["Baja la lectura","Eleva la lectura diferencial y puede ocultar un check con fuga","No tiene efecto","Calibra el manómetro"], re:"El aire en las líneas se lee como diferencial adicional (falso alto), enmascarando un check con fuga; purgar las mangueras alta y baja da una lectura verdadera. Orientación de equipo de prueba BAVCO / AWWA M14."},
  {id:391, q:"Después de cualquier reparación o reemplazo de piezas, el conjunto debe:", opts:["Regresar al servicio sin probarse","Pintarse","Volver a probarse y demostrarse que aprueba antes de ponerse de nuevo en servicio","Dejarse para la próxima prueba anual"], re:"Reemplazar un sello, resorte, check o alivio cambia la dinámica interna; una reprueba aprobatoria y un informe son obligatorios antes de que el conjunto regrese al servicio. AWWA M14 / requisito regulatorio."},
  {id:392, q:"Un solo manómetro diferencial de 3 válvulas o 5 válvulas se prefiere sobre dos manómetros de presión separados porque:", opts:["Es más barato de enviar","Lee solo la presión de suministro","No necesita calibración","Lee directamente el pequeño diferencial, evitando el error de restar dos lecturas grandes"], re:"Restar dos manómetros de rango alto amplifica el error en los pequeños valores de 1-5 psid que importan; un manómetro diferencial lee la diferencia directa y con precisión. Orientación de equipo de prueba BAVCO / AWWA M14."},
  {id:393, q:"Un equipo de prueba que se ha caído o muestra lecturas erráticas debe:", opts:["Retirarse del servicio y volver a verificarse/calibrarse antes de más pruebas","Mantenerse en servicio","Usarse solo en conjuntos pequeños","Pintarse y reutilizarse"], re:"El choque físico puede desplazar la calibración; verifique la precisión contra un estándar trazable antes de confiar de nuevo en el equipo. Las lecturas erráticas invalidan los resultados. BAVCO / TCEQ."},
  {id:394, q:"El informe de prueba después de una reparación y reprueba debe registrar:", opts:["Solo el nombre del inspector","Las lecturas finales aprobatorias (diferenciales de check y punto de apertura del alivio) y que aprobó","El color de la pintura","Solo la presión de suministro"], re:"El informe de reprueba documenta las lecturas finales reales (cada diferencial de check y el punto de apertura del alivio) demostrando que el conjunto cumple los criterios después de la reparación. AWWA M14 / informe regulatorio."},
  {id:395, q:"Si un manómetro recién calibrado y una prueba cuidadosa aún muestran la apertura del alivio por debajo de 2.0 psid, la conclusión correcta es que la:", opts:["Manómetro está mal de nuevo","Prueba no puede hacerse","Válvula de alivio está fallando y debe repararse y volver a probarse","Presión de suministro es demasiado alta"], re:"Una vez confirmada la precisión del manómetro, una apertura de alivio por debajo de 2.0 psid es una falla real del alivio, que requiere servicio y una reprueba aprobatoria. USC FCCCHR / AWWA M14."},
  {id:396, q:"Un registro o etiqueta de calibración en el equipo de prueba sirve para:", opts:["Decorar el equipo","Reemplazar el informe de prueba","Aumentar el ajuste de alivio","Documentar la última fecha de verificación de precisión y que el manómetro está dentro de tolerancia"], re:"La etiqueta/certificado de calibración demuestra que el manómetro fue verificado dentro de +/- 0.2 psid en una fecha dada, lo que los reguladores y proveedores de agua requieren. TCEQ / BAVCO."},
  {id:397, q:"Durante la prueba del punto de apertura del alivio, las válvulas de aguja (válvulas de control) del manómetro se usan para:", opts:["Purgar lentamente la presión para poder leer el diferencial de apertura exacto","Pintar el manómetro","Aumentar la presión de suministro","Cerrar el alivio permanentemente"], re:"Las válvulas de aguja/control del equipo permiten al inspector purgar la presión gradualmente y capturar el diferencial en el que el alivio se abre por primera vez. Procedimiento AWWA M14 / USC FCCCHR."},
  {id:398, q:"Una reprueba que falla después de una reparación significa que el técnico debe:", opts:["Presentarla como aprobada de todos modos","Diagnosticar y corregir la falla restante, luego volver a probar hasta que apruebe","Dejarla en servicio","Quitar la válvula de alivio"], re:"Un conjunto solo puede regresar al servicio después de una prueba aprobatoria; una reprueba fallida significa más reparación (p. ej., una pieza desgastada que se pasó por alto) y otra prueba. AWWA M14 / requisito regulatorio."},
  {id:399, q:"Conectar las mangueras alta y baja del manómetro diferencial a un punto común idealmente debe leer:", opts:["Alrededor de 2 psid","Alrededor de 5 psid","Alrededor de 0 psid (cero), confirmando que el manómetro se pone a cero correctamente","La presión de suministro"], re:"Con ambas mangueras a la misma presión no hay diferencial, por lo que un manómetro correcto debe leer alrededor de cero; una lectura distinta de cero señala un problema de calibración o de purga de aire. BAVCO / AWWA M14."},
  {id:400, q:"La razón fundamental por la que la precisión del manómetro y una reprueba aprobatoria importan tanto es que:", opts:["Aceleran el papeleo","Elevan la presión de suministro","Reducen las facturas de agua","Un manómetro inexacto o una reprueba omitida pueden dejar en servicio un conjunto contaminado o fallido"], re:"Todo el propósito de la prueba es la protección de la salud pública; un manómetro incorrecto o una reprueba faltante pueden dejar un conjunto de alto riesgo fallido protegiendo el agua potable. USC FCCCHR / AWWA M14."},
  {id:401, q:"En California, ¿qué documento adoptado por la State Water Resources Control Board rige ahora el control de conexiones cruzadas y reemplaza los antiguos reglamentos de conexiones cruzadas del Title 17?", opts:["El Cross-Connection Control Policy Handbook (CCCPH)","El Uniform Plumbing Code","El California Fire Code","OSHA 29 CFR 1910"], re:"La SWRCB adoptó el Cross-Connection Control Policy Handbook (CCCPH), que reemplaza las Secciones 7583-7586 y 7601-7605 del Title 17 CCR en lo referente al control de conexiones cruzadas. Fuente: página web del CCCPH de la SWRCB; CCCPH (2023)."},
  {id:402, q:"¿Cuál es la fecha de entrada en vigor del Cross-Connection Control Policy Handbook (CCCPH) de California?", opts:["1 de enero de 2000","1 de julio de 2024","1 de enero de 1985","1 de julio de 2030"], re:"El CCCPH se adoptó el 19 de diciembre de 2023 y entró en vigor el 1 de julio de 2024. Fuente: historial de reglamentación del Cross-Connection Control Policy Handbook de la SWRCB."},
  {id:403, q:"¿Qué agencia estatal de California adoptó y administra el Cross-Connection Control Policy Handbook?", opts:["La U.S. EPA","El Departamento de Transporte de California","La State Water Resources Control Board (Division of Drinking Water)","La FMCSA federal"], re:"La State Water Resources Control Board (SWRCB), a través de su Division of Drinking Water, adoptó y administra el CCCPH. Fuente: página web del CCCPH de la SWRCB."},
  {id:404, q:"Antes del CCCPH, ¿qué secciones del Title 17 del California Code of Regulations contenían los requisitos de control de conexiones cruzadas?", opts:["Secciones 1000-1100","Secciones 5000-5050","Secciones 60000-60050","Secciones 7583-7605"], re:"Las Secciones 7583 a 7605 del Title 17 CCR contenían los reglamentos de control de conexiones cruzadas de California; el CCCPH reemplazó las Secciones 7583-7586 y 7601-7605. Fuente: Title 17 CCR; CCCPH de la SWRCB."},
  {id:405, q:"Según las normas de control de conexiones cruzadas de California, ¿con qué frecuencia mínima debe probarse en campo un dispositivo de prevención de reflujo?", opts:["Al menos anualmente (cada 12 meses)","Solo una vez en la instalación","Cada cinco años","Cada diez años"], re:"Las normas de California (Title 17 y ahora el CCCPH) exigen que los dispositivos de prevención de reflujo se prueben en campo al momento de la instalación y al menos anualmente después, o con mayor frecuencia si el purveyor/agencia de salud lo requiere. Fuente: CCCPH; antiguo Title 17 CCR §7605."},
  {id:406, q:"Además de la prueba en la instalación y anualmente, ¿cuándo más exige California que se pruebe un dispositivo de prevención de reflujo?", opts:["Solo cuando se vende la propiedad","Después de reparar, reubicar o reemplazar el dispositivo","Solo cada año bisiesto","Nunca más después de la instalación"], re:"California exige pruebas en la instalación, después de cualquier reparación, reubicación o reemplazo, y al menos anualmente. Un dispositivo alterado debe volver a verificarse antes de ponerlo nuevamente en servicio. Fuente: CCCPH; AWWA M14."},
  {id:407, q:"¿Qué estatutos de California (Health & Safety Code) otorgan la autoridad legal para los requisitos estatales de control de conexiones cruzadas y agua potable segura?", opts:["Vehicle Code §1000-1100","Penal Code §187","Health & Safety Code §116800-116820","Civil Code §1500"], re:"Las Secciones 116800-116820 del California Health & Safety Code (dentro del California Safe Drinking Water Act) autorizan los requisitos de control de conexiones cruzadas implementados a través del Title 17/CCCPH. Fuente: CA Health & Safety Code §116800 y siguientes."},
  {id:408, q:"Según el reglamento de California, ¿quién tiene el deber legal principal de proteger el sistema público de agua de la contaminación por conexiones cruzadas?", opts:["El tasador fiscal del condado","Únicamente el técnico individual","El jefe estatal de bomberos","El proveedor de agua (sistema público de agua / purveyor)"], re:"El proveedor de agua (sistema público de agua) debe proteger el suministro público de agua de la contaminación mediante la implementación de un programa de control de conexiones cruzadas. Fuente: antiguo Title 17 CCR §7584; responsabilidades del PWS en el CCCPH."},
  {id:409, q:"El Title 17 / CCCPH exige que el tipo de protección contra reflujo instalada se base en ¿qué factor?", opts:["El grado de peligro que las instalaciones del cliente representan para el suministro público de agua","La antigüedad del edificio","El color de la pintura exterior","La factura mensual de agua del cliente"], re:"El tipo de protección requerido (separación por aire, RP, DC, etc.) se determina según el grado de peligro que representan las instalaciones del usuario para el sistema público de agua. Fuente: disposiciones de evaluación de peligro del CCCPH; antiguo Title 17 CCR §7585."},
  {id:410, q:"Según el CCCPH, las certificaciones de técnicos certificados de reflujo deben ser reconocidas por ¿qué organismo a partir del 1 de julio de 2026?", opts:["La cámara de comercio local","La State Water Resources Control Board (SWRCB)","El U.S. Department of Labor","El sheriff del condado"], re:"A partir del 1 de julio de 2026, los técnicos deben poseer una certificación de una organización reconocida por la SWRCB para cumplir con el CCCPH. Fuente: página de Certificación de Técnicos de Reflujo y Especialistas en Control de Conexiones Cruzadas de la SWRCB."},
  {id:411, q:"Según el CCCPH, a partir del 1 de julio de 2027, las organizaciones certificadoras de técnicos usadas para el cumplimiento también deben estar acreditadas conforme a ¿qué norma?", opts:["NFPA 13","ISO 9001 únicamente","Acreditación ANSI conforme a ISO/IEC 17024","Código de calderas ASME"], re:"A partir del 1 de julio de 2027, solo podrán usarse para el cumplimiento del CCCPH organizaciones certificadoras acreditadas por ANSI conforme a ISO/IEC 17024 (certificación de personas). Fuente: página de Certificación de Técnicos de Reflujo de la SWRCB."},
  {id:412, q:"¿Cuál de los siguientes NO es un método de protección reconocido según las normas de control de conexiones cruzadas de California?", opts:["Separación por aire (AG)","Dispositivo de principio de presión reducida (RP)","Dispositivo de doble válvula de retención (DC)","Un trapo enrollado de manera floja sobre la tubería"], re:"Los métodos reconocidos incluyen la separación por aire, los dispositivos de principio de presión reducida, los dispositivos de doble válvula de retención y los rompedores de vacío. Un trapo no es un método aprobado. Fuente: CCCPH; antiguo Title 17 CCR §7603-7604."},
  {id:413, q:"¿Por qué California reemplazó las antiguas disposiciones de conexiones cruzadas del Title 17 con el CCCPH?", opts:["Porque el Title 17 había permanecido prácticamente sin cambios desde la década de 1980 y necesitaba modernizarse","Para eliminar todos los requisitos de prueba","Para eliminar el papel de los proveedores de agua","Para hacer opcionales los dispositivos de reflujo"], re:"El CCCPH moderniza requisitos que habían permanecido prácticamente sin cambios desde la adopción original del Title 17 en la década de 1980, ampliando y actualizando las normas del programa. Fuente: materiales de adopción del CCCPH de la SWRCB."},
  {id:414, q:"Según las normas de California, ¿quién es responsable de garantizar que el dispositivo de prevención de reflujo de un cliente se pruebe y se mantenga en buen estado de funcionamiento?", opts:["La State Water Board directamente","El cliente de agua/propietario del dispositivo","El propietario de la propiedad vecina","El fabricante del dispositivo"], re:"Es responsabilidad del cliente de agua garantizar que el dispositivo se pruebe anualmente y se mantenga en condiciones de funcionamiento adecuadas en todo momento. Fuente: CCCPH; programas de control de conexiones cruzadas de proveedores de agua de California."},
  {id:415, q:"Para instalaciones que manejan materiales peligrosos para la salud (un peligro para la salud), ¿qué nivel de protección exige California en la conexión de servicio?", opts:["No se requiere protección","Solo un rompedor de vacío de grifo de manguera","Una separación por aire (AG) o un dispositivo de principio de presión reducida (RP)","Una simple válvula de cierre"], re:"Las instalaciones que representan un peligro para la salud (contaminante) deben protegerse con una separación por aire aprobada o un dispositivo de principio de presión reducida. Fuente: disposiciones de peligro del CCCPH; antiguo Title 17 CCR §7604 Tabla 1."},
  {id:416, q:"Las separaciones por aire usadas para el control de conexiones cruzadas en California deben cumplir las dimensiones mínimas de ¿qué norma referenciada?", opts:["FMVSS 121 (frenos de aire)","NFPA 70 (National Electrical Code)","ASTM A36 (acero estructural)","ASME A112.1.2 (separaciones por aire mínimas)"], re:"El CCCPH hace referencia a ASME A112.1.2 para las separaciones por aire mínimas en accesorios de plomería. Fuente: CCCPH; ASME A112.1.2."},
  {id:417, q:"Según el CCCPH, ¿a quién puede designar un sistema público de agua para llevar a cabo tareas de control de conexiones cruzadas como las inspecciones de peligro?", opts:["Un especialista certificado en control de conexiones cruzadas","Cualquier persona, sin requisitos","Solo el Gobernador del estado","Solo contratistas de fuera del estado"], re:"El CCCPH exige que el PWS use especialistas certificados en control de conexiones cruzadas para llevar a cabo tareas del programa como inspecciones y evaluaciones de peligro. Fuente: artículo del CCCPH sobre especialistas; página de certificación de especialistas de la SWRCB."},
  {id:418, q:"¿Qué es el AWWA Manual M14?", opts:["Una ley federal","El manual de prácticas recomendadas de la AWWA sobre prevención de reflujo y control de conexiones cruzadas","Un estatuto estatal de California","Un permiso de espacio confinado de OSHA"], re:"El AWWA M14, 'Backflow Prevention and Cross-Connection Control: Recommended Practices', es un manual industrial de práctica de suministro de agua, no una ley. Fuente: AWWA Manual M14."},
  {id:419, q:"¿Cuál es la edición actual del AWWA Manual M14?", opts:["Primera edición","Segunda edición","Quinta edición (publicada en 2024)","No existe un sistema de ediciones"], re:"La quinta edición del AWWA M14 se publicó en 2024 (referencia ANSI AWWA M14-2024). Fuente: tienda de AWWA; listado de ANSI webstore AWWA M14-2024."},
  {id:420, q:"Legalmente hablando, las normas y manuales de la AWWA como el M14 se describen mejor como ¿cuál de los siguientes?", opts:["Documentos industriales secretos","Estatutos penales federales","Automáticamente obligatorios en todos los estados","Documentos de consenso voluntario que no reemplazan la ley aplicable"], re:"Las normas de la AWWA son documentos de consenso voluntario y no reemplazan ni desplazan las leyes, reglamentos o códigos aplicables; solo se vuelven exigibles cuando una autoridad las adopta. Fuente: declaración del programa de normas de la AWWA."},
  {id:421, q:"¿Qué hace principalmente el USC FCCCHR (Foundation for Cross-Connection Control and Hydraulic Research)?", opts:["Evaluar y aprobar dispositivos de prevención de reflujo y publicar procedimientos de prueba en campo","Fijar límites de emisiones de vehículos","Emitir licencias de conducir","Regular el cableado eléctrico"], re:"El USC FCCCHR opera un programa de aprobación (evaluación de laboratorio y de campo) de dispositivos de prevención de reflujo y publica el Manual of Cross-Connection Control con procedimientos de prueba en campo. Fuente: páginas web de aprobación y lista del USC FCCCHR."},
  {id:422, q:"¿Por cuánto tiempo es válida la aprobación de un dispositivo de prevención de reflujo en la Lista del USC FCCCHR antes de que deba renovarse?", opts:["Un año","Tres años","Diez años","Indefinidamente; nunca se renueva"], re:"Las aprobaciones del USC FCCCHR se otorgan por un período de tres años y están sujetas a renovación. Fuente: List of Approved Backflow Prevention Assemblies del USC FCCCHR."},
  {id:423, q:"¿Qué requisito distintivo incluye el programa de aprobación del USC FCCCHR que muchos otros programas de aprobación no tienen?", opts:["Una garantía de 50 años","Un requisito de que el dispositivo se pinte de rojo","Una evaluación de campo obligatoria de un año antes del listado","Aprobación por el Presidente de EE. UU."], re:"Se señala que el USC FCCCHR es el único programa de aprobación de reflujo que exige una evaluación de campo de un año, además de las pruebas de laboratorio, antes de listar un dispositivo. Fuente: descripción del programa de aprobación del USC FCCCHR."},
  {id:424, q:"La 'Lista' del USC FCCCHR identifica cada dispositivo aprobado por todo lo siguiente EXCEPTO:", opts:["Tipo de dispositivo y fabricante","Modelo y tamaño","Fechas de aprobación y renovación","La dirección del domicilio del propietario de la propiedad"], re:"La Lista identifica cada dispositivo por tipo, fabricante, modelo, tamaño, la edición del manual bajo la cual fue aprobado y las fechas de aprobación/renovación, no las direcciones de los clientes. Fuente: List del USC FCCCHR."},
  {id:425, q:"¿Qué documento publicado por el USC FCCCHR se usa ampliamente para estandarizar cómo los técnicos realizan las pruebas de campo de los dispositivos de reflujo?", opts:["El Manual of Cross-Connection Control (procedimientos de prueba en campo, p. ej., 10.ª edición)","El National Electrical Code","El código fiscal federal","El MUTCD"], re:"El Manual of Cross-Connection Control del USC FCCCHR (con procedimientos de prueba en campo, 10.ª edición actual) estandariza los métodos de prueba en campo de los técnicos usados en muchos programas. Fuente: USC FCCCHR; manual de la 10.ª edición del USC."},
  {id:426, q:"El AWWA M14 explica que los dos tipos básicos de reflujo son ¿qué par?", opts:["Flujo directo y ósmosis inversa","Sifonaje inverso (backsiphonage) y contrapresión (backpressure)","Evaporación y condensación","Cavitación y golpe de ariete"], re:"El AWWA M14 describe los dos tipos de reflujo como sifonaje inverso (backsiphonage) (causado por presión de suministro negativa) y contrapresión (backpressure) (presión aguas abajo que supera la del suministro). Fuente: AWWA M14."},
  {id:427, q:"¿Cuál es el propósito principal del AWWA Manual M14?", opts:["Fijar límites de horas de servicio de conductores comerciales","Regular el manejo de refrigerantes","Describir las causas y la prevención del reflujo y las conexiones cruzadas en sistemas de agua potable","Establecer normas de salario mínimo"], re:"El M14 describe las causas y la prevención del reflujo y las conexiones cruzadas y ayuda a los sistemas de agua a construir un programa de control de conexiones cruzadas. Fuente: descripción del AWWA M14."},
  {id:428, q:"¿Con qué universidad está afiliado el USC FCCCHR (Foundation for Cross-Connection Control and Hydraulic Research)?", opts:["University of Texas","New York University","University of Florida","University of Southern California (en California)"], re:"La Foundation está afiliada con la University of Southern California (USC) en California. Fuente: USC FCCCHR (fccchr.usc.edu)."},
  {id:429, q:"Un dispositivo de prevención de reflujo debe completar con éxito ¿qué dos fases para obtener la aprobación del USC FCCCHR?", opts:["Evaluación de laboratorio y evaluación de campo","Revisión de marketing y cuota de ventas","Una prueba de sabor y una prueba de color","Una prueba de ruido y una prueba de peso"], re:"La aprobación del USC FCCCHR requiere completar con éxito tanto una evaluación de laboratorio como una evaluación de campo bajo la supervisión de la Foundation. Fuente: programa de aprobación del USC FCCCHR."},
  {id:430, q:"¿Qué afirmación describe mejor la relación entre los documentos del AWWA M14 / USC FCCCHR y un proveedor de agua local?", opts:["Reemplazan automáticamente todas las normas locales","Un purveyor o jurisdicción puede adoptarlos o referenciarlos, dándoles efecto exigible a nivel local","Prohíben a los proveedores tener cualquier programa","Se aplican solo fuera de Estados Unidos"], re:"Estos son documentos de referencia; adquieren efecto exigible donde un purveyor, estado o jurisdicción los adopta o los referencia en sus normas. Fuente: programa de normas de la AWWA; uso del programa del USC FCCCHR por las agencias."},
  {id:431, q:"Según el AWWA M14, un programa completo de control de conexiones cruzadas ayuda a un sistema de agua a hacer ¿cuál de lo siguiente?", opts:["Diseñar intercambiadores de carreteras","Presentar impuestos sobre la renta","Elegir, instalar y mantener la prevención de reflujo apropiada","Certificar soldadores"], re:"El M14 ayuda a un sistema de agua a elegir, instalar y mantener dispositivos de prevención de reflujo como parte de un programa total de control de conexiones cruzadas. Fuente: descripción del AWWA M14."},
  {id:432, q:"Cuando un dispositivo de reflujo aparece en la Lista del USC FCCCHR, el listado también indica la edición de ¿qué documento bajo el cual se aprobó el dispositivo?", opts:["Un manual del propietario de un vehículo","El periódico local","El presupuesto federal","El USC Foundation Manual of Cross-Connection Control"], re:"Cada dispositivo listado indica la edición del manual de la USC Foundation (especificaciones/procedimientos de prueba en campo) bajo la cual se aprobó. Fuente: List del USC FCCCHR."},
  {id:433, q:"¿Por qué es importante que un técnico use la Lista del USC FCCCHR o la lista aprobada del purveyor al verificar un dispositivo?", opts:["Para confirmar que el modelo del dispositivo es un tipo aprobado para la aplicación","Para encontrar el precio de las acciones del fabricante","Para elegir colores de pintura","Para fijar el monto de la factura de agua"], re:"La lista aprobada confirma que la marca/modelo es un tipo de dispositivo aprobado y aceptable para la instalación; los dispositivos no aprobados pueden no satisfacer al purveyor ni al reglamento. Fuente: List del USC FCCCHR; normas del programa del purveyor."},
  {id:434, q:"El AWWA M14 se publica como parte de ¿qué serie de la AWWA?", opts:["El Code of Regulations federal","El Manual of Water Supply Practices (serie M)","La serie de divulgación de OSHA","El código de vehículos estatal"], re:"El M14 forma parte del Manual of Water Supply Practices de la AWWA (la serie 'M' de manuales de prácticas recomendadas). Fuente: Manuales de la AWWA / listado del M14."},
  {id:435, q:"Según las normas de California, ¿cuál de los siguientes es un elemento requerido del programa de control de conexiones cruzadas de un sistema público de agua?", opts:["Una prohibición de la plomería interior","Un requisito de que todos los clientes pinten sus casas","La adopción de normas operativas o una ordenanza para implementar el programa","Agua embotellada gratuita para todos los residentes"], re:"Un programa de control de conexiones cruzadas debe incluir normas operativas, ordenanzas o una resolución para implementarlo. Fuente: antiguo Title 17 CCR §7584; elementos del programa del CCCPH."},
  {id:436, q:"Como parte de su programa, ¿qué debe realizar un proveedor de agua para identificar las instalaciones donde es probable que ocurran conexiones cruzadas?", opts:["Una verificación de crédito","Un estudio de tráfico","Una encuesta de sabor","Inspecciones / evaluaciones de peligro de las instalaciones de los clientes"], re:"Los proveedores deben inspeccionar su área de servicio y realizar evaluaciones de peligro para identificar conexiones cruzadas reales o potenciales y el grado de peligro. Fuente: Capítulo 3 de evaluación de peligro del CCCPH; antiguo Title 17 CCR §7584."},
  {id:437, q:"El programa de un proveedor de agua debe proporcionar al menos una persona capacitada/certificada en ¿qué campo?", opts:["Control de conexiones cruzadas","Preparación de impuestos","Diseño de carreteras","Servicio de alimentos"], re:"El programa debe proporcionar al menos una persona capacitada/certificada en control de conexiones cruzadas para llevarlo a cabo. Fuente: antiguo Title 17 CCR §7584; requisito de especialista del CCCPH."},
  {id:438, q:"¿Cuál de los siguientes debe establecer un proveedor de agua como parte de su programa de control de conexiones cruzadas?", opts:["Una flota de camiones de reparto","Un procedimiento o sistema para probar los preventores de reflujo","Una tienda minorista","Una estación de radio"], re:"El programa debe establecer un procedimiento o sistema para probar los preventores de reflujo (incluido el seguimiento y los avisos de prueba anual). Fuente: antiguo Title 17 CCR §7584; programa de pruebas del CCCPH."},
  {id:439, q:"El CCCPH exige que un sistema público de agua mantenga registros del programa que incluyan detalles de cada dispositivo de prevención de reflujo. ¿Qué detalle se requiere?", opts:["El historial de votación del propietario","El color favorito del propietario","Tipo, fabricante, modelo, tamaño, ubicación, propietario, fecha de instalación y número de serie","La marca del vehículo del propietario"], re:"Los registros deben incluir el peligro/aplicación, ubicación, propietario, tipo, fabricante, modelo, tamaño, fecha de instalación y número de serie de cada dispositivo. Fuente: requisitos de mantenimiento de registros del CCCPH."},
  {id:440, q:"Según el CCCPH, ¿cuántas de las evaluaciones de peligro más recientes en cada instalación debe conservar un purveyor en sus registros?", opts:["Cincuenta","Ninguna","Solo la primera que se haya realizado","Las dos evaluaciones de peligro más recientes"], re:"El CCCPH exige que el programa conserve las dos evaluaciones de peligro más recientes realizadas en cada instalación. Fuente: requisitos de mantenimiento de registros del CCCPH."},
  {id:441, q:"Si un cliente no hace probar o reparar un dispositivo de reflujo requerido, ¿qué medida de cumplimiento puede tomar finalmente un proveedor de agua según su ordenanza?", opts:["Suspender (cortar) el servicio de agua hasta que se logre el cumplimiento","Remolcar el automóvil del cliente","Revocar la licencia de conducir del cliente","Aumentar el impuesto sobre las ventas"], re:"Las ordenanzas de los purveyors normalmente autorizan suspender el servicio de agua por incumplimiento de los requisitos de prueba o instalación, previo aviso. Fuente: cumplimiento del programa CCCPH/Title 17; ordenanzas de conexiones cruzadas de los purveyors."},
  {id:442, q:"El programa de control de conexiones cruzadas de un proveedor de agua está destinado principalmente a proteger ¿qué?", opts:["El presupuesto publicitario del purveyor","El suministro público de agua potable de la contaminación","El equipo deportivo local","El precio del refrigerante"], re:"El propósito fundamental del programa es proteger el suministro público de agua potable de la contaminación por reflujo. Fuente: CCCPH; antiguo Title 17 CCR §7584."},
  {id:443, q:"Según las normas de California, ¿con quién puede contratar un proveedor de agua para implementar todo o parte de su programa de control de conexiones cruzadas?", opts:["Un gobierno extranjero","Cualquier persona sin licencia al azar","La agencia de salud local u otra agencia aprobada por la agencia de salud","Una cuenta anónima en línea"], re:"Un proveedor de agua puede implementar el programa directamente o por contrato con la agencia de salud local u otra agencia aprobada por la agencia de salud. Fuente: antiguo Title 17 CCR §7584; CCCPH."},
  {id:444, q:"Un proveedor de agua decide qué protección de reflujo necesita un cliente con base en una evaluación de peligro que clasifica las instalaciones como ¿cuál de los siguientes?", opts:["Solo construcción nueva o remodelación","Solo zonificación residencial o comercial","Solo ocupado por el propietario o alquilado","Un peligro para la salud (contaminante) o un peligro no relacionado con la salud (contaminante menor / pollutant)"], re:"Las evaluaciones de peligro clasifican el grado de peligro -peligro para la salud (contaminante) frente a peligro no relacionado con la salud (pollutant)-, lo que define la protección requerida. Fuente: CCCPH; AWWA M14."},
  {id:445, q:"¿Qué tipo de protección de reflujo suele exigir un purveyor para unas instalaciones clasificadas solo como peligro no relacionado con la salud (pollutant)?", opts:["Como mínimo un dispositivo de doble válvula de retención (DC)","Ninguna protección en absoluto","Solo una separación por aire, nunca otra cosa","Una simple válvula de compuerta"], re:"Los peligros no relacionados con la salud (pollutant) suelen protegerse con un dispositivo de doble válvula de retención aprobado, mientras que los peligros para la salud requieren AG o RP. Fuente: CCCPH; antiguo Title 17 CCR §7604 Tabla 1."},
  {id:446, q:"Muchos purveyors envían a los clientes un recordatorio/aviso anual ¿con qué propósito?", opts:["Solo para anunciar nuevas tarifas de agua","Para recordar al cliente que vence la prueba anual del dispositivo de reflujo","Para pedir al cliente que corte el césped","Para recopilar la contraseña de correo electrónico del cliente"], re:"Los purveyors hacen seguimiento de los dispositivos y notifican a los clientes cuando vence la prueba anual, parte fundamental del procedimiento de prueba exigido al programa. Fuente: programa de pruebas del CCCPH; programas de purveyors."},
  {id:447, q:"Dentro de un sistema público de agua, la persona que gestiona las inspecciones, las evaluaciones de peligro y el programa en general suele ser un ¿qué certificado?", opts:["Auditor fiscal","Operador de maquinaria pesada","Especialista en control de conexiones cruzadas","Farmacéutico"], re:"Un especialista certificado en control de conexiones cruzadas gestiona funciones del programa como inspecciones y evaluaciones de peligro; esta es una certificación distinta de la del técnico de dispositivos. Fuente: certificación de especialistas de la SWRCB; CCCPH."},
  {id:448, q:"Según el CCCPH, los técnicos y especialistas en los que se apoya un sistema público de agua deben ser ¿qué?", opts:["Agentes de bienes raíces con licencia","Amigos de la junta de agua","Voluntarios no certificados","Certificados por una organización reconocida (y posteriormente acreditada por ANSI) según el CCCPH"], re:"El PWS debe asegurarse de que todos los técnicos de dispositivos de reflujo y especialistas en control de conexiones cruzadas que utiliza estén certificados conforme al CCCPH (organizaciones reconocidas, posteriormente acreditadas a ANSI/ISO 17024). Fuente: artículo del CCCPH sobre certificación; SWRCB."},
  {id:449, q:"El programa de un proveedor de agua debe garantizar que las conexiones cruzadas reales y potenciales se eliminen cuando sea posible o, de lo contrario, se controlen mediante ¿qué?", opts:["La instalación de dispositivos de prevención de reflujo aprobados o separaciones por aire","Solo la colocación de letreros de advertencia","Pintar el medidor de agua","Enviar un boletín anual"], re:"Los programas deben eliminar las conexiones cruzadas donde sea factible, o controlarlas con dispositivos de prevención de reflujo aprobados o separaciones por aire conforme al CCCPH. Fuente: requisitos de protección del CCCPH."},
  {id:450, q:"¿Qué nivel de gobierno exige de manera más directa que los proveedores de agua de California operen un programa de control de conexiones cruzadas?", opts:["Las Naciones Unidas","El Estado de California (SWRCB), conforme a la ley estatal y el CCCPH","Una asociación de propietarios","Una compañía de seguros privada"], re:"La ley estatal (Health & Safety Code) y el CCCPH de la SWRCB exigen que los sistemas públicos de agua de California implementen programas de control de conexiones cruzadas. Fuente: CA Health & Safety Code §116800 y siguientes; CCCPH."},
  {id:451, q:"Cuando un dispositivo de reflujo no aprueba su prueba anual, ¿qué espera del cliente el programa del purveyor?", opts:["Retirar el dispositivo de forma permanente","Ignorar la falla hasta el próximo año","Hacer reparar y volver a probar el dispositivo, y luego presentar un informe de prueba aprobado","Pintar el dispositivo y no hacer nada más"], re:"Un dispositivo que falla debe repararse (o reemplazarse) y volverse a probar, presentando un informe de prueba aprobado al purveyor para restablecer la protección. Fuente: disposiciones de prueba/reparación del CCCPH; programas de purveyors."},
  {id:452, q:"Después de completar la prueba de un dispositivo de reflujo, ¿a quién debe presentarse normalmente el informe de prueba del técnico certificado?", opts:["El periódico local","El despachador del departamento de bomberos","El departamento estatal de parques","El proveedor de agua (sistema público de agua)"], re:"Los informes de prueba se presentan al proveedor de agua responsable del programa de control de conexiones cruzadas (y el técnico/propietario conserva una copia). Fuente: informes del CCCPH; normas del programa del purveyor."},
  {id:453, q:"La mayoría de los proveedores de agua exigen que el manómetro de prueba usado por un técnico certificado esté calibrado dentro de ¿qué plazo?", opts:["Dentro de los 12 meses anteriores","Dentro de los 10 años anteriores","Solo una vez cuando se compra","Nunca se requiere calibración"], re:"La mayoría de los purveyors exigen que el manómetro diferencial de prueba haya sido calibrado dentro de los 12 meses anteriores, y la fecha de calibración debe registrarse en el informe. Fuente: requisitos del informe de prueba del purveyor; procedimientos de prueba en campo del AWWA M14/USC."},
  {id:454, q:"¿Qué información debe registrar un técnico certificado en el informe de prueba para identificar el dispositivo específico que se probó?", opts:["La factura del teléfono de casa del técnico","El número de serie del dispositivo (que coincide con el sello grabado en el dispositivo)","La placa de matrícula del automóvil del cliente","El pronóstico del clima"], re:"El informe debe registrar el número de serie del dispositivo, que debe coincidir con el número de serie grabado en el dispositivo, junto con el tipo, marca, modelo y tamaño. Fuente: campos estándar del informe de prueba de reflujo; programas de purveyors."},
  {id:455, q:"¿Qué información identificativa sobre el técnico debe aparecer en un informe de prueba de un dispositivo de reflujo?", opts:["La talla de zapato del técnico","La comida favorita del técnico","El nombre y número de certificación del técnico (y su vencimiento)","Los planes de vacaciones del técnico"], re:"Los informes deben incluir el nombre del técnico certificado, su número de certificación y la fecha de vencimiento de la certificación para que el purveyor pueda verificar las credenciales. Fuente: campos estándar del informe de prueba; programas de purveyors."},
  {id:456, q:"En un informe de prueba, el técnico debe indicar claramente ¿qué resultado de la prueba?", opts:["La fase de la luna","El índice del mercado bursátil","El estado de ánimo del técnico","Aprobado o Reprobado (y cualquier reparación realizada)"], re:"El informe debe indicar el resultado aprobado/reprobado y documentar cualquier limpieza o reparación realizada antes del resultado final. Fuente: campos estándar del informe de prueba de reflujo."},
  {id:457, q:"¿Qué debe registrar un técnico certificado en el informe sobre el equipo de prueba utilizado?", opts:["La marca/modelo del kit de prueba, el número de serie y la fecha de calibración","El precio por el que se compró el kit","La tienda donde se compró el kit","Nada sobre el equipo"], re:"El informe debe registrar la marca y el modelo del kit/manómetro de prueba, su número de serie y su fecha de calibración. Fuente: campos estándar del informe de prueba; requisitos del purveyor."},
  {id:458, q:"Si un técnico descubre que un dispositivo instalado no es un modelo aprobado para la aplicación, ¿cuál es la acción apropiada?", opts:["Falsificar el informe para mostrar que aprobó","Anotarlo y reportar la deficiencia al purveyor; el dispositivo puede necesitar reemplazo","Ignorarlo porque solo importa el resultado de la prueba","Retirar el sello del número de serie"], re:"Los técnicos deben reportar las deficiencias, incluidos los dispositivos no aprobados o de aplicación incorrecta, al purveyor; la presentación de informes honesta protege la salud pública. Fuente: deberes del técnico del CCCPH; uso de la lista aprobada del USC FCCCHR."},
  {id:459, q:"El deber ético fundamental de un técnico certificado de dispositivos de reflujo se describe mejor como ¿cuál de los siguientes?", opts:["Probar solo los dispositivos que sean fáciles de alcanzar","Aprobar siempre todos los dispositivos para complacer al cliente","Reportar los resultados de las pruebas de manera veraz y precisa","Mantener todos los resultados en secreto del purveyor"], re:"Dado que está en juego el agua potable del público, un técnico debe reportar los resultados de manera veraz y precisa; falsificar un informe de reflujo puede poner en peligro la salud y es motivo para perder la certificación. Fuente: CCCPH; códigos de conducta de certificación de técnicos."},
  {id:460, q:"Antes de volver a poner en servicio un dispositivo reparado o recién instalado, ¿qué debe hacer el técnico certificado?", opts:["Esperar un año antes de probar","Simplemente suponer que funciona","Pintar sobre las llaves de prueba","Realizar una prueba en campo para verificar que el dispositivo funcione correctamente"], re:"Los dispositivos recién instalados, reparados, reubicados o reemplazados deben probarse en campo para verificar su correcto funcionamiento antes de confiar en ellos. Fuente: CCCPH; requisitos de prueba en campo del AWWA M14."},
  {id:461, q:"Para seguir calificado para realizar pruebas en California conforme al CCCPH, un técnico debe hacer ¿cuál de lo siguiente?", opts:["Mantener una certificación vigente de una organización reconocida (y posteriormente acreditada por ANSI)","Renovar una licencia de pesca","Registrar un vehículo nuevo","Suscribirse a una revista"], re:"Los técnicos deben mantener una certificación vigente de una organización reconocida por la SWRCB (acreditada a ANSI/ISO 17024 a partir del 1 de julio de 2027) para realizar pruebas de cumplimiento del CCCPH. Fuente: página de Certificación de Técnicos de Reflujo de la SWRCB; CCCPH."},
  {id:462, q:"Muchos programas de certificación de técnicos exigen la recertificación en ¿qué ciclo?", opts:["Una vez en la vida, nunca se renueva","Periódicamente (comúnmente cada tres años)","Cada semana","Cada 30 años"], re:"Las certificaciones de técnicos de reflujo tienen un plazo limitado y normalmente requieren recertificación en un ciclo periódico (comúnmente cada tres años). Fuente: descripciones de programas de certificación de técnicos de California (p. ej., CA-NV AWWA, ASSE)."},
  {id:463, q:"¿Por qué el número de serie del informe de prueba debe coincidir con el número de serie grabado en el dispositivo?", opts:["Para registrar el automóvil del técnico","Para fijar la factura de agua","Para confirmar que se probó realmente el dispositivo correcto y específico","Para elegir un color de pintura"], re:"Los números de serie coincidentes prueban que el informe corresponde al dispositivo específico en el campo, evitando fraudes y errores de registro. Fuente: requisitos del informe de prueba del purveyor."},
  {id:464, q:"Si el manómetro de prueba de un técnico está descalibrado, ¿qué debe hacer el técnico?", opts:["Pedir prestada la báscula de baño de un cliente","Usarlo de todos modos y adivinar las lecturas","Redondear las lecturas hacia arriba","Detenerse y hacer calibrar el manómetro antes de reportar los resultados como válidos"], re:"Un manómetro descalibrado produce lecturas poco fiables; el técnico debe calibrarlo antes de realizar pruebas válidas y reportables. Fuente: requisitos de calibración del purveyor; procedimientos de prueba en campo."},
  {id:465, q:"En general se espera que un técnico certificado conserve una copia de los informes de prueba completados ¿por qué motivo?", opts:["Para el mantenimiento de registros y para documentar el cumplimiento","Para venderla a anunciantes","Para empapelar la oficina","No hay motivo para conservarlos"], re:"Los técnicos conservan copias de los informes para el mantenimiento de registros y para documentar que las pruebas requeridas se realizaron y se reportaron. Fuente: práctica de mantenimiento de registros del programa del purveyor; CCCPH."},
  {id:466, q:"¿Qué debe hacer un técnico certificado si un cliente le pide marcar un dispositivo que falló como 'aprobado'?", opts:["Marcarlo como aprobado para mantener contento al cliente","Negarse; reportar el resultado real de falla","Marcarlo como aprobado pero no decírselo a nadie","Dejar el informe en blanco"], re:"Un técnico debe negarse a falsificar un informe; el resultado real (de falla) debe reportarse para que el dispositivo se repare y se proteja el suministro de agua. Fuente: códigos de conducta de certificación de técnicos; CCCPH."},
  {id:467, q:"En el informe de prueba, se requiere la fecha en que se calibró el manómetro por última vez para que el purveyor pueda confirmar ¿qué?", opts:["La marca del automóvil del cliente","La edad del técnico","Que la calibración del manómetro está vigente (normalmente dentro de 12 meses)","El clima local"], re:"La fecha de calibración permite al purveyor verificar que el manómetro estaba en calibración vigente (comúnmente dentro de 12 meses) cuando se realizó la prueba. Fuente: requisitos del informe de prueba del purveyor."},
  {id:468, q:"¿Qué información identifica la ubicación a la que se aplica la prueba en un informe de prueba de un dispositivo de reflujo?", opts:["La capital del estado","El cumpleaños del técnico","La sede del fabricante","La dirección de servicio y la ubicación del dispositivo en las instalaciones"], re:"Los informes registran la dirección de servicio y la ubicación específica del dispositivo para que el purveyor pueda relacionarla con los registros del programa. Fuente: campos estándar del informe de prueba; mantenimiento de registros del CCCPH."},
  {id:469, q:"Para que una separación por aire sea efectiva, ¿cuál es la separación vertical mínima requerida entre la salida de suministro y el borde de desbordamiento del recipiente receptor?", opts:["Al menos el doble del diámetro de la tubería de suministro, y nunca menos de 1 pulgada","Exactamente 1/8 de pulgada","Igual al diámetro de la tubería solamente","Diez veces el diámetro de la tubería, mínimo 3 pies"], re:"Una separación por aire efectiva (aprobada) debe ser al menos el doble del diámetro de la tubería de suministro medido verticalmente sobre el borde de desbordamiento, y en ningún caso menor de 1 pulgada. Fuente: AWWA M14; ASME A112.1.2."},
  {id:470, q:"Un dispositivo de principio de presión reducida (RP) NO debe instalarse en ¿qué ubicación?", opts:["Sobre el nivel del suelo en un área bien drenada","Un foso o cualquier ubicación sujeta a inundación/sumersión","En interiores con drenaje adecuado","Sobre una plataforma nivelada por encima del punto de descarga de la válvula de alivio"], re:"Un dispositivo RP no debe sumergirse ni instalarse donde pueda inundarse; su válvula de alivio debe descargar al aire, y la sumersión anularía la protección y crearía riesgo de contaminación. Fuente: AWWA M14; normas de instalación del fabricante/purveyor."},
  {id:471, q:"Un rompedor de vacío de presión (PVB) debe instalarse al menos ¿a qué altura por encima de la salida/tubería aguas abajo más alta a la que sirve?", opts:["Al menos 6 pies por encima","A nivel del suelo o por debajo","Al menos 12 pulgadas por encima de la salida aguas abajo más alta","No importa dónde se instale"], re:"Un PVB debe instalarse al menos 12 pulgadas por encima de la tubería/salida aguas abajo más alta para que la entrada de aire no pueda sumergirse y la ruptura de aire pueda funcionar. Fuente: AWWA M14; ASSE 1020 / instrucciones del fabricante."},
  {id:472, q:"¿Contra qué condición NO está diseñado para proteger un rompedor de vacío de presión (PVB)?", opts:["Baja demanda aguas abajo","Sifonaje inverso (backsiphonage)","Aire que entra por la entrada de aire","Contrapresión (backpressure)"], re:"Un PVB protege solo contra el sifonaje inverso (backsiphonage); no debe usarse donde pueda desarrollarse contrapresión (backpressure) en la tubería aguas abajo. Fuente: AWWA M14; guía de aplicación de PVB."},
  {id:473, q:"¿Por qué debe instalarse un dispositivo de prevención de reflujo de modo que sea accesible?", opts:["Para que pueda probarse anualmente y mantenerse o repararse","Para que pueda ocultarse de la vista","Para que los niños puedan jugar sobre él","Para que pueda enterrarse por completo"], re:"Los dispositivos deben ser accesibles para la prueba anual requerida, el mantenimiento y la reparación; enterrarlos o encerrarlos sin acceso anula el programa. Fuente: AWWA M14; normas de instalación del purveyor."},
  {id:474, q:"Para que un dispositivo de prevención de reflujo instalado sea aceptable en un programa de California, generalmente debe ser ¿qué?", opts:["El dispositivo más barato disponible","Un modelo aprobado (p. ej., en la Lista del USC FCCCHR o la lista aprobada del purveyor)","Cualquier dispositivo casero","Pintado de un color específico independientemente de la aprobación"], re:"Los dispositivos instalados deben ser modelos aprobados aceptables para el purveyor, comúnmente los que están en la Lista del USC FCCCHR o la lista aprobada de la agencia. Fuente: List del USC FCCCHR; requisitos del CCCPH/purveyor."},
  {id:475, q:"La válvula de alivio de un dispositivo de principio de presión reducida (RP) descarga a la atmósfera principalmente para hacer ¿qué?", opts:["Aumentar la presión aguas abajo","Enfriar el edificio","Verter agua de la zona para prevenir el reflujo cuando las válvulas de retención no sellan","Filtrar el agua"], re:"La válvula de alivio del RP se abre para descargar la zona de presión reducida a la atmósfera, evitando que el agua contaminada refluya cuando las válvulas de retención no retienen. Fuente: AWWA M14; procedimientos de prueba en campo del USC."},
  {id:476, q:"Dado que la válvula de alivio de un dispositivo RP puede descargar agua, la instalación debe prever ¿qué?", opts:["Ningún drenaje en absoluto","Una cámara sellada hermética al aire","Sumersión en un sumidero","Drenaje/separación por aire adecuados en la descarga de la válvula de alivio"], re:"Las instalaciones de RP deben proporcionar drenaje adecuado y una separación por aire en la salida de la válvula de alivio para manejar la descarga intermitente o catastrófica sin inundación ni reflujo. Fuente: AWWA M14; normas de instalación."},
  {id:477, q:"Un dispositivo de doble válvula de retención (DC) es apropiado para ¿qué tipo de peligro?", opts:["Aplicaciones no relacionadas con la salud (pollutant), de bajo peligro","Aplicaciones de salud de alto peligro como plantas químicas","Conexiones de plantas de tratamiento de aguas residuales","Peligros para la salud de funerarias y hospitales"], re:"Un dispositivo DC se usa para aplicaciones no relacionadas con la salud (pollutant) de bajo peligro; los peligros para la salud (contaminantes) requieren un AG o RP. Fuente: AWWA M14; tablas de peligro del CCCPH/Title 17."},
  {id:478, q:"¿Qué dispositivo brinda protección tanto contra el sifonaje inverso como contra la contrapresión para una conexión de peligro para la salud?", opts:["Rompedor de vacío de presión (PVB)","Dispositivo de principio de presión reducida (RP)","Solo rompedor de vacío atmosférico (resistente a derrames)","Solo rompedor de vacío de grifo de manguera"], re:"Un dispositivo RP protege tanto contra el sifonaje inverso como contra la contrapresión y es aceptable para conexiones de peligro para la salud (contaminante); el PVB/AVB protege solo contra el sifonaje inverso. Fuente: AWWA M14; disposiciones de peligro del CCCPH."},
  {id:479, q:"Las dimensiones mínimas de una separación por aire usada para el control de conexiones cruzadas se definen en ¿qué norma referenciada por California?", opts:["NFPA 70E","Código de calderas y recipientes a presión ASME","ASME A112.1.2","FMVSS 121"], re:"ASME A112.1.2 especifica las separaciones por aire mínimas para accesorios de plomería y es referenciada por el CCCPH para las separaciones por aire. Fuente: CCCPH; ASME A112.1.2."},
  {id:480, q:"Una separación por aire puede anularse (volverse inefectiva) por ¿cuál de los siguientes?", opts:["Limpiar la cuenca","Pintar el accesorio","Aumentar la separación muy por encima del mínimo","Sumergir la salida de suministro o reducir la separación por debajo del mínimo"], re:"Una separación por aire falla si la salida se sumerge o la separación vertical se reduce por debajo del mínimo requerido (2x el diámetro de la tubería, mínimo 1 pulgada). Fuente: AWWA M14; ASME A112.1.2."},
  {id:481, q:"¿Por qué deben instalarse los dispositivos de prevención de reflujo generalmente en la orientación correcta (p. ej., RP y DC normalmente horizontales a menos que se apruebe lo contrario)?", opts:["Porque la aprobación y el correcto funcionamiento interno dependen de instalarlo según el listado/instrucciones del fabricante","Porque las tuberías verticales son ilegales","Para que coincida con el color del edificio","La orientación nunca importa"], re:"Los dispositivos se aprueban y deben instalarse según su listado y las instrucciones del fabricante, incluida la orientación; una orientación incorrecta puede anular la aprobación y afectar el funcionamiento/las pruebas. Fuente: aprobación del USC FCCCHR; AWWA M14; instrucciones del fabricante."},
  {id:482, q:"La instalación de un nuevo dispositivo de prevención de reflujo en un programa de California generalmente requiere ¿qué antes de poder confiar en él?", opts:["Nada en absoluto","Un permiso/aprobación según lo requiera el purveyor y una prueba inicial en campo","Solo un acuerdo verbal","Un período de espera de 10 años"], re:"Las nuevas instalaciones están sujetas a la aprobación/permiso del purveyor según corresponda y deben aprobar una prueba inicial en campo antes de poder confiar en ellas para la protección. Fuente: CCCPH; requisitos de instalación/permiso del purveyor."},
  {id:483, q:"¿Qué dispositivo generalmente se limita a situaciones de solo sifonaje inverso de peligro bajo a moderado y debe instalarse por encima de la tubería aguas abajo?", opts:["Separación por aire en una conexión de aguas residuales","Dispositivo de principio de presión reducida (RP)","Rompedor de vacío de presión (PVB)","Doble retención detectora (de incendios) en una alimentación química"], re:"Un PVB protege solo contra el sifonaje inverso, generalmente se limita a aplicaciones de menor peligro y debe instalarse al menos 12 pulgadas por encima de la salida aguas abajo más alta. Fuente: AWWA M14; guía de aplicación/instalación de PVB."},
  {id:484, q:"Instalar un dispositivo de prevención de reflujo por debajo del nivel del suelo en una bóveda sin drenaje adecuado crea ¿qué riesgo?", opts:["Cumplimiento automático de todos los códigos","Mejor sabor del agua","Menor presión de agua que siempre es deseable","El dispositivo puede sumergirse en agua contaminada, anulando la protección y la función de alivio"], re:"Las instalaciones por debajo del nivel del suelo/en bóveda sin drenaje corren el riesgo de sumergir el dispositivo (y la ventilación de alivio de un RP) en agua contaminada, anulando la protección y creando un peligro de reflujo. Fuente: AWWA M14; normas de instalación."},
  {id:485, q:"Según OSHA, se considera que una atmósfera es deficiente en oxígeno cuando la concentración de oxígeno cae por debajo de ¿qué nivel?", opts:["19.5 por ciento de oxígeno por volumen","30 por ciento de oxígeno por volumen","5 por ciento de oxígeno por volumen","50 por ciento de oxígeno por volumen"], re:"OSHA define una atmósfera deficiente en oxígeno como aquella que contiene menos del 19.5% de oxígeno por volumen. Fuente: OSHA 29 CFR 1910.146 (Espacios confinados que requieren permiso)."},
  {id:486, q:"Una bóveda subterránea de un dispositivo de reflujo lo bastante grande para entrar, con medios limitados de entrada/salida y que no está diseñada para ocupación continua se clasifica mejor como ¿qué?", opts:["Un campo abierto","Un espacio confinado","Una oficina estándar","Una cabina de vehículo"], re:"Una bóveda/foso en el que se puede entrar corporalmente, con entrada/salida limitada y no diseñado para ocupación continua, cumple la definición de espacio confinado de OSHA (y puede requerir permiso). Fuente: definiciones de OSHA 29 CFR 1910.146."},
  {id:487, q:"Antes de entrar en un espacio confinado que requiere permiso, la atmósfera interna debe probarse con un instrumento calibrado de lectura directa en ¿qué orden?", opts:["Inflamables primero, luego tóxicos, luego oxígeno","Tóxicos primero, luego oxígeno, luego inflamables","Oxígeno primero, luego gases/vapores inflamables, luego contaminantes tóxicos","El orden no importa"], re:"OSHA exige realizar las pruebas en el orden: contenido de oxígeno primero, luego gases y vapores inflamables, luego posibles contaminantes tóxicos del aire. Fuente: OSHA 29 CFR 1910.146 Apéndice B."},
  {id:488, q:"¿Por qué se prueba el oxígeno primero al evaluar la atmósfera de un espacio confinado?", opts:["Es una tradición arbitraria sin razón","El oxígeno es el único peligro que importa","Los tóxicos no pueden medirse en absoluto","La mayoría de los medidores de gas combustible dependen del oxígeno y dan lecturas poco fiables con poco oxígeno"], re:"El oxígeno se prueba primero porque la mayoría de los medidores de gas combustible (inflamable) dependen del oxígeno y no leen de forma fiable en una atmósfera deficiente en oxígeno. Fuente: OSHA 29 CFR 1910.146 Apéndice B."},
  {id:489, q:"¿Qué característica haría que un espacio confinado sea un espacio confinado 'que requiere permiso' según OSHA?", opts:["Contiene o podría contener una atmósfera peligrosa","Tiene buena iluminación","Está recién pintado","Está cerca de un estacionamiento"], re:"Un espacio confinado que requiere permiso tiene uno o más peligros: una atmósfera peligrosa, potencial de sepultamiento, una configuración convergente hacia el interior/de atrapamiento, o cualquier otro peligro grave reconocido. Fuente: definiciones de OSHA 29 CFR 1910.146."},
  {id:490, q:"Un trabajador que prueba un dispositivo de reflujo en una calzada debe usar prendas de seguridad de alta visibilidad que cumplan ¿qué requisito?", opts:["Ninguna ropa especial","ANSI/ISEA 107 Clase de Rendimiento 2 o 3","Una camiseta blanca lisa","Ropa de color oscuro para pasar desapercibido"], re:"Los trabajadores expuestos al tráfico en la zona de derecho de paso deben usar prendas de alta visibilidad que cumplan ANSI/ISEA 107 Clase de Rendimiento 2 o 3. Fuente: MUTCD Parte 6 (Control Temporal de Tráfico); ANSI/ISEA 107."},
  {id:491, q:"El control temporal de tráfico alrededor de una zona de trabajo en la vía pública se rige por ¿qué documento nacional?", opts:["El manual AWWA M14","El National Electrical Code","El Manual on Uniform Traffic Control Devices (MUTCD), Parte 6","Las normas de refrigerantes de la EPA"], re:"El MUTCD Parte 6 establece las normas para las configuraciones de control temporal de tráfico (zona de trabajo) en las vías. Fuente: FHWA MUTCD Parte 6."},
  {id:492, q:"La válvula de alivio de un dispositivo RP puede descargar un chorro o rociado repentino de agua durante la prueba. ¿Qué significa este peligro para el técnico?", opts:["Garantiza que la prueba se aprobó","Es inofensivo y puede ignorarse","Significa que el manómetro está roto","Estar preparado para la descarga de agua y evitar lesiones en los ojos/cara y peligros de resbalones"], re:"El agua a presión puede descargarse de la válvula de alivio o las llaves de prueba; los técnicos deben proteger sus ojos/cara, manejar los peligros de resbalones y controlar la descarga. Fuente: guía de seguridad del AWWA M14; instrucciones del fabricante."},
  {id:493, q:"¿Por qué debe un técnico tener cuidado con el reflujo de agua contaminada al dar servicio a un dispositivo que protege unas instalaciones con peligro para la salud?", opts:["El agua contaminada puede plantear un grave riesgo para la salud si alcanza al técnico o al suministro potable","Solo afecta la factura de agua","El agua contaminada siempre es segura para beber","Mejora la calidad del agua"], re:"Los dispositivos en conexiones con peligro para la salud pueden retener agua contaminada; un manejo incorrecto durante el servicio puede exponer al técnico o al suministro potable, por lo que se requiere precaución y aislamiento. Fuente: AWWA M14; contexto de peligro del CCCPH."},
  {id:494, q:"Para la entrada a un espacio confinado que requiere permiso, OSHA exige una persona apostada fuera del espacio para vigilar a quienes entran. ¿Cómo se llama esta persona?", opts:["Un transeúnte","Un vigilante (attendant)","Un cliente","Un señalero (flagger)"], re:"OSHA exige un vigilante (attendant) apostado fuera de un espacio confinado que requiere permiso para vigilar a quienes entran y ordenar la evacuación si es necesario. Fuente: OSHA 29 CFR 1910.146."},
  {id:495, q:"Si un espacio confinado que requiere permiso contiene una atmósfera peligrosa, ¿qué control exige OSHA antes y durante la entrada cuando sea factible?", opts:["Añadir un gas inflamable","Sellar el espacio herméticamente","Ventilación de aire forzado para eliminar/controlar la atmósfera peligrosa","Retirar todo el equipo de monitoreo"], re:"Cuando se usa, la ventilación de aire forzado de una fuente limpia debe eliminar la atmósfera peligrosa y continuar mientras los trabajadores están dentro; la atmósfera debe permanecer segura durante la ocupación. Fuente: OSHA 29 CFR 1910.146."},
  {id:496, q:"Para aislar de forma segura un dispositivo de reflujo para repararlo, el técnico generalmente debe hacer ¿qué primero?", opts:["Aumentar la presión de suministro","Abrir todas las llaves de prueba bajo plena presión y alejarse","Cortar la tubería de inmediato","Cerrar las válvulas de cierre aguas arriba y aguas abajo para despresurizar el dispositivo"], re:"Aislar el dispositivo cerrando sus válvulas de cierre lo despresuriza para un servicio seguro y evita la descarga descontrolada de agua. Fuente: AWWA M14; procedimientos de prueba en campo/mantenimiento del USC."},
  {id:497, q:"¿Cuál es el propósito principal de un permiso de entrada para un espacio confinado que requiere permiso?", opts:["Documentar los peligros, controles y autorización antes de la entrada","Cobrar una tarifa de estacionamiento","Anunciar el trabajo","Reemplazar las pruebas atmosféricas"], re:"El permiso de entrada documenta el espacio, los peligros, los resultados de las pruebas atmosféricas, los controles y la autorización, y debe completarse antes de la entrada; complementa, no reemplaza, las pruebas. Fuente: OSHA 29 CFR 1910.146."},
  {id:498, q:"Cuando se usan señaleros para controlar el tráfico en una zona de trabajo, ¿cuál es su principal dispositivo de señalización manual según el MUTCD?", opts:["Solo una linterna","Una paleta PARE/DESPACIO (STOP/SLOW) (de al menos 18 pulgadas)","Solo sus manos desnudas","Solo un silbato"], re:"El MUTCD exige que los señaleros usen una paleta PARE/DESPACIO (STOP/SLOW) (de al menos 18 pulgadas) como principal dispositivo de señalización manual y que usen prendas de alta visibilidad. Fuente: FHWA MUTCD Parte 6, Capítulo 6E (Control con Señalero)."},
  {id:499, q:"Al trabajar con agua a presión, ¿cómo debe tratar un técnico las llaves de prueba y los accesorios?", opts:["Golpearlos con un martillo para aflojarlos","Forzarlos a abrirse lo más rápido posible","Abrirlos y cerrarlos con cuidado, anticipando la liberación de agua a presión","Suponer que nunca están presurizados"], re:"Las llaves de prueba y los accesorios pueden liberar agua a presión de forma repentina; abrirlos/cerrarlos lenta y deliberadamente evita lesiones por rociado y la pérdida de control de la descarga. Fuente: guía de seguridad del AWWA M14; procedimientos de prueba en campo."},
  {id:500, q:"En general, las prácticas de seguridad que sigue un técnico certificado (precauciones de espacios confinados, control de tráfico y control de agua a presión/contaminada) están destinadas a proteger ¿a quién?", opts:["A nadie en particular","Solo las ganancias de la empresa de agua","Solo al fabricante del equipo","Al técnico, al público y al suministro de agua potable"], re:"Las prácticas de seguridad en el lugar de trabajo protegen al técnico, al público alrededor de la zona de trabajo y la integridad del suministro de agua potable que la prevención de reflujo existe para salvaguardar. Fuente: OSHA 29 CFR 1910.146; MUTCD Parte 6; AWWA M14."}
];
